import type { CSSProperties, ReactNode } from 'react';

// 폴백 styled map (Google Maps 키 없을 때) — 마포구 연남동 일대 일러스트.

interface MapSceneProps {
  children?: ReactNode;
  dim?: boolean;
}

export function MapScene({ children, dim = false }: MapSceneProps) {
  const blocks: number[][] = [
    [8, 8, 20, 16], [32, 6, 18, 14], [54, 10, 16, 12], [74, 8, 20, 18],
    [6, 30, 18, 18], [60, 30, 14, 14], [78, 32, 18, 16],
    [10, 56, 16, 16], [30, 60, 16, 14], [66, 58, 18, 18],
    [8, 78, 20, 16], [40, 80, 22, 14], [72, 80, 20, 16],
  ];
  return (
    <div className="map-wrap">
      <svg
        className="map-canvas"
        viewBox="0 0 100 100"
        preserveAspectRatio="xMidYMid slice"
        style={{ filter: dim ? 'saturate(.9) brightness(.99)' : 'none' }}
      >
        <rect x={-10} y={-10} width={120} height={120} fill="var(--map-land)" />
        {blocks.map((b, i) => (
          <rect key={'bl' + i} x={b[0]} y={b[1]} width={b[2]} height={b[3]} rx={2.2} fill="var(--map-block)" stroke="#E2E6EA" strokeWidth={0.4} />
        ))}
        <path d="M-6 28 L40 16 L78 40 L108 30 L108 40 L80 50 L40 26 L-6 38 Z" fill="var(--map-park)" opacity={0.9} />
        <path d="M-6 33 L40 21 L79 45 L108 35" fill="none" stroke="#A9D6AC" strokeWidth={0.6} strokeDasharray="2 2" opacity={0.8} />
        <g stroke="var(--map-road)" strokeWidth={5} strokeLinecap="round">
          <path d="M-5 50 H105" />
          <path d="M50 -5 V105" />
          <path d="M-5 74 L60 70 L105 86" />
          <path d="M22 -5 L28 50 L20 105" />
        </g>
        <g stroke="#F2F4F6" strokeWidth={2.4} strokeLinecap="round">
          <path d="M-5 50 H105" />
          <path d="M50 -5 V105" />
        </g>
      </svg>
      {children}
    </div>
  );
}

interface TrailLayerProps {
  points: [number, number][];
  color?: string;
}

export function TrailLayer({ points, color = 'var(--accent)' }: TrailLayerProps) {
  if (!points || points.length < 2) return null;
  const d = points.map((p, i) => (i ? 'L' : 'M') + p[0] * 100 + ' ' + p[1] * 100).join(' ');
  return (
    <svg
      style={{ position: 'absolute', inset: 0, zIndex: 4, pointerEvents: 'none' }}
      viewBox="0 0 100 100"
      preserveAspectRatio="none"
    >
      <path d={d} fill="none" stroke="#fff" strokeWidth={2.4} strokeLinecap="round" strokeLinejoin="round" opacity={0.7} />
      <path d={d} fill="none" stroke={color} strokeWidth={1.4} strokeLinecap="round" strokeLinejoin="round" strokeDasharray="0.1 3" />
      {points.map((p, i) => (
        <circle
          key={i}
          cx={p[0] * 100}
          cy={p[1] * 100}
          r={i === 0 || i === points.length - 1 ? 1.6 : 1}
          fill={i === points.length - 1 ? color : '#fff'}
          stroke={color}
          strokeWidth={0.8}
        />
      ))}
    </svg>
  );
}

export function MeDot({ x, y, style }: { x: number; y: number; style?: CSSProperties }) {
  return (
    <div className="me-dot" style={{ left: x * 100 + '%', top: y * 100 + '%', ...style }}>
      <div className="ring" />
      <div className="core" />
    </div>
  );
}
