import { Capacitor } from '@capacitor/core';

interface StatusBarProps {
  dark?: boolean;
}

const isNative = Capacitor.isNativePlatform();

export function StatusBar({ dark = false }: StatusBarProps) {
  // 네이티브(실기기)에선 OS 실제 상태바가 안전영역에 표시되므로 가짜 시계·배터리는 숨김 (겹침 방지).
  // 데스크톱 브라우저 목업(safe-top=0)에선 어차피 높이 0이라 비표시.
  if (isNative) return null;
  const now = new Date();
  const time = `${now.getHours()}:${String(now.getMinutes()).padStart(2, '0')}`;
  return (
    <div className={'statusbar' + (dark ? ' on-dark' : '')}>
      <span className="num">{time}</span>
      <div className="sb-right">
        <svg width={18} height={12} viewBox="0 0 18 12" fill="currentColor">
          {[0, 1, 2, 3].map((i) => (
            <rect key={i} x={i * 4.6} y={8 - i * 2.6} width={3.2} height={4 + i * 2.6} rx={1} />
          ))}
        </svg>
        <svg width={17} height={12} viewBox="0 0 17 12" fill="currentColor">
          <path
            d="M8.5 2C5.2 2 2.3 3.3.1 5.4L8.5 12 16.9 5.4C14.7 3.3 11.8 2 8.5 2z"
            opacity={0.95}
          />
        </svg>
        <svg width={26} height={12} viewBox="0 0 26 12" fill="none">
          <rect x={0.6} y={0.6} width={21} height={10.8} rx={3} stroke="currentColor" strokeWidth={1} opacity={0.4} />
          <rect x={2.2} y={2.2} width={15} height={7.6} rx={1.6} fill="currentColor" />
          <rect x={23} y={4} width={1.8} height={4} rx={0.9} fill="currentColor" opacity={0.4} />
        </svg>
      </div>
    </div>
  );
}
