import { loadKakaoMaps } from '@/lib/kakaoMaps';
import { getSupabase } from '@/lib/supabase';

export interface RegionResult {
  kind: 'region';
  id: string;
  name: string;
  gu: string;
  dong: string;
  lat: number;
  lng: number;
}

export interface ComplexHit {
  kind: 'complex';
  id: string;
  name: string;
  type: string;
  lat: number;
  lng: number;
  households?: number;
  roadAddr?: string;
  jibunAddr?: string;
}

export type SearchHit = RegionResult | ComplexHit;

function isRegionToken(t: string): boolean {
  return /(동|읍|면|구|시|군|로)$/.test(t);
}

function stripSuffix(t: string): string {
  return t.replace(/(아파트|빌라|오피스텔|단지|타워|마을|주공)$/g, '').trim();
}

function haversineKm(a: { lat: number; lng: number }, b: { lat: number; lng: number }): number {
  const R = 6371;
  const dLat = ((b.lat - a.lat) * Math.PI) / 180;
  const dLng = ((b.lng - a.lng) * Math.PI) / 180;
  const la1 = (a.lat * Math.PI) / 180;
  const la2 = (b.lat * Math.PI) / 180;
  const x =
    Math.sin(dLat / 2) ** 2 +
    Math.cos(la1) * Math.cos(la2) * Math.sin(dLng / 2) ** 2;
  return 2 * R * Math.asin(Math.sqrt(x));
}

async function geocodeFirst(q: string): Promise<{ lat: number; lng: number } | null> {
  const k = await loadKakaoMaps();
  const services = k?.services;
  if (!services) return null;
  return new Promise((resolve) => {
    const geocoder = new services.Geocoder();
    geocoder.addressSearch(q, (addrs, st) => {
      if (st === 'OK' && addrs.length > 0) {
        resolve({ lat: parseFloat(addrs[0].y), lng: parseFloat(addrs[0].x) });
        return;
      }
      const places = new services.Places();
      places.keywordSearch(q, (ps, st2) => {
        if (st2 === 'OK' && ps.length > 0) {
          resolve({ lat: parseFloat(ps[0].y), lng: parseFloat(ps[0].x) });
        } else {
          resolve(null);
        }
      });
    });
  });
}

async function reverseAddress(
  lat: number,
  lng: number,
): Promise<{ road?: string; jibun?: string }> {
  const k = await loadKakaoMaps();
  const services = k?.services;
  if (!services) return {};
  return new Promise((resolve) => {
    const geocoder = new services.Geocoder();
    (geocoder as unknown as {
      coord2Address: (
        lng: number,
        lat: number,
        cb: (
          res: Array<{
            road_address?: { address_name?: string };
            address?: { address_name?: string };
          }>,
          st: string,
        ) => void,
      ) => void;
    }).coord2Address(lng, lat, (res, st) => {
      if (st !== 'OK' || !res || res.length === 0) {
        resolve({});
        return;
      }
      const r = res[0];
      resolve({
        road: r.road_address?.address_name,
        jibun: r.address?.address_name,
      });
    });
  });
}

export async function searchRegions(term: string): Promise<RegionResult[]> {
  const k = await loadKakaoMaps();
  const services = k?.services;
  if (!services) return [];
  const geocoder = new services.Geocoder();
  const places = new services.Places();
  const hits: RegionResult[] = [];
  const seen = new Set<string>();
  const push = (h: RegionResult) => {
    const key = `${h.gu}|${h.dong}`;
    if (seen.has(key)) return;
    seen.add(key);
    hits.push(h);
  };
  await new Promise<void>((resolve) => {
    geocoder.addressSearch(term, (addrs, st) => {
      if (st === 'OK' && addrs.length > 0) {
        for (const a of addrs) {
          const parts = a.address_name.split(' ');
          const gu = parts[1] ?? '';
          const dong = parts[2] ?? parts[parts.length - 1] ?? '';
          push({
            kind: 'region',
            id: `${gu}|${dong}`,
            name: a.address_name,
            gu,
            dong,
            lat: parseFloat(a.y),
            lng: parseFloat(a.x),
          });
          if (hits.length >= 5) break;
        }
      }
      resolve();
    });
  });
  if (hits.length === 0) {
    await new Promise<void>((resolve) => {
      places.keywordSearch(term, (ps, st) => {
        if (st === 'OK' && ps.length > 0) {
          for (const p of ps) {
            const parts = (p.address_name || '').split(' ');
            const gu = parts[1] ?? '';
            const dong = parts[2] ?? parts[parts.length - 1] ?? p.place_name;
            push({
              kind: 'region',
              id: `${gu}|${dong}|${p.place_name}`,
              name: p.place_name,
              gu,
              dong,
              lat: parseFloat(p.y),
              lng: parseFloat(p.x),
            });
            if (hits.length >= 5) break;
          }
        }
        resolve();
      });
    });
  }
  return hits;
}

export async function searchComplexes(term: string): Promise<ComplexHit[]> {
  const sb = getSupabase();
  if (!sb) return [];
  const tokens = term.split(/\s+/).filter((t) => t.length >= 1);
  let rawName: string;
  let regionQuery: string;
  if (tokens.length <= 1) {
    rawName = term;
    regionQuery = '';
  } else {
    const longest = tokens.reduce((a, b) => (b.length > a.length ? b : a));
    rawName = longest;
    const others = [...tokens];
    others.splice(others.indexOf(longest), 1);
    regionQuery = others.join(' ');
  }
  const queryTerm = stripSuffix(rawName) || rawName;
  // 짧은 query는 전체 table scan으로 500/timeout 발생. 한글 2자 또는 영문 3자 이상만 허용.
  if (!queryTerm || queryTerm.length < 2) return [];
  // 한글 자모(ㄱ, ㄴ 등)만 입력된 경우도 차단 (PostgreSQL collation 이슈)
  if (/^[ㄱ-㆏]+$/.test(queryTerm)) return [];
  const regionCenter = regionQuery ? await geocodeFirst(regionQuery) : null;

  try {
    // RPC 경유 (complexes 테이블 직접 SELECT 금지 — RLS service-only).
    // 마스킹 단지(name에 *)는 아래 client fallback에서 제외.
    type RpcRow = { id: string; name: string; type: string; lat: number; lng: number; households: number | null; canonical_id: string | null };
    const { data: raw, error } = await sb.rpc('search_complexes_by_name', {
      q: queryTerm,
      region_lat: regionCenter?.lat ?? null,
      region_lng: regionCenter?.lng ?? null,
      result_limit: 200,
    });
    if (error || !raw) return [];
    const data = raw as RpcRow[];

    // alias → canonical 매핑: canonical_id가 있으면 그 단지를 가져와서 대표로 사용
    const aliasIds = Array.from(
      new Set(
        data
          .filter((r) => r.canonical_id != null)
          .map((r) => String(r.canonical_id)),
      ),
    );
    const canonicalMap = new Map<string, { id: string; name: string; type: string; lat: number; lng: number; households: number | null }>();
    if (aliasIds.length > 0) {
      type IdRow = { id: string; name: string; type: string; lat: number; lng: number; households: number | null };
      const { data: canRowsRaw } = await sb.rpc('complexes_by_ids', { ids: aliasIds });
      const canRows = (canRowsRaw ?? []) as IdRow[];
      for (const r of canRows) {
        canonicalMap.set(String(r.id), {
          id: String(r.id),
          name: String(r.name),
          type: String(r.type ?? '아파트'),
          lat: Number(r.lat),
          lng: Number(r.lng),
          households: r.households != null ? Number(r.households) : null,
        });
      }
    }

    // 각 row를 canonical row로 치환, dedup
    const seen = new Set<string>();
    let hits: ComplexHit[] = [];
    for (const r of data) {
      const canonical = r.canonical_id != null
        ? canonicalMap.get(String(r.canonical_id))
        : { id: String(r.id), name: String(r.name), type: String(r.type ?? '아파트'), lat: Number(r.lat), lng: Number(r.lng), households: r.households != null ? Number(r.households) : null };
      if (!canonical || seen.has(canonical.id)) continue;
      if (canonical.name?.includes('*')) continue; // 마스킹 단지(다가구) 클라이언트 fallback 필터
      seen.add(canonical.id);
      hits.push({
        kind: 'complex' as const,
        id: canonical.id,
        name: canonical.name,
        type: canonical.type,
        lat: canonical.lat,
        lng: canonical.lng,
        households: canonical.households ?? undefined,
      });
    }

    function suffixPenalty(name: string): number {
      return /(임대|공공|민간|연립|분양)/.test(name) ? 1 : 0;
    }
    if (regionCenter) {
      hits.sort((a, b) => {
        const da = haversineKm(regionCenter, { lat: a.lat, lng: a.lng });
        const db = haversineKm(regionCenter, { lat: b.lat, lng: b.lng });
        if (Math.abs(da - db) > 0.05) return da - db;
        const pa = suffixPenalty(a.name);
        const pb = suffixPenalty(b.name);
        if (pa !== pb) return pa - pb;
        return a.name.length - b.name.length;
      });
    } else {
      hits.sort((a, b) => {
        const pa = suffixPenalty(a.name);
        const pb = suffixPenalty(b.name);
        if (pa !== pb) return pa - pb;
        return a.name.length - b.name.length;
      });
    }
    hits = hits.slice(0, 8);
    const withAddr = await Promise.all(
      hits.map(async (h) => {
        const a = await reverseAddress(h.lat, h.lng);
        return { ...h, roadAddr: a.road, jibunAddr: a.jibun };
      }),
    );
    return withAddr;
  } catch {
    return [];
  }
}

// 통합 검색 — 단지+지역 동시 fetch (Promise.all). 단지 결과를 먼저 노출.
export async function searchAll(term: string): Promise<SearchHit[]> {
  const [c, r] = await Promise.all([searchComplexes(term), searchRegions(term)]);
  return [...c, ...r];
}
// eslint-disable-next-line @typescript-eslint/no-unused-vars
const _isRegionToken = isRegionToken; // 보존(향후 사용)
