export interface Member {
  id: string;
  name: string;
  color?: string;
  pending?: boolean;
}

export function Avatar({ m, size = 30, ring }: { m: Member; size?: number; ring?: boolean }) {
  return (
    <div
      className="avatar-c"
      style={{
        width: size,
        height: size,
        background: m.pending ? 'var(--surface-2)' : (m.color ?? '#8B95A1'),
        color: m.pending ? 'var(--ink-3)' : '#fff',
        fontSize: size * 0.4,
        boxShadow: ring ? '0 0 0 2px #fff' : 'none',
        border: m.pending ? '1.5px dashed var(--line-strong)' : 'none',
      }}
    >
      {m.name.slice(0, 1)}
    </div>
  );
}
