// won 표기 — 데이터 단위는 만원
export function wonText(man: number): string {
  const eok = Math.floor(man / 10000);
  const rest = man % 10000;
  if (eok <= 0) return man.toLocaleString() + '만';
  if (rest === 0) return eok + '억';
  return eok + '억 ' + rest.toLocaleString();
}

export function wonShort(man: number): string {
  const eok = man / 10000;
  if (eok >= 1) {
    const v = Math.round(eok * 10) / 10;
    return (v % 1 === 0 ? v.toFixed(0) : v.toFixed(1)) + '억';
  }
  return man.toLocaleString() + '만';
}

export function pyeong(m2: number): number {
  return Math.round(m2 / 3.3058);
}

export function formatDateLabel(iso: string): string {
  // 2026-06-14 → 2026.06.14
  return iso.replaceAll('-', '.');
}

export function relativeDay(iso: string, now = new Date()): string {
  const d = new Date(iso + 'T00:00:00');
  const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  const dayMs = 24 * 60 * 60 * 1000;
  const diff = Math.round((today.getTime() - d.getTime()) / dayMs);
  if (diff <= 0) return '오늘';
  if (diff === 1) return '어제';
  if (diff < 7) return diff + '일 전';
  if (diff < 14) return '지난주';
  if (diff < 30) return Math.floor(diff / 7) + '주 전';
  return Math.floor(diff / 30) + '개월 전';
}
