import { Capacitor } from '@capacitor/core';
import { AppProvider, useApp } from '@/store/AppStore';
import { StatusBar } from '@/components/StatusBar';

const isNative = Capacitor.isNativePlatform();
import { TabBar } from '@/components/TabBar';
import { Toast } from '@/components/Toast';
import { ConfirmDialog } from '@/components/ConfirmDialog';
import { AuthScreen } from '@/screens/AuthScreen';
import { hasSupabase } from '@/lib/env';
import { Splash } from '@/screens/Splash';
import { HomeList } from '@/screens/HomeList';
import { HomeMapKakao as HomeMap } from '@/screens/HomeMapKakao';
import { ComplexDetail } from '@/screens/ComplexDetail';
import { ComplexNote } from '@/screens/ComplexNote';
import { Imjang } from '@/screens/Imjang';
import { Friends } from '@/screens/Friends';
import { SessionDetail } from '@/screens/SessionDetail';
import { Compare } from '@/screens/Compare';
import { Settings } from '@/screens/Settings';
import { TripDetail } from '@/screens/TripDetail';
import { AddPlanSheet } from '@/screens/AddPlanSheet';
import { PlanChat } from '@/screens/PlanChat';
import { NotificationsSheet } from '@/screens/NotificationsSheet';
import type { OverlayItem } from '@/store/AppStore';

function renderOverlay(item: OverlayItem, i: number) {
  const key = `${item.type}-${item.id}-${i}`;
  switch (item.type) {
    case 'detail':
      return (
        <div key={key} style={{ position: 'absolute', inset: 0, isolation: 'isolate' }}>
          <ComplexDetail id={item.id} />
        </div>
      );
    case 'note':
      return <ComplexNote key={key} id={item.id} />;
    case 'noteView':
      return <ComplexNote key={key} id={item.id} readOnly viewNote={item.memberNote} />;
    case 'session':
      return (
        <div key={key} style={{ position: 'absolute', inset: 0, isolation: 'isolate' }}>
          <SessionDetail id={item.id} />
        </div>
      );
    case 'compare':
      return (
        <div key={key} style={{ position: 'absolute', inset: 0, isolation: 'isolate' }}>
          <Compare id={item.id} />
        </div>
      );
    case 'trip':
      return (
        <div key={key} style={{ position: 'absolute', inset: 0, isolation: 'isolate' }}>
          <TripDetail complexIds={item.complexIds ?? []} label={item.label ?? ''} batchId={item.batchId ?? ''} />
        </div>
      );
    case 'addPlan':
      return (
        <div key={key} style={{ position: 'absolute', inset: 0, isolation: 'isolate' }}>
          <AddPlanSheet />
        </div>
      );
    case 'planChat':
      return (
        <div key={key} style={{ position: 'absolute', inset: 0, isolation: 'isolate' }}>
          <PlanChat batchId={item.batchId ?? ''} label={item.label ?? ''} />
        </div>
      );
    case 'notifications':
      return <NotificationsSheet key={key} />;
    default:
      return null;
  }
}

function Shell() {
  const {
    splashDone,
    setSplashDone,
    tab,
    setTab,
    view,
    stack,
    toast,
    confirmState,
    dismissConfirm,
    user,
    authReady,
  } = useApp();

  const hideMainForOverlay =
    stack.length > 0 && ['detail', 'session', 'compare', 'trip', 'addPlan'].includes(stack[0].type);
  // Auth Gate 제거 — 비로그인도 홈/시세 탐색 가능. 로그인은 Settings에서 명시적으로.
  void user;
  void hasSupabase;
  const showAuthGate = false;

  return (
    <div className="phone-screen">
      {(splashDone || showAuthGate) && <StatusBar />}
      {(splashDone || showAuthGate) && (
        <div
          style={{
            flex: 1,
            position: 'relative',
            minHeight: 0,
            display: (hideMainForOverlay || showAuthGate || !authReady) ? 'none' : 'flex',
            flexDirection: 'column',
          }}
        >
          <div style={{ flex: 1, position: 'relative', minHeight: 0 }}>
            {tab === 'home' && (
              <>
                {/* HomeList/HomeMap 둘 다 mount 유지하고 view 따라 visibility만 토글
                    → 지도 ↔ 목록 전환 시 카카오 SDK 재초기화 없이 즉시 표시 */}
                <div
                  style={{
                    display: view === 'list' ? 'flex' : 'none',
                    flexDirection: 'column',
                    position: 'absolute',
                    inset: 0,
                  }}
                >
                  <HomeList />
                </div>
                <div
                  style={{
                    display: view === 'map' ? 'block' : 'none',
                    position: 'absolute',
                    inset: 0,
                  }}
                >
                  <HomeMap />
                </div>
              </>
            )}
            {tab === 'record' && <Imjang />}
            {tab === 'friends' && <Friends />}
            {tab === 'settings' && <Settings />}
          </div>
          <TabBar tab={tab} setTab={setTab} />
        </div>
      )}
      {splashDone && stack.length > 0 && !showAuthGate && (
        <div style={{ position: 'absolute', inset: 0 }}>{stack.map(renderOverlay)}</div>
      )}
      {showAuthGate && (
        <div style={{ position: 'absolute', inset: 0, zIndex: 9000 }}>
          <AuthScreen gate />
        </div>
      )}
      {!splashDone && !showAuthGate && <Splash onDone={setSplashDone} />}
      {toast && <Toast key={toast}>{toast}</Toast>}
      <ConfirmDialog state={confirmState} onClose={dismissConfirm} />
      {splashDone && isNative && <div className="home-ind" />}
    </div>
  );
}

export function App() {
  return (
    <AppProvider>
      <Shell />
    </AppProvider>
  );
}
