import { Icon } from './Icon';
import { useApp } from '@/store/AppStore';

interface BrandHeaderProps {
  /** 무시됨 — 벨은 항상 알림(초대) 시트를 연다. 하위호환용. */
  onBellClick?: () => void;
  showBellDot?: boolean;
}

export function BrandHeader(_props: BrandHeaderProps = {}) {
  const { setTab, setView, clearOverlays, openNotifications, pendingInvites, unreadComments, unreadSharedNotes } = useApp();
  const goHome = () => {
    clearOverlays();
    setTab('home');
    setView('list');
  };
  const hasNoti = pendingInvites.length > 0 || unreadComments.length > 0 || unreadSharedNotes.length > 0;
  return (
    <div className="brand-header centered">
      <button
        type="button"
        className="brand-center"
        onClick={goHome}
        style={{ background: 'none', border: 'none', padding: 0, cursor: 'pointer' }}
        aria-label="홈으로"
      >
        <div className="brand-logo">
          <Icon name="loc" size={17} color="#fff" fill />
        </div>
        <div className="brand-wm">단지노트</div>
      </button>
      <div className="brand-right">
        <button
          type="button"
          className={'brand-bell' + (hasNoti ? ' has-noti' : '')}
          onClick={openNotifications}
          aria-label="알림"
        >
          <Icon name="bell" size={20} />
        </button>
      </div>
    </div>
  );
}
