import { useState, useEffect } from 'react';
import { Icon } from '@/components/Icon';
import { BrandHeader } from '@/components/BrandHeader';
import { ProviderBadge } from '@/components/ProviderBadge';
import { useApp } from '@/store/AppStore';
import { signOut } from '@/services/auth';
import { getSupabase } from '@/lib/supabase';
import { AuthScreen } from './AuthScreen';
import { AdminScreen, useIsAdmin } from './AdminScreen';

interface SettingRowProps {
  icon: string;
  iconOn?: boolean;
  title: string;
  sub?: string;
  right?: React.ReactNode;
}

function SettingRow({ icon, iconOn, title, sub, right }: SettingRowProps) {
  return (
    <div className="set-row">
      <div className={'set-ico' + (iconOn ? ' on' : '')}>
        <Icon name={icon} size={20} />
      </div>
      <div style={{ flex: 1, minWidth: 0 }}>
        <div style={{ fontWeight: 700, fontSize: 14 }}>{title}</div>
        {sub && (
          <div className="muted" style={{ fontSize: 12, fontWeight: 600, marginTop: 2 }}>
            {sub}
          </div>
        )}
      </div>
      {right}
    </div>
  );
}

function MiniToggle({ value, onChange }: { value: boolean; onChange: (v: boolean) => void }) {
  return (
    <button
      type="button"
      className={'voice-toggle' + (value ? ' on' : '')}
      onClick={() => onChange(!value)}
      style={{ padding: 0, width: 46, height: 30, justifyContent: 'center' }}
    >
      <span className="sw" />
    </button>
  );
}

function FeedbackSheet({ onClose }: { onClose: () => void }) {
  const { user, showToast } = useApp();
  const [text, setText] = useState('');
  const [cat, setCat] = useState('기능');
  const [busy, setBusy] = useState(false);
  const CATS = ['기능', '시세·데이터', '지도', '버그', '기타'];

  async function submit() {
    if (!text.trim() || busy) return;
    setBusy(true);
    try {
      const sb = getSupabase();
      if (!sb) throw new Error('Supabase 미구성');
      const { error } = await sb.from('feedback').insert({
        user_id: user?.id ?? null,
        user_email: user?.email ?? null,
        category: cat,
        content: text.trim(),
      });
      if (error) throw error;
      showToast('소중한 의견 고마워요!');
      onClose();
    } catch (e) {
      showToast((e as Error).message ?? '전송 실패');
    } finally {
      setBusy(false);
    }
  }
  return (
    <div className="sheet-scrim" onClick={onClose} style={{ zIndex: 130 }}>
      <div
        className="filter-sheet"
        onClick={(e) => e.stopPropagation()}
        style={{ maxHeight: '90%', overflowY: 'auto' }}
      >
        <div className="sheet-grip" />
        <div className="row between" style={{ marginBottom: 6, padding: '0 2px' }}>
          <div style={{ fontWeight: 800, fontSize: 18, letterSpacing: '-.02em' }}>기능 건의</div>
          <button onClick={onClose} type="button" style={{ color: 'var(--ink-3)', padding: 4 }}>
            <Icon name="x" size={20} />
          </button>
        </div>
        <div
          className="muted"
          style={{
            fontSize: 12.5,
            fontWeight: 600,
            marginBottom: 18,
            padding: '0 2px',
            lineHeight: 1.5,
          }}
        >
          어떤 기능이 있으면 좋을지 알려주세요. 보내주신 의견은 다음 업데이트에 반영해요.
        </div>
        <div className="sect-cap" style={{ marginBottom: 8, marginLeft: 2 }}>
          분류
        </div>
        <div className="chip-wrap" style={{ marginBottom: 18 }}>
          {CATS.map((c) => (
            <button
              key={c}
              type="button"
              className={'filter-chip' + (cat === c ? ' on' : '')}
              onClick={() => setCat(c)}
            >
              {c}
            </button>
          ))}
        </div>
        <div className="sect-cap" style={{ marginBottom: 8, marginLeft: 2 }}>
          내용
        </div>
        <textarea
          className="plan-memo"
          style={{ minHeight: 120 }}
          value={text}
          onChange={(e) => setText(e.target.value)}
          placeholder="예) 관심 단지 가격이 바뀌면 알림을 받고 싶어요"
        />
        <button
          className="btn btn-primary"
          type="button"
          style={{
            marginTop: 18,
            opacity: text.trim() ? 1 : 0.45,
            pointerEvents: text.trim() ? 'auto' : 'none',
          }}
          disabled={!text.trim() || busy}
          onClick={submit}
        >
          <Icon name="arrowR" size={18} stroke={2.4} />
          {busy ? '전송 중…' : '건의 보내기'}
        </button>
        <div style={{ height: 8 }} />
      </div>
    </div>
  );
}

export function Settings() {
  const { user, voiceOn, setVoiceOn, showProxBanner, setShowProxBanner, showToast } = useApp();
  const [showAuth, setShowAuth] = useState(false);
  const [showAdmin, setShowAdmin] = useState(false);
  const [fbOpen, setFbOpen] = useState(false);
  const { isAdmin } = useIsAdmin();

  // 로그인 성공(user 설정) 시 로그인 화면 자동 닫기 — OAuth 콜백 복귀 후 화면이 남는 문제 해결
  useEffect(() => {
    if (showAuth && user) setShowAuth(false);
  }, [user, showAuth]);

  if (showAdmin) return <AdminScreen onClose={() => setShowAdmin(false)} />;

  if (showAuth) {
    return (
      <div style={{ position: 'absolute', inset: 0, background: 'var(--bg)', zIndex: 5 }}>
        <AuthScreen onClose={() => setShowAuth(false)} />
      </div>
    );
  }

  return (
    <div className="screen fade-in" style={{ background: 'var(--bg)' }}>
      <div
        style={{
          background: 'var(--surface)',
          padding: 'calc(var(--safe-top) + 10px) 22px 12px',
        }}
      >
        <BrandHeader onBellClick={() => showToast('새 알림이 없어요')} />
      </div>
      <div className="scroll pad" style={{ paddingTop: 30 }}>
        <div className="sect-cap" style={{ marginBottom: 9, marginLeft: 2 }}>
          계정
        </div>
        {user ? (
          <div
            className="card"
            style={{ padding: 16, display: 'flex', alignItems: 'center', gap: 12 }}
          >
            {user.avatarUrl ? (
              <img
                src={user.avatarUrl}
                alt=""
                style={{ width: 48, height: 48, borderRadius: 50, objectFit: 'cover' }}
              />
            ) : (
              <div className="avatar">
                <Icon name="user" size={24} />
              </div>
            )}
            <div style={{ flex: 1, minWidth: 0 }}>
              <div className="row gap6" style={{ alignItems: 'center' }}>
                <div style={{ fontWeight: 800, fontSize: 15 }}>
                  {user.displayName ?? user.email ?? '계정'}
                </div>
                <ProviderBadge provider={user.provider} />
              </div>
              {user.email && (
                <div
                  className="muted"
                  style={{ fontSize: 12.5, fontWeight: 600, marginTop: 2 }}
                >
                  {user.email}
                </div>
              )}
            </div>
            <button
              className="btn btn-ghost btn-sm"
              style={{ width: 'auto', padding: '0 12px' }}
              onClick={async () => {
                await signOut();
                showToast('로그아웃했어요');
              }}
              type="button"
            >
              <Icon name="logout" size={15} />
              로그아웃
            </button>
          </div>
        ) : (
          <div className="card" style={{ padding: 16 }}>
            <div style={{ fontWeight: 800, fontSize: 15.5, marginBottom: 3 }}>
              로그인하고 기기 간 동기화
            </div>
            <div
              className="muted"
              style={{ fontSize: 12.5, fontWeight: 600, lineHeight: 1.5, marginBottom: 14 }}
            >
              임장노트·사진·세션을 클라우드에 보관해 기기를 바꿔도 그대로 이어쓸 수 있어요.
            </div>
            <button
              className="btn btn-primary"
              type="button"
              onClick={() => setShowAuth(true)}
            >
              <Icon name="user" size={18} />
              로그인 / 가입
            </button>
          </div>
        )}

        <div className="sect-cap" style={{ margin: '24px 0 9px 2px' }}>
          알림 · 음성
        </div>
        <div className="card" style={{ padding: '4px 16px' }}>
          <SettingRow
            icon={voiceOn ? 'speaker' : 'muted'}
            iconOn={voiceOn}
            title="근접 음성 안내"
            sub="가까운 단지에 다가가면 시세를 읽어줘요"
            right={<MiniToggle value={voiceOn} onChange={setVoiceOn} />}
          />
          <div style={{ height: 1, background: 'var(--line)' }} />
          <SettingRow
            icon="bell"
            title="배너 알림"
            sub="단지 근처 진입 시 상단 배너 표시"
            right={<MiniToggle value={showProxBanner} onChange={setShowProxBanner} />}
          />
        </div>

        <div className="sect-cap" style={{ margin: '24px 0 9px 2px' }}>
          의견
        </div>
        <div className="card" style={{ padding: '4px 16px' }}>
          <button
            type="button"
            onClick={() => setFbOpen(true)}
            style={{
              display: 'block',
              width: '100%',
              textAlign: 'left',
              background: 'none',
              padding: 0,
            }}
          >
            <SettingRow
              icon="help"
              iconOn
              title="필요한 기능 건의하기"
              sub="이런 기능이 있으면 좋겠어요"
              right={<Icon name="chevR" size={18} color="var(--ink-4)" />}
            />
          </button>
        </div>

        {isAdmin && (
          <>
            <div className="sect-cap" style={{ margin: '24px 0 9px 2px' }}>
              관리자
            </div>
            <div className="card" style={{ padding: '4px 16px' }}>
              <button
                type="button"
                onClick={() => setShowAdmin(true)}
                style={{ display: 'block', width: '100%', textAlign: 'left', background: 'none', padding: 0 }}
              >
                <SettingRow
                  icon="gear"
                  iconOn
                  title="관리자 콘솔"
                  sub="대시보드 · 사용자 분석 · 건의 관리"
                  right={<Icon name="chevR" size={18} color="var(--ink-4)" />}
                />
              </button>
            </div>
          </>
        )}

        <div className="sect-cap" style={{ margin: '24px 0 9px 2px' }}>
          정보
        </div>
        <div className="card" style={{ padding: '4px 16px' }}>
          <SettingRow
            icon="won"
            title="실거래가 출처"
            sub="국토교통부 RTMS 신고자료"
            right={<Icon name="chevR" size={18} color="var(--ink-4)" />}
          />
          <div style={{ height: 1, background: 'var(--line)' }} />
          <SettingRow
            icon="map"
            title="지도"
            sub="MapLibre · OpenFreeMap"
            right={<Icon name="chevR" size={18} color="var(--ink-4)" />}
          />
          <div style={{ height: 1, background: 'var(--line)' }} />
          <SettingRow icon="alert" title="버전" sub="1.0.0" />
        </div>

        <div className="legal">
          실거래가는 국토교통부 신고 자료 기반이며 계약일·신고일 시차로 최신성이 제한될 수 있어요.
          참고용이며 법적 효력은 없습니다.
        </div>
        <div style={{ height: 20 }} />
      </div>
      {fbOpen && <FeedbackSheet onClose={() => setFbOpen(false)} />}
    </div>
  );
}
