import { Icon } from '@/components/Icon';
import { Stars } from '@/components/Stars';
import { TypeChip, EvalDot } from '@/components/Toast';
import { useApp, repArea, complexById } from '@/store/AppStore';
import { wonShort } from '@/lib/format';
import type { Complex, EvalState } from '@/types/domain';

const KEY_CHECKS: { key: string; label: string }[] = [
  { key: 'transit', label: '역세권' },
  { key: 'parking', label: '주차' },
  { key: 'mgmt', label: '관리' },
  { key: 'noise', label: '소음' },
  { key: 'sun', label: '일조' },
];

function evalKo(v: EvalState | undefined): string {
  return v === 'good' ? '좋음' : v === 'soso' ? '보통' : v === 'bad' ? '나쁨' : '–';
}

export function Compare({ id }: { id: string }) {
  const { sessions, complexes, notes, popOverlay, openNote } = useApp();
  const s = sessions.find((x) => x.id === id);
  if (!s) return null;
  const visited: Complex[] = s.complexIds
    .map((cid) => complexById(complexes, cid))
    .filter((c): c is Complex => !!c);

  const colW = visited.length <= 2 ? 150 : 132;
  const gridCols = `108px repeat(${visited.length}, ${colW}px)`;

  function row(
    label: string,
    render: (c: Complex) => React.ReactNode,
    alt = false,
  ) {
    return (
      <div className="cmp-grid" style={{ gridTemplateColumns: gridCols }}>
        <div className="cmp-rowlabel" style={{ background: alt ? '#fff' : 'var(--surface-2)' }}>
          {label}
        </div>
        {visited.map((c) => (
          <div
            key={c.id}
            className="cmp-cell"
            style={{ background: alt ? '#fff' : 'var(--surface-2)' }}
          >
            {render(c)}
          </div>
        ))}
      </div>
    );
  }

  return (
    <div className="screen push-enter" style={{ background: 'var(--bg)' }}>
      <div className="navbar">
        <button className="backbtn" onClick={popOverlay} type="button">
          <Icon name="back" size={22} />
        </button>
        <h2>단지 비교</h2>
        <div className="grow" />
        <span className="sect-cap">{s.dateLabel ?? s.date}</span>
      </div>
      <div className="scroll" style={{ padding: '8px 0 0' }}>
        <div className="pad">
          <div
            className="muted"
            style={{ fontSize: 13, fontWeight: 600, marginBottom: 12, lineHeight: 1.5 }}
          >
            한 세션에서 본 단지를 나란히 비교해 최종 후보를 정하세요. 색이 좋음·보통·나쁨이에요.
          </div>
        </div>
        <div className="cmp-scroll">
          <div style={{ minWidth: 'max-content' }}>
            <div
              className="cmp-grid"
              style={{
                gridTemplateColumns: gridCols,
                position: 'sticky',
                top: 0,
                zIndex: 3,
                background: '#fff',
              }}
            >
              <div className="cmp-rowlabel" style={{ background: '#fff' }} />
              {visited.map((c) => (
                <div
                  key={c.id}
                  className="cmp-head"
                  onClick={() => openNote(c.id)}
                  style={{ cursor: 'pointer' }}
                >
                  <TypeChip type={c.type} />
                  <div style={{ fontWeight: 700, fontSize: 12.5, marginTop: 6, lineHeight: 1.3 }}>
                    {c.name}
                  </div>
                  <div className="price-cap" style={{ marginTop: 3 }}>
                    {(c.distM ?? 0) + 'm'}
                  </div>
                </div>
              ))}
            </div>
            {row(
              '총평 별점',
              (c) => {
                const n = notes[c.id];
                return n && n.rating ? <Stars rating={n.rating} /> : <span className="muted">–</span>;
              },
              true,
            )}
            {row(
              `${repArea(visited[0]).m2}㎡대 시세`,
              (c) => (
                <span className="num" style={{ color: 'var(--accent)', fontWeight: 900 }}>
                  {wonShort(repArea(c).price)}
                </span>
              ),
            )}
            {KEY_CHECKS.map((kc, i) =>
              row(
                kc.label,
                (c) => {
                  const n = notes[c.id];
                  const v = (n?.checks?.[kc.key]) as EvalState | undefined;
                  return (
                    <span
                      style={{
                        color:
                          v === 'good'
                            ? 'var(--good)'
                            : v === 'soso'
                            ? 'var(--soso)'
                            : v === 'bad'
                            ? 'var(--bad)'
                            : 'var(--ink-4)',
                      }}
                    >
                      <EvalDot v={v} />
                      {evalKo(v)}
                    </span>
                  );
                },
                i % 2 === 0,
              ),
            )}
            {row(
              '한 줄 평',
              (c) => {
                const n = notes[c.id];
                return (
                  <span
                    style={{
                      fontSize: 11.5,
                      fontWeight: 600,
                      color: 'var(--ink-2)',
                      lineHeight: 1.4,
                      display: 'block',
                    }}
                  >
                    {n?.oneliner ? n.oneliner : '–'}
                  </span>
                );
              },
              KEY_CHECKS.length % 2 === 0,
            )}
          </div>
        </div>
        <div className="pad" style={{ marginTop: 18 }}>
          <div
            className="card"
            style={{
              padding: 14,
              display: 'flex',
              gap: 10,
              alignItems: 'center',
              background: 'var(--accent-tint)',
              boxShadow: 'none',
            }}
          >
            <Icon name="alert" size={20} color="var(--accent-press)" />
            <span
              style={{
                fontSize: 12.5,
                fontWeight: 600,
                color: 'var(--accent-press)',
                lineHeight: 1.45,
              }}
            >
              열 제목을 누르면 해당 단지 임장노트로 이동해 기록을 수정할 수 있어요.
            </span>
          </div>
        </div>
        <div style={{ height: 30 }} />
      </div>
    </div>
  );
}
