import { useEffect, useState } from 'react';
import { Icon } from '@/components/Icon';
import { StatusBar } from '@/components/StatusBar';
import { requestLocationPermission } from '@/services/geolocation';
import { Geolocation } from '@capacitor/geolocation';
import { Capacitor } from '@capacitor/core';

interface SplashProps {
  onDone: (mode?: 'manual') => void;
}

type Step = 'logo' | 'perm' | 'locating';

export function Splash({ onDone }: SplashProps) {
  const [step, setStep] = useState<Step>('logo');

  useEffect(() => {
    let cancelled = false;
    let timer: ReturnType<typeof setTimeout> | null = null;
    void (async () => {
      // 이미 위치 권한이 허용돼 있으면 권한 시트를 건너뛰고 바로 진행 (매 실행 재요청 방지)
      try {
        if (Capacitor.isNativePlatform()) {
          const st = await Geolocation.checkPermissions();
          if (cancelled) return;
          if (st.location === 'granted' || st.coarseLocation === 'granted') {
            void allow();
            return;
          }
        }
      } catch {
        /* checkPermissions 실패 시 일반 흐름(권한 시트)으로 */
      }
      if (!cancelled) timer = setTimeout(() => setStep('perm'), 1100);
    })();
    return () => { cancelled = true; if (timer) clearTimeout(timer); };
    // allow는 setStep/onDone만 사용 — 마운트 1회로 충분
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  async function allow() {
    setStep('locating');
    try {
      // 권한 query가 hang되는 환경(특정 헤드리스 브라우저) 대비 타임아웃
      await Promise.race([
        requestLocationPermission(),
        new Promise((r) => setTimeout(r, 1500)),
      ]);
    } catch {
      /* user rejection 등 — 그대로 진행 */
    }
    onDone();
  }

  return (
    <div className="splash">
      <StatusBar dark />
      <div className="splash-logo">
        <Icon name="loc" size={46} color="#fff" stroke={2} />
      </div>
      <h1>단지노트</h1>
      <p>
        검색 없이, 현위치 기준으로
        <br />
        주변 단지 실거래가를 바로
      </p>
      {step === 'locating' && (
        <>
          <div style={{ marginTop: 26, display: 'flex', gap: 6 }}>
            {[0, 1, 2].map((i) => (
              <span
                key={i}
                style={{
                  width: 8,
                  height: 8,
                  borderRadius: '50%',
                  background: '#fff',
                  animation: `mepulse 1s ${i * 0.18}s infinite`,
                  opacity: 0.9,
                }}
              />
            ))}
          </div>
          <p style={{ marginTop: 14, fontSize: 13 }}>현위치 확인 중…</p>
        </>
      )}
      {step === 'perm' && (
        <div className="perm-sheet">
          <div className="perm-ico">
            <Icon name="loc" size={26} />
          </div>
          <div style={{ fontWeight: 900, fontSize: 19, letterSpacing: '-.02em' }}>
            위치 권한이 필요해요
          </div>
          <p
            style={{
              color: 'var(--ink-2)',
              fontSize: 13.5,
              fontWeight: 500,
              margin: '8px 0 4px',
              lineHeight: 1.55,
              textAlign: 'left',
            }}
          >
            현위치 주변 단지를 거리순으로 바로 보여드리고, 단지에 가까워지면 음성·알림으로 시세를 안내해요.
          </p>
          <div className="row gap8" style={{ margin: '14px 0 16px' }}>
            <div
              className="row gap6"
              style={{ fontSize: 12, color: 'var(--ink-3)', fontWeight: 700 }}
            >
              <Icon name="bell" size={15} />
              알림은 선택이에요
            </div>
          </div>
          <button className="btn btn-primary" onClick={allow} type="button">
            위치 사용 허용
          </button>
          <button
            className="btn btn-ghost"
            style={{ height: 48, marginTop: 8 }}
            onClick={() => onDone('manual')}
            type="button"
          >
            지역 직접 선택
          </button>
        </div>
      )}
    </div>
  );
}
