import { useEffect, useState } from 'react';
import { Icon } from '@/components/Icon';
import { Avatar } from '@/components/Avatar';
import { BrandHeader } from '@/components/BrandHeader';
import { useApp } from '@/store/AppStore';

export function Friends() {
  const { friends, refreshFriends, createFriendInvite, setFriendAlias, removeFriend, confirmAlert, showToast, user, setTab } = useApp();
  const [busy, setBusy] = useState(false);
  const [editId, setEditId] = useState<string | null>(null);
  const [draft, setDraft] = useState('');
  const isLoggedIn = !!user;

  useEffect(() => {
    if (isLoggedIn) void refreshFriends();
  }, [refreshFriends, isLoggedIn]);

  async function invite() {
    setBusy(true);
    try {
      const link = await createFriendInvite();
      if (!link) {
        showToast('초대 링크를 만들지 못했어요');
        return;
      }
      const shared = await tryShareOrCopy(link, '단지노트 친구 초대');
      showToast(shared === 'share' ? '초대 링크를 공유했어요' : '초대 링크를 복사했어요');
    } finally {
      setBusy(false);
    }
  }

  return (
    <div className="screen fade-in">
      <div style={{ background: 'var(--surface)', padding: 'calc(var(--safe-top) + 10px) 22px 12px' }}>
        <BrandHeader onBellClick={() => showToast('새 알림이 없어요')} />
      </div>
      <div className="scroll pad" style={{ paddingTop: 12 }}>
        {!isLoggedIn ? (
          <div className="empty-state">
            <div className="empty-ico">
              <Icon name="people" size={26} />
            </div>
            <div style={{ fontWeight: 700, fontSize: 14.5, color: 'var(--ink-2)' }}>
              친구는 로그인 후 이용할 수 있어요
            </div>
            <div className="muted" style={{ fontSize: 12.5, fontWeight: 600, marginTop: 6, lineHeight: 1.5 }}>
              친구 추가·초대 수락은 로그인이 필요해요.<br />로그인하면 친구·공유가 계정에 유지돼요.
            </div>
            <button
              type="button"
              className="btn btn-primary"
              style={{ marginTop: 16 }}
              onClick={() => setTab('settings')}
            >
              <Icon name="user" size={17} />
              로그인하러 가기
            </button>
          </div>
        ) : (
        <>
        <div className="row between" style={{ margin: '4px 2px 14px', alignItems: 'center' }}>
          <span style={{ fontWeight: 800, fontSize: 20, letterSpacing: '-.02em' }}>친구</span>
          <span className="muted" style={{ fontSize: 13, fontWeight: 700 }}>{`${friends.length}명`}</span>
        </div>

        <button
          type="button"
          className="btn btn-primary"
          onClick={() => void invite()}
          disabled={busy}
          style={{ marginBottom: 18 }}
        >
          <Icon name="share" size={17} stroke={2.2} />
          친구 초대 링크 만들기
        </button>

        {friends.length === 0 ? (
          <div className="empty-state">
            <div className="empty-ico">
              <Icon name="people" size={26} />
            </div>
            <div style={{ fontWeight: 700, fontSize: 14.5, color: 'var(--ink-2)' }}>아직 친구가 없어요</div>
            <div className="muted" style={{ fontSize: 12.5, fontWeight: 600, marginTop: 6, lineHeight: 1.5 }}>
              초대 링크를 보내면<br />친구와 임장 계획·메모를 함께 볼 수 있어요
            </div>
          </div>
        ) : (
          <div className="card" style={{ padding: '4px 14px' }}>
            {friends.map((m, i) => {
              const editing = editId === m.id;
              const saveAlias = async () => {
                setEditId(null);
                await setFriendAlias(m.id, draft);
              };
              return (
                <div key={m.id} className={'member-row' + (i ? ' br' : '')}>
                  <Avatar m={m} size={38} />
                  {editing ? (
                    <div className="row gap6" style={{ flex: 1, minWidth: 0 }}>
                      <input
                        autoFocus
                        value={draft}
                        placeholder={m.baseName}
                        onChange={(e) => setDraft(e.target.value)}
                        onKeyDown={(e) => {
                          if (e.key === 'Enter') void saveAlias();
                          if (e.key === 'Escape') setEditId(null);
                        }}
                        style={{
                          flex: 1, minWidth: 0, fontWeight: 700, fontSize: 14,
                          padding: '5px 9px', border: '1.5px solid var(--accent)',
                          borderRadius: 8, outline: 'none', background: 'var(--surface)', color: 'var(--ink)',
                        }}
                      />
                      <button type="button" className="plan-member-btn" onClick={() => void saveAlias()} style={{ color: 'var(--accent)' }}>
                        <Icon name="check" size={14} stroke={2.4} />저장
                      </button>
                    </div>
                  ) : (
                    <>
                      <div style={{ flex: 1, minWidth: 0 }}>
                        <div style={{ fontWeight: 700, fontSize: 14.5, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
                          {m.name}
                        </div>
                        {m.alias && (
                          <div className="muted" style={{ fontSize: 11.5, fontWeight: 600, marginTop: 1 }}>
                            {m.baseName}
                          </div>
                        )}
                      </div>
                      <button
                        type="button"
                        className="plan-x"
                        title="별명 수정"
                        onClick={() => { setDraft(m.alias ?? ''); setEditId(m.id); }}
                      >
                        <Icon name="edit" size={15} stroke={2} />
                      </button>
                      <button
                        type="button"
                        className="plan-x"
                        title="친구 삭제"
                        onClick={async () => {
                          const ok = await confirmAlert({
                            title: '친구 삭제',
                            message: `"${m.name}"\n친구에서 삭제할까요?`,
                            confirmLabel: '삭제',
                            danger: true,
                          });
                          if (ok) void removeFriend(m.id);
                        }}
                      >
                        <Icon name="x" size={16} />
                      </button>
                    </>
                  )}
                </div>
              );
            })}
          </div>
        )}
        </>
        )}
      </div>
    </div>
  );
}

/** Web Share API 우선, 실패 시 클립보드 복사. 반환: 'share' | 'copy' */
export async function tryShareOrCopy(text: string, title?: string): Promise<'share' | 'copy'> {
  try {
    const nav = navigator as Navigator & { share?: (d: { title?: string; url?: string; text?: string }) => Promise<void> };
    if (typeof nav.share === 'function') {
      await nav.share({ title, url: text });
      return 'share';
    }
  } catch { /* 취소/실패 → 복사 폴백 */ }
  try {
    await navigator.clipboard.writeText(text);
  } catch { /* ignore */ }
  return 'copy';
}
