// Korean TTS via Web SpeechSynthesis. 모바일 WebView/Safari/Chrome 모두 지원.

let enabled = true;

export function setTTSEnabled(v: boolean): void {
  enabled = v;
}

export function isTTSEnabled(): boolean {
  return enabled;
}

export function speak(text: string, opts: { lang?: string; rate?: number; force?: boolean } = {}): void {
  if (!opts.force && !enabled) return;
  if (typeof speechSynthesis === 'undefined') return;
  try {
    const u = new SpeechSynthesisUtterance(text);
    u.lang = opts.lang ?? 'ko-KR';
    u.rate = opts.rate ?? 1.05;
    speechSynthesis.cancel();
    speechSynthesis.speak(u);
  } catch {
    /* ignore */
  }
}

export function stopSpeaking(): void {
  if (typeof speechSynthesis === 'undefined') return;
  try {
    speechSynthesis.cancel();
  } catch {
    /* ignore */
  }
}
