import { getSupabase } from '@/lib/supabase';
import { ProviderBadge } from '@/components/ProviderBadge';

export function useIsAdmin(): { ready: boolean; isAdmin: boolean } {
  const { user } = useApp();
  const [state, setState] = useState<{ ready: boolean; isAdmin: boolean }>({ ready: false, isAdmin: false });
  useEffect(() => {
    let cancel = false;
    void (async () => {
      if (!user?.email) { if (!cancel) setState({ ready: true, isAdmin: false }); return; }
      const sb = getSupabase();
      if (!sb) { if (!cancel) setState({ ready: true, isAdmin: false }); return; }
      const { data } = await sb.from('admin_users').select('email').eq('email', user.email).maybeSingle();
      if (!cancel) setState({ ready: true, isAdmin: !!data });
    })();
    return () => { cancel = true; };
  }, [user?.email]);
  return state;
}

type AdminTab = 'dash' | 'users' | 'feedback';

interface StatCardProps { label: string; value: string | number; delta?: string; tone?: 'up' | 'down' | 'flat'; }
function StatCard({ label, value, delta, tone }: StatCardProps) {
  const color = tone === 'up' ? 'var(--good)' : tone === 'down' ? 'var(--bad)' : 'var(--ink-3)';
  return (
    <div className="card" style={{ padding: 16, minWidth: 140, flex: 1 }}>
      <div className="muted" style={{ fontSize: 12, fontWeight: 700 }}>{label}</div>
      <div style={{ fontWeight: 900, fontSize: 22, marginTop: 4, letterSpacing: '-.02em' }}>{value}</div>
      {delta && <div style={{ fontSize: 11.5, fontWeight: 700, color, marginTop: 2 }}>{delta}</div>}
    </div>
  );
}

function MiniLineChart({ data, height = 64, color = 'var(--accent)' }: { data: number[]; height?: number; color?: string }) {
  if (data.length === 0) return <div style={{ height, background: 'var(--surface-2)', borderRadius: 6 }} />;
  const max = Math.max(...data, 1);
  const W = 280, H = height;
  const step = data.length > 1 ? W / (data.length - 1) : 0;
  const pts = data.map((v, i) => `${i * step},${H - (v / max) * (H - 8) - 4}`).join(' ');
  return (
    <svg viewBox={`0 0 ${W} ${H}`} preserveAspectRatio="none" style={{ width: '100%', height, display: 'block' }}>
      <polyline points={pts} fill="none" stroke={color} strokeWidth={2} strokeLinecap="round" strokeLinejoin="round" />
      {data.map((v, i) => (
        <circle key={i} cx={i * step} cy={H - (v / max) * (H - 8) - 4} r={2.5} fill={color} />
      ))}
    </svg>
  );
}

interface DashboardData {
  totalUsers: number;
  newUsersToday: number;
  newUsers7d: number;
  totalPlans: number;
  totalSessions: number;
  totalComplexes: number;
  openFeedback: number;
  providerDist: { provider: string; count: number }[];
  signupTrend: number[]; // 최근 14일
}

function DashboardTab() {
  const [data, setData] = useState<DashboardData | null>(null);
  const [err, setErr] = useState<string | null>(null);

  useEffect(() => {
    void (async () => {
      const sb = getSupabase();
      if (!sb) { setErr('Supabase 미구성'); return; }
      try {
        // 4개 count 통합 RPC (complexes 직접 SELECT 금지 — RLS service-only)
        const { data: dashRows, error: dashErr } = await sb.rpc('admin_dashboard_counts');
        if (dashErr) throw dashErr;
        const dash = (dashRows as Array<{
          plans_count: number;
          sessions_count: number;
          canonical_complexes_count: number;
          open_feedback_count: number;
        }> | null)?.[0];
        if (!dash) throw new Error('admin RPC 결과 없음');
        // auth.users는 직접 query 불가 — admin_users로 가져온 user_id (plans/sessions) 또는 별도 RPC 필요
        // 일단 plans + sessions의 distinct user_id로 활성 사용자 수 추정. 가입 trend는 plans.created_at 기준
        const { data: planRows } = await sb.from('imjang_plans').select('user_id, created_at').order('created_at', { ascending: false }).limit(500);
        const { data: sessionRows } = await sb.from('imjang_sessions').select('user_id, date').order('date', { ascending: false }).limit(500);
        const userIds = new Set<string>();
        (planRows ?? []).forEach((r) => r.user_id && userIds.add(r.user_id));
        (sessionRows ?? []).forEach((r) => r.user_id && userIds.add(r.user_id));
        // signup trend: feedback table created_at으로는 신규 가입 알 수 없음 — plans 첫 활동 기준 대용
        const dayKey = (d: Date) => d.toISOString().slice(0, 10);
        const todayKey = dayKey(new Date());
        const past14 = [...Array(14)].map((_, i) => {
          const d = new Date(); d.setDate(d.getDate() - (13 - i));
          return dayKey(d);
        });
        const dailyMap: Record<string, Set<string>> = {};
        past14.forEach((k) => (dailyMap[k] = new Set()));
        (planRows ?? []).forEach((r) => {
          if (!r.user_id || !r.created_at) return;
          const k = String(r.created_at).slice(0, 10);
          if (dailyMap[k]) dailyMap[k].add(r.user_id);
        });
        const signupTrend = past14.map((k) => dailyMap[k].size);
        const newUsersToday = dailyMap[todayKey].size;
        const newUsers7d = past14.slice(-7).reduce((s, k) => s + dailyMap[k].size, 0);

        // provider 분포: plans/sessions가 user_id만 가지고 있어 직접 알 수 없음 — feedback의 user_email 또는 별도 metadata 필요
        // 일단 비워둠 (provider 컬럼 따로 만들면 정확해짐)
        const providerDist: { provider: string; count: number }[] = [];

        setData({
          totalUsers: userIds.size,
          newUsersToday,
          newUsers7d,
          totalPlans: dash.plans_count ?? 0,
          totalSessions: dash.sessions_count ?? 0,
          totalComplexes: dash.canonical_complexes_count ?? 0,
          openFeedback: dash.open_feedback_count ?? 0,
          providerDist,
          signupTrend,
        });
      } catch (e) {
        setErr((e as Error).message);
      }
    })();
  }, []);

  if (err) return <div className="card" style={{ padding: 16, color: 'var(--bad)' }}>로드 실패: {err}</div>;
  if (!data) return <div className="card" style={{ padding: 16, color: 'var(--ink-3)' }}>불러오는 중…</div>;

  return (
    <div className="col gap8">
      <div className="row gap6" style={{ flexWrap: 'wrap' }}>
        <StatCard label="총 활성 사용자" value={data.totalUsers.toLocaleString()} />
        <StatCard label="오늘 활동" value={data.newUsersToday.toLocaleString()} tone="up" />
        <StatCard label="최근 7일 활동" value={data.newUsers7d.toLocaleString()} />
      </div>
      <div className="row gap6" style={{ flexWrap: 'wrap' }}>
        <StatCard label="총 임장계획" value={data.totalPlans.toLocaleString()} />
        <StatCard label="총 세션" value={data.totalSessions.toLocaleString()} />
        <StatCard label="등록 단지" value={data.totalComplexes.toLocaleString()} />
        <StatCard label="미처리 건의" value={data.openFeedback.toLocaleString()} tone={data.openFeedback > 0 ? 'down' : 'flat'} />
      </div>
      <div className="card" style={{ padding: 16 }}>
        <div className="row between" style={{ marginBottom: 8 }}>
          <div style={{ fontWeight: 800, fontSize: 14 }}>일자별 활동 사용자 (최근 14일)</div>
          <div className="muted" style={{ fontSize: 11.5, fontWeight: 600 }}>임장계획 생성 기준</div>
        </div>
        <MiniLineChart data={data.signupTrend} height={80} />
      </div>
    </div>
  );
}

interface UserRow {
  user_id: string;
  email: string | null;
  planCount: number;
  sessionCount: number;
  lastActivity: string;
}

function UsersTab() {
  const [rows, setRows] = useState<UserRow[]>([]);
  const [err, setErr] = useState<string | null>(null);
  const [q, setQ] = useState('');

  useEffect(() => {
    void (async () => {
      const sb = getSupabase();
      if (!sb) { setErr('Supabase 미구성'); return; }
      try {
        const [{ data: plans }, { data: sessions }] = await Promise.all([
          sb.from('imjang_plans').select('user_id, created_at').limit(2000),
          sb.from('imjang_sessions').select('user_id, date, area_name').limit(2000),
        ]);
        // feedback에서 user_email 매핑
        const { data: fbs } = await sb.from('feedback').select('user_id, user_email');
        const emailMap = new Map<string, string>();
        (fbs ?? []).forEach((r) => { if (r.user_id && r.user_email) emailMap.set(r.user_id, r.user_email); });

        const userMap = new Map<string, { planCount: number; sessionCount: number; lastActivity: string }>();
        (plans ?? []).forEach((r) => {
          if (!r.user_id) return;
          const cur = userMap.get(r.user_id) ?? { planCount: 0, sessionCount: 0, lastActivity: '' };
          cur.planCount++;
          if (r.created_at && r.created_at > cur.lastActivity) cur.lastActivity = String(r.created_at).slice(0, 10);
          userMap.set(r.user_id, cur);
        });
        (sessions ?? []).forEach((r) => {
          if (!r.user_id) return;
          const cur = userMap.get(r.user_id) ?? { planCount: 0, sessionCount: 0, lastActivity: '' };
          cur.sessionCount++;
          if (r.date && r.date > cur.lastActivity) cur.lastActivity = r.date;
          userMap.set(r.user_id, cur);
        });

        const list: UserRow[] = Array.from(userMap.entries()).map(([uid, v]) => ({
          user_id: uid,
          email: emailMap.get(uid) ?? null,
          planCount: v.planCount,
          sessionCount: v.sessionCount,
          lastActivity: v.lastActivity || '-',
        }));
        list.sort((a, b) => b.lastActivity.localeCompare(a.lastActivity));
        setRows(list);
      } catch (e) {
        setErr((e as Error).message);
      }
    })();
  }, []);

  const filtered = useMemo(() => {
    if (!q.trim()) return rows;
    const k = q.trim().toLowerCase();
    return rows.filter((r) => (r.email ?? '').toLowerCase().includes(k) || r.user_id.includes(k));
  }, [rows, q]);

  if (err) return <div className="card" style={{ padding: 16, color: 'var(--bad)' }}>로드 실패: {err}</div>;
  return (
    <div className="col gap8">
      <input
        className="auth-input"
        placeholder="이메일 또는 user_id 검색"
        value={q}
        onChange={(e) => setQ(e.target.value)}
      />
      <div className="card" style={{ padding: 12 }}>
        <div className="muted" style={{ fontSize: 11.5, fontWeight: 700, marginBottom: 6 }}>
          {filtered.length}명 표시 (전체 {rows.length}명)
        </div>
        {filtered.length === 0 ? (
          <div className="muted" style={{ fontSize: 13, padding: '24px 0', textAlign: 'center' }}>사용자 없음</div>
        ) : (
          filtered.slice(0, 200).map((r, i) => (
            <div
              key={r.user_id}
              className="row gap6"
              style={{
                padding: '10px 4px',
                borderTop: i ? '1px solid var(--line)' : 'none',
                alignItems: 'center',
              }}
            >
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ fontWeight: 700, fontSize: 13, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                  {r.email ?? r.user_id.slice(0, 8) + '…'}
                </div>
                <div className="muted" style={{ fontSize: 11, fontWeight: 600, marginTop: 2 }}>
                  마지막 활동 · {r.lastActivity}
                </div>
              </div>
              <div className="num" style={{ fontSize: 12, fontWeight: 800, color: 'var(--accent)', minWidth: 56, textAlign: 'right' }}>
                계획 {r.planCount}
              </div>
              <div className="num" style={{ fontSize: 12, fontWeight: 800, color: 'var(--ink-3)', minWidth: 56, textAlign: 'right' }}>
                세션 {r.sessionCount}
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
}

interface FeedbackRow {
  id: string;
  user_email: string | null;
  category: string;
  content: string;
  status: string;
  created_at: string;
  admin_note: string | null;
}

function FeedbackTab() {
  const [rows, setRows] = useState<FeedbackRow[]>([]);
  const [err, setErr] = useState<string | null>(null);
  const [filter, setFilter] = useState<'all' | 'open' | 'closed'>('open');
  const { showToast } = useApp();

  async function load() {
    const sb = getSupabase();
    if (!sb) { setErr('Supabase 미구성'); return; }
    let q = sb.from('feedback').select('*').order('created_at', { ascending: false }).limit(200);
    if (filter !== 'all') q = q.eq('status', filter);
    const { data, error } = await q;
    if (error) { setErr(error.message); return; }
    setRows((data ?? []) as FeedbackRow[]);
  }
  useEffect(() => { void load(); /* eslint-disable-next-line react-hooks/exhaustive-deps */ }, [filter]);

  async function toggle(r: FeedbackRow) {
    const sb = getSupabase();
    if (!sb) return;
    const next = r.status === 'open' ? 'closed' : 'open';
    const { error } = await sb.from('feedback').update({
      status: next,
      closed_at: next === 'closed' ? new Date().toISOString() : null,
    }).eq('id', r.id);
    if (error) { showToast(error.message); return; }
    showToast(next === 'closed' ? '처리 완료로 표시' : '다시 열림');
    void load();
  }

  if (err) return <div className="card" style={{ padding: 16, color: 'var(--bad)' }}>로드 실패: {err}</div>;
  return (
    <div className="col gap8">
      <div className="chip-wrap">
        {(['open', 'closed', 'all'] as const).map((k) => (
          <button
            key={k}
            type="button"
            className={'filter-chip' + (filter === k ? ' on' : '')}
            onClick={() => setFilter(k)}
          >
            {k === 'open' ? '미처리' : k === 'closed' ? '완료' : '전체'}
          </button>
        ))}
      </div>
      <div className="muted" style={{ fontSize: 11.5, fontWeight: 700, marginLeft: 2 }}>
        {rows.length}건
      </div>
      {rows.length === 0 ? (
        <div className="card" style={{ padding: 24, textAlign: 'center' }}>
          <div className="muted" style={{ fontSize: 13 }}>건의 없음</div>
        </div>
      ) : (
        rows.map((r) => (
          <div key={r.id} className="card" style={{ padding: 14 }}>
            <div className="row between" style={{ marginBottom: 6, alignItems: 'flex-start' }}>
              <div className="row gap6" style={{ alignItems: 'center', flexWrap: 'wrap' }}>
                <span className="type-chip">{r.category}</span>
                <span
                  style={{
                    fontSize: 10.5,
                    fontWeight: 800,
                    padding: '2px 7px',
                    borderRadius: 999,
                    background: r.status === 'open' ? 'rgba(255,178,0,.15)' : 'var(--surface-2)',
                    color: r.status === 'open' ? '#B47800' : 'var(--ink-3)',
                  }}
                >
                  {r.status === 'open' ? '미처리' : '완료'}
                </span>
                <span className="muted" style={{ fontSize: 11, fontWeight: 600 }}>
                  {r.created_at.slice(0, 16).replace('T', ' ')}
                </span>
              </div>
              <button
                type="button"
                onClick={() => void toggle(r)}
                style={{
                  padding: '4px 10px',
                  fontSize: 11.5,
                  fontWeight: 700,
                  borderRadius: 6,
                  background: 'var(--surface-2)',
                  color: 'var(--ink-2)',
                  border: 'none',
                  cursor: 'pointer',
                }}
              >
                {r.status === 'open' ? '완료 처리' : '다시 열기'}
              </button>
            </div>
            <div style={{ fontSize: 13.5, lineHeight: 1.55, whiteSpace: 'pre-wrap' }}>{r.content}</div>
            {r.user_email && (
              <div className="muted" style={{ fontSize: 11, fontWeight: 600, marginTop: 6 }}>
                {r.user_email}
              </div>
            )}
          </div>
        ))
      )}
    </div>
  );
}

export function AdminScreen({ onClose }: { onClose: () => void }) {
  const [tab, setTab] = useState<AdminTab>('dash');
  return (
    <div className="screen push-enter" style={{ background: 'var(--bg)' }}>
      <div className="navbar flush">
        <button className="backbtn" onClick={onClose} type="button">
          <Icon name="back" size={22} />
        </button>
        <div className="grow" style={{ fontWeight: 800, fontSize: 16, textAlign: 'center' }}>
          관리자 콘솔
        </div>
        <div style={{ width: 40 }} />
      </div>
      <div style={{ padding: '8px 20px 4px' }}>
        <div className="segment">
          <div
            className="thumb"
            style={{
              width: 'calc(33.33% - 2px)',
              transform: `translateX(${tab === 'dash' ? '0' : tab === 'users' ? 'calc(100% + 2px)' : 'calc(200% + 4px)'})`,
            }}
          />
          <button className={tab === 'dash' ? 'on' : ''} onClick={() => setTab('dash')} type="button">대시보드</button>
          <button className={tab === 'users' ? 'on' : ''} onClick={() => setTab('users')} type="button">사용자</button>
          <button className={tab === 'feedback' ? 'on' : ''} onClick={() => setTab('feedback')} type="button">건의</button>
        </div>
      </div>
      <div className="scroll pad" style={{ paddingTop: 8 }}>
        {tab === 'dash' && <DashboardTab />}
        {tab === 'users' && <UsersTab />}
        {tab === 'feedback' && <FeedbackTab />}
        <div style={{ height: 24 }} />
      </div>
    </div>
  );
}

