function fmtNoteDate(ts: number): string {
  const d = new Date(ts);
  const now = new Date();
  const y = d.getFullYear() === now.getFullYear() ? '' : `${d.getFullYear()}. `;
  return `${y}${d.getMonth() + 1}월 ${d.getDate()}일`;
}

function evalCounts(checks: Record<string, string> | undefined) {
  const vals = Object.values(checks ?? {});
  return {
    total: vals.length,
    good: vals.filter((v) => v === 'good').length,
    soso: vals.filter((v) => v === 'soso').length,
    bad: vals.filter((v) => v === 'bad').length,
  };
}

