// 학교 종류별 뱃지
type SchoolKind = '유치원' | '초등학교' | '중학교' | '고등학교' | '대학교' | '학원' | '기타';
const SCHOOL_BADGE: Record<SchoolKind, { bg: string; label: string }> = {
  유치원: { bg: '#E6186C', label: '유' },
  초등학교: { bg: '#3182F6', label: '초' },
  중학교: { bg: '#00A84D', label: '중' },
  고등학교: { bg: '#EF7C1C', label: '고' },
  대학교: { bg: '#996CAC', label: '대' },
  학원: { bg: '#6B7684', label: '학원' },
  기타: { bg: '#888', label: '기' },
};
const SCHOOL_ORDER: SchoolKind[] = ['유치원', '초등학교', '중학교', '고등학교', '대학교', '학원', '기타'];

function classifySchool(category: string, name: string): SchoolKind {
  const c = category || '';
  if (/어린이집|유치원/.test(c) || /어린이집|유치원/.test(name)) return '유치원';
  if (/초등학교/.test(c) || /초등학교|초$/.test(name)) return '초등학교';
  if (/중학교/.test(c) || /중학교/.test(name)) return '중학교';
  if (/고등학교/.test(c) || /고등학교/.test(name)) return '고등학교';
  if (/대학교|대학원/.test(c) || /대학교|대학원/.test(name)) return '대학교';
  if (/학원/.test(c) || /학원$/.test(name)) return '학원';
  return '기타';
}

function getSchoolBadge(category: string, name: string): { bg: string; label: string } {
  return SCHOOL_BADGE[classifySchool(category, name)];
}

function getSubwayBadge(line: string): { bg: string; label: string } {
  if (SUBWAY_LINE[line]) return SUBWAY_LINE[line];
  // 부분 매칭 - "수도권 1호선" → 1호선 등
  for (const [key, val] of Object.entries(SUBWAY_LINE)) {
    if (line.includes(key)) return val;
  }
  // 숫자만 있으면 매칭
  const m = line.match(/(\d+)호선/);
  if (m) {
    const k = `${m[1]}호선`;
    if (SUBWAY_LINE[k]) return SUBWAY_LINE[k];
    return { bg: '#888', label: m[1] };
  }
  return { bg: '#888', label: line.slice(0, 2) };
}
interface NearbyData {
  subways: NearbyPlace[];
  buses: NearbyPlace[];
  schools: NearbyPlace[];
}

async function fetchNearby(lat: number, lng: number): Promise<NearbyData> {
  const k = await loadKakaoMaps();
  const services = k?.services;
  if (!k || !services) return { subways: [], buses: [], schools: [] };
  const kakao = k;
  const places = new services.Places();
  type PlacesAny = {
    categorySearch: (code: string, cb: (data: PlaceDoc[], st: string) => void, opt: SearchOpt) => void;
    keywordSearch: (q: string, cb: (data: PlaceDoc[], st: string) => void, opt: SearchOpt) => void;
  };
  type PlaceDoc = Record<string, unknown>;
  type SearchOpt = { location: unknown; radius: number; sort: string };
  function search(opts: { category?: string; keyword?: string; radius: number; limit: number }): Promise<NearbyPlace[]> {
    return new Promise((resolve) => {
      const cb = (data: PlaceDoc[], st: string) => {
        if (st !== 'OK' || !data) return resolve([]);
        resolve(
          data.slice(0, opts.limit).map((d) => ({
            id: String(d.id),
            name: String(d.place_name ?? ''),
            distance: Number(d.distance ?? 0),
            category: String(d.category_name ?? ''),
            road: String(d.road_address_name ?? d.address_name ?? ''),
          })),
        );
      };
      const loc = new kakao.LatLng(lat, lng);
      const opt: SearchOpt = { location: loc, radius: opts.radius, sort: 'distance' };
      const p = places as unknown as PlacesAny;
      if (opts.category) p.categorySearch(opts.category, cb, opt);
      else if (opts.keyword) p.keywordSearch(opts.keyword, cb, opt);
      else resolve([]);
    });
  }
  // 학교: schools 마스터 테이블 (교육부 표준데이터) — RPC nearby_schools (RLS service-only)
  async function fetchSchoolsFromDb(radiusM: number): Promise<NearbyPlace[]> {
    try {
      const sb = (await import('@/lib/supabase')).getSupabase();
      if (!sb) return [];
      const { data } = await sb.rpc('nearby_schools', { p_lat: lat, p_lng: lng, radius_m: radiusM });
      if (!data) return [];
      return (data as Array<{ id: string; name: string; kind: string; distance_m: number }>).map((s) => ({
        id: s.id,
        name: s.name,
        distance: s.distance_m,
        category: `교육,학문 > 학교 > ${s.kind}`,
      }));
    } catch { return []; }
  }
  // 지하철역: subway_stations 마스터 테이블 — RPC nearby_subway_stations (RLS service-only)
  async function fetchSubwaysFromDb(radiusM: number): Promise<NearbyPlace[]> {
    try {
      const sb = (await import('@/lib/supabase')).getSupabase();
      if (!sb) return [];
      const { data } = await sb.rpc('nearby_subway_stations', { p_lat: lat, p_lng: lng, radius_m: radiusM });
      if (!data) return [];
      return (data as Array<{ id: string; name: string; line: string; distance_m: number }>).map((s) => ({
        id: s.id,
        name: s.name,
        distance: s.distance_m,
        category: `교통,수송 > 지하철역 > ${s.line}`,
      }));
    } catch { return []; }
  }
  // 버스정류장: 국토교통부 데이터(bus_stops 테이블) 사용 — 카카오 Places보다 훨씬 풍부
  async function fetchBusesFromTago(): Promise<NearbyPlace[]> {
    try {
      const sb = (await import('@/lib/supabase')).getSupabase();
      if (!sb) return [];
      const { data, error } = await sb.functions.invoke('tago-buses', {
        body: { lat, lng, radius: 500, limit: 8 },
      });
      if (error || !data?.stops) return [];
      return (data.stops as Array<{ id: string; name: string; distance: number; routeCount?: number }>).map((s) => ({
        id: s.id,
        name: s.name,
        distance: s.distance,
        category: '교통,수송 > 버스 > 정류장',
        routeCount: s.routeCount,
      }));
    } catch {
      return [];
    }
  }
  const [subwaysRaw, busesRaw, schoolsRaw, kindergartens, academies] = await Promise.all([
    fetchSubwaysFromDb(2000),
    fetchBusesFromTago(),
    fetchSchoolsFromDb(5000),  // 학교군 polygon 학교들 거리 sort 위해 5km까지
    search({ category: 'PS3', radius: 1000, limit: 15 }), // 어린이집·유치원
    search({ category: 'AC5', radius: 800, limit: 15 }),  // 학원
  ]);
  // 지하철: 노선별 가장 가까운 1개씩
  const lineMap = new Map<string, NearbyPlace>();
  for (const s of subwaysRaw.sort((a, b) => a.distance - b.distance)) {
    const tail = (s.category || '').split('>').map((t) => t.trim()).filter(Boolean);
    const line = tail[tail.length - 1] || s.name;
    if (!lineMap.has(line)) lineMap.set(line, { ...s, line });
  }
  const subways = Array.from(lineMap.values()).slice(0, 5);
  // 버스: 상위 5개
  const buses = busesRaw.slice(0, 5);
  // 학교/학원/유치원 통합 — 종류별 가까운 순으로 그룹화
  const all = [...kindergartens, ...schoolsRaw, ...academies];
  const groupMap = new Map<SchoolKind, NearbyPlace[]>();
  for (const p of all) {
    const k = classifySchool(p.category ?? '', p.name);
    if (k === '기타') continue;
    if (!groupMap.has(k)) groupMap.set(k, []);
    groupMap.get(k)!.push(p);
  }
  // 종류별 가까운 순 + 종류 순서대로 평탄화 (각 종류 상위 3개씩)
  const schools: NearbyPlace[] = [];
  for (const kind of SCHOOL_ORDER) {
    // 학교군 안 학교까지 거리 sort 대상에 포함하려고 50개까지 (배정학교 섹션이 매칭에 사용)
    const limit = (kind === '초등학교' || kind === '중학교' || kind === '고등학교') ? 50 : 3;
    const list = (groupMap.get(kind) ?? []).sort((a, b) => a.distance - b.distance).slice(0, limit);
    schools.push(...list);
  }
  return { subways, buses, schools };
}

// 최근 12개월 슬롯을 만들고 trend 데이터로 채운다 (없는 달은 null).
function buildTrendSlots(trend: AreaTrendPoint[] | undefined): Array<{ ym: string; avg: number | null; max: number | null; cnt: number }> {
  const now = new Date();
  const slots: Array<{ ym: string; avg: number | null; max: number | null; cnt: number }> = [];
  const map = new Map((trend ?? []).map((t) => [t.ym, t]));
  for (let i = 11; i >= 0; i--) {
    const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
    const ym = `${d.getFullYear()}${String(d.getMonth() + 1).padStart(2, '0')}`;
    const hit = map.get(ym);
    slots.push({
      ym,
      avg: hit ? hit.avg : null,
      max: hit ? hit.max : null,
      cnt: hit ? hit.cnt : 0,
    });
  }
  return slots;
}

function TrendChart({ area }: { area: Area }) {
  const slots = useMemo(() => buildTrendSlots(area.trend), [area.trend]);
  const valid = slots.filter((s) => s.avg != null) as Array<{
    ym: string;
    avg: number;
    max: number;
    cnt: number;
  }>;
  if (valid.length < 2) {
    return (
      <div
        className="muted"
        style={{ fontSize: 12.5, fontWeight: 600, padding: '14px 0', textAlign: 'center' }}
      >
        최근 3년 신고된 거래가 없어요
      </div>
    );
  }
  const W = 300;
  const H = 120;
  const padL = 4;
  const padR = 4;
  const padT = 10;
  const padB = 18;
  const avgs = valid.map((p) => p.avg);
  const maxs = valid.map((p) => p.max);
  const lo = Math.min(...avgs);
  const hi = Math.max(...maxs);
  const rng = hi - lo || 1;
  const x = (i: number) => padL + (i / (valid.length - 1)) * (W - padL - padR);
  const y = (v: number) => padT + (1 - (v - lo) / rng) * (H - padT - padB);
  const line = (arr: number[]) =>
    arr.map((v, i) => (i ? 'L' : 'M') + x(i).toFixed(1) + ' ' + y(v).toFixed(1)).join(' ');
  const areaPath =
    line(avgs) + ` L${x(valid.length - 1)} ${H - padB} L${x(0)} ${H - padB} Z`;
  const up = avgs[avgs.length - 1] >= avgs[0];
  const ticks = [0, Math.floor((valid.length - 1) / 2), valid.length - 1];
  return (
    <div>
      <svg
        className="trend-svg"
        viewBox={`0 0 ${W} ${H}`}
        preserveAspectRatio="none"
      >
        <defs>
          <linearGradient id="tg" x1={0} y1={0} x2={0} y2={1}>
            <stop offset="0%" stopColor="var(--accent)" stopOpacity={0.16} />
            <stop offset="100%" stopColor="var(--accent)" stopOpacity={0} />
          </linearGradient>
        </defs>
        <path d={areaPath} fill="url(#tg)" />
        <path
          d={line(maxs)}
          fill="none"
          stroke="var(--line-strong)"
          strokeWidth={1.6}
          strokeDasharray="3 3"
          strokeLinecap="round"
        />
        <path
          d={line(avgs)}
          fill="none"
          stroke="var(--accent)"
          strokeWidth={2.4}
          strokeLinecap="round"
          strokeLinejoin="round"
        />
        <circle
          cx={x(valid.length - 1)}
          cy={y(avgs[avgs.length - 1])}
          r={3.4}
          fill="var(--accent)"
          stroke="#fff"
          strokeWidth={1.6}
        />
        {ticks.map((i) => (
          <text
            key={`t${i}`}
            className="trend-axis"
            x={x(i)}
            y={H - 5}
            textAnchor={i === 0 ? 'start' : i === valid.length - 1 ? 'end' : 'middle'}
          >
            {valid[i].ym}
          </text>
        ))}
      </svg>
      <div className="trend-legend">
        <span className="lg">
          <span className="trend-dot" style={{ background: 'var(--accent)' }} />
          평균가
        </span>
        <span className="lg">
          <span className="trend-dot" style={{ background: 'var(--line-strong)' }} />
          최고가
        </span>
        <span
          className="lg"
          style={{ marginLeft: 'auto', color: up ? 'var(--good)' : 'var(--bad)' }}
        >
          <Icon name="trend" size={13} />
          {`${up ? '+' : ''}${(((avgs[avgs.length - 1] - avgs[0]) / avgs[0]) * 100).toFixed(1)}% (12개월)`}
        </span>
      </div>
    </div>
  );
}


function MonthList({ area }: { area: Area }) {
  const slots = useMemo(() => buildTrendSlots(area.trend), [area.trend]);
  const valid = slots.filter((s) => s.avg != null).reverse() as Array<{ ym: string; avg: number; max: number; cnt: number }>;
  if (valid.length === 0) return null;
  return (
    <div style={{ marginTop: 10, display: 'flex', flexDirection: 'column', gap: 4 }}>
      {valid.map((v) => (
        <div
          key={v.ym}
          className="row between"
          style={{ padding: '6px 0', borderTop: '1px solid var(--line)' }}
        >
          <span className="num" style={{ fontSize: 12.5, fontWeight: 700, color: 'var(--ink-2)' }}>
            {`${v.ym.slice(2, 4)}.${v.ym.slice(4)}`}
          </span>
          <span className="num" style={{ fontSize: 12.5, fontWeight: 700, color: 'var(--ink-3)' }}>
            {`${v.cnt}건`}
          </span>
          <span className="num" style={{ fontSize: 13, fontWeight: 800 }}>
            {wonText(v.avg)}
          </span>
          <span className="num" style={{ fontSize: 11.5, fontWeight: 700, color: 'var(--ink-3)' }}>
            {`최고 ${wonShort(v.max)}`}
          </span>
        </div>
      ))}
    </div>
  );
}

