import { Icon } from './Icon';

export type TabId = 'home' | 'record' | 'friends' | 'settings';

interface TabBarProps {
  tab: TabId;
  setTab: (t: TabId) => void;
}

const TABS: { id: TabId; label: string; icon: string }[] = [
  { id: 'home', label: '시세', icon: 'won' },
  { id: 'record', label: '임장', icon: 'clipboard' },
  { id: 'friends', label: '친구', icon: 'people' },
  { id: 'settings', label: '설정', icon: 'sliders' },
];

export function TabBar({ tab, setTab }: TabBarProps) {
  return (
    <div className="tabbar">
      {TABS.map((t) => (
        <button
          key={t.id}
          className={tab === t.id ? 'on' : ''}
          onClick={() => setTab(t.id)}
          type="button"
        >
          <Icon name={t.icon} size={25} fill={false} stroke={tab === t.id ? 2.2 : 1.9} />
          {t.label}
        </button>
      ))}
    </div>
  );
}
