/**
 * 단지 표시명 정제.
 * - alias_name 있으면 우선 (카카오 통용명)
 * - 없으면 K-APT name에서 노이즈 suffix 제거
 */
export function displayName(complex: { name?: string | null; alias_name?: string | null }): string {
  if (complex.alias_name) return complex.alias_name;
  const n = complex.name ?? '';
  return n
    .replace(/\s*입주자대표회의$/, '')
    .replace(/\s*관리사무소$/, '')
    .replace(/\s*\(주\)$/, '')
    .replace(/\s*주식회사/g, '')
    .trim() || n;
}
