  const retryLocation: AppStore['retryLocation'] = useCallback(async () => {
    try {
      const perm = await requestLocationPermission();
      const granted =
        (perm as { location: string }).location === 'granted';
      if (!granted) {
        showToast('위치 권한이 거부됐어요. 브라우저 설정에서 허용해 주세요.');
        return;
      }
      const pos = await getCurrentPosition();
      await handlePositionRef.current?.(pos, true);
      showToast('현재 위치를 받았어요');
    } catch (e: unknown) {
      showToast((e as Error).message ?? '위치를 받지 못했어요');
    }
  }, [showToast]);

  const plansRef = useRef(plans);
  plansRef.current = plans;

  const toggleFavorite = useCallback<AppStore['toggleFavorite']>(
    async (complexId, price) => {
      if (!user?.id) { showToast('로그인하면 즐겨찾기를 쓸 수 있어요'); return; }
      const wasFav = favorites.has(complexId);
      // 낙관적 업데이트
      setFavorites((prev) => {
        const next = new Set(prev);
        if (wasFav) next.delete(complexId); else next.add(complexId);
        return next;
      });
      const res = await persistToggleFavorite(complexId, price);
      if (res === null) {
        // 실패 → 롤백
        setFavorites((prev) => {
          const next = new Set(prev);
          if (wasFav) next.add(complexId); else next.delete(complexId);
          return next;
        });
        showToast('즐겨찾기 처리에 실패했어요');
        return;
      }
      showToast(res ? '즐겨찾기에 추가했어요 · 실거래가 변동 시 알림' : '즐겨찾기에서 뺐어요');
    },
    [user?.id, favorites, showToast],
  );

  const savePlan: AppStore['savePlan'] = useCallback(
    async (plan) => {
      // 북마크 단건 저장도 자체 batch를 가져 다른 계획과 독립 (batchId 없으면 생성)
      const withBatch: ImjangPlan = plan.batchId
        ? plan
        : {
            ...plan,
            batchId:
              typeof crypto !== 'undefined' && 'randomUUID' in crypto
                ? crypto.randomUUID()
                : `b${plan.createdAt}-${plan.complexId}`,
          };
      const next = await persistUpsertPlan(user?.id ?? null, withBatch, plansRef.current);
      plansRef.current = next;
      setPlans(next);
      showToast('임장 계획에 담았어요');
    },
    [user?.id, showToast],
  );

