  const renamePlanBatch: AppStore['renamePlanBatch'] = useCallback(
    async (batchId, title) => {
      const targets = plansRef.current.filter((p) => planBatchId(p) === batchId);
      if (targets.length === 0) return;
      const t = title.trim();
      let acc = plansRef.current;
      for (const p of targets) {
        // 기존 memo에서 [제목] 접두 제거 → 본문(rest)만 남김
        let rest = p.memo;
        if (p.memo.startsWith('[')) {
          const end = p.memo.indexOf(']');
          if (end > 0) rest = p.memo.slice(end + 1).trim();
        }
        const newMemo = t ? (rest ? `[${t}] ${rest}` : `[${t}]`) : rest;
        acc = await persistUpsertPlan(user?.id ?? null, { ...p, memo: newMemo }, acc);
      }
      plansRef.current = acc;
      setPlans(acc);
      showToast('계획 제목을 변경했어요');
    },
    [user?.id, showToast],
  );

