import { useState } from 'react';
import { Icon } from './Icon';

const DOW = ['일', '월', '화', '수', '목', '금', '토'];

function pad(n: number): string {
  return n < 10 ? `0${n}` : String(n);
}
function ymd(y: number, m: number, d: number): string {
  return `${y}-${pad(m + 1)}-${pad(d)}`;
}

interface Props {
  value: string;
  onChange: (v: string) => void;
}

export function MonthCalendar({ value, onChange }: Props) {
  const today = new Date();
  const init = value ? new Date(value + 'T00:00:00') : today;
  const [vy, setVy] = useState(init.getFullYear());
  const [vm, setVm] = useState(init.getMonth());

  const first = new Date(vy, vm, 1);
  const startDow = first.getDay();
  const daysInMonth = new Date(vy, vm + 1, 0).getDate();
  const todayStr = ymd(today.getFullYear(), today.getMonth(), today.getDate());

  const cells: Array<number | null> = [];
  for (let i = 0; i < startDow; i++) cells.push(null);
  for (let d = 1; d <= daysInMonth; d++) cells.push(d);

  const shift = (delta: number) => {
    let m = vm + delta;
    let y = vy;
    if (m < 0) {
      m = 11;
      y--;
    }
    if (m > 11) {
      m = 0;
      y++;
    }
    setVm(m);
    setVy(y);
  };

  return (
    <div>
      <div className="cal-head">
        <button type="button" className="cal-nav" onClick={() => shift(-1)}>
          <Icon name="chevL" size={18} />
        </button>
        <div className="cal-title num">{`${vy}년 ${vm + 1}월`}</div>
        <button type="button" className="cal-nav" onClick={() => shift(1)}>
          <Icon name="chevR" size={18} />
        </button>
      </div>
      <div className="cal-grid cal-dow">
        {DOW.map((d, i) => (
          <div
            key={d}
            className="cal-dowcell"
            style={{
              color:
                i === 0 ? 'var(--bad)' : i === 6 ? 'var(--accent)' : 'var(--ink-3)',
            }}
          >
            {d}
          </div>
        ))}
      </div>
      <div className="cal-grid">
        {cells.map((d, i) => {
          if (d == null) return <div key={`e${i}`} />;
          const ds = ymd(vy, vm, d);
          const sel = value === ds;
          const isToday = ds === todayStr;
          const dow = (startDow + d - 1) % 7;
          return (
            <button
              key={d}
              type="button"
              className={'cal-day' + (sel ? ' sel' : '') + (isToday && !sel ? ' today' : '')}
              style={{
                color: sel
                  ? '#fff'
                  : dow === 0
                    ? 'var(--bad)'
                    : dow === 6
                      ? 'var(--accent)'
                      : 'var(--ink)',
              }}
              onClick={() => onChange(sel ? '' : ds)}
            >
              {d}
            </button>
          );
        })}
      </div>
    </div>
  );
}
