const PALETTE = ['#3182F6', '#22C55E', '#F59E0B', '#EF4444', '#8B5CF6', '#EC4899', '#14B8A6', '#F97316'];
/** id 해시 → 고정 색상 (아바타용) */
export function colorFromId(id: string): string {
  let h = 0;
  for (let i = 0; i < id.length; i++) h = (h * 31 + id.charCodeAt(i)) >>> 0;
  return PALETTE[h % PALETTE.length];
}

/** 현재 로그인 세션의 user id 반환 (익명/없음이면 null). 협업은 로그인 필수 — 익명 세션 만들지 않음. */
export async function ensureSession(): Promise<string | null> {
  const sb = getSupabase();
  if (!sb) return null;
  const { data } = await sb.auth.getSession();
  const u = data.session?.user as { id: string; is_anonymous?: boolean } | undefined;
  if (!u || u.is_anonymous) return null;
  return u.id;
}

/** 내 profiles 행 upsert (이름/아바타). 익명이면 '게스트'. */
export async function upsertMyProfile(p: {
  id: string;
  displayName?: string | null;
  avatarUrl?: string | null;
}): Promise<void> {
  const sb = getSupabase();
  if (!sb) return;
  await sb.from('profiles').upsert(
    {
      id: p.id,
      display_name: p.displayName || '게스트',
      avatar_url: p.avatarUrl ?? null,
      updated_at: new Date().toISOString(),
    },
    { onConflict: 'id' },
  );
}

function randomToken(): string {
  if (typeof crypto !== 'undefined' && 'randomUUID' in crypto) return crypto.randomUUID().replace(/-/g, '');
  return Math.random().toString(36).slice(2) + Date.now().toString(36);
}

/** 초대 링크 생성. 반환: 공유용 URL */
export async function createInvite(kind: 'friend' | 'plan', batchId?: string): Promise<string | null> {
  const sb = getSupabase();
  if (!sb) return null;
  const me = await ensureSession();
  if (!me) return null;
  const token = randomToken();
  const { error } = await sb.from('invites').insert({
    token,
    kind,
    inviter_id: me,
    batch_id: batchId ?? null,
  });
  if (error) {
    console.warn('[collab] 초대 생성 실패:', error.message);
    return null;
  }
  const origin = typeof window !== 'undefined' ? window.location.origin : '';
  return `${origin}/?invite=${token}`;
}

/** 친구를 계획 멤버로 직접 초대 (소유자만, 친구 관계 검증은 서버 RPC) */
