export type AcceptResult =
  | { kind: string; batchId: string | null }
  | { error: 'login_required' }
  | null;

/** 초대 수락. 친구 초대를 게스트가 수락 시 {error:'login_required'} 반환. */
export async function acceptInvite(token: string): Promise<AcceptResult> {
  const sb = getSupabase();
  if (!sb) return null;
  // 로그인 필수 — 비로그인/익명이면 로그인 유도
  if (!(await ensureSession())) return { error: 'login_required' };
  const { data, error } = await sb.rpc('accept_invite', { p_token: token });
  if (error) {
    if (/login_required/.test(error.message)) return { error: 'login_required' };
    console.warn('[collab] 초대 수락 실패:', error.message);
    return null;
  }
  const row = Array.isArray(data) ? data[0] : data;
  if (!row) return null;
  return { kind: row.out_kind, batchId: row.out_batch_id ?? null };
}

/** id 목록 → {id: display_name} (profiles와 직접 FK 없으므로 2단계 조회) */
export async function loadProfiles(ids: string[]): Promise<Map<string, string>> {
  const out = new Map<string, string>();
  const sb = getSupabase();
  const uniq = [...new Set(ids)].filter(Boolean);
  if (!sb || uniq.length === 0) return out;
  const { data } = await sb.from('profiles').select('id, display_name').in('id', uniq);
  for (const r of (data ?? []) as { id: string; display_name?: string | null }[]) {
    out.set(r.id, r.display_name || '게스트');
  }
  return out;
}

/** 이름 없음/기본'게스트' → 구분 위해 '게스트 <id8>' 로 표시 */
function displayName(id: string, names: Map<string, string>): string {
  const nm = names.get(id);
  return nm && nm !== '게스트' ? nm : `게스트 ${id.slice(0, 8)}`;
}
function toMember(id: string, names: Map<string, string>): Member {
  return { id, name: displayName(id, names), color: colorFromId(id) };
}

/** 내 친구 목록 (내가 지정한 별명 우선) */
export async function loadFriends(): Promise<Friend[]> {
  const sb = getSupabase();
  if (!sb) return [];
  const { data, error } = await sb.from('friendships').select('friend_id, alias');
  if (error || !data) {
    if (error) console.warn('[collab] 친구 로드 실패:', error.message);
    return [];
  }
  const rows = data as { friend_id: string; alias: string | null }[];
  const names = await loadProfiles(rows.map((r) => r.friend_id));
  return rows.map((r) => {
    const baseName = displayName(r.friend_id, names);
    const alias = r.alias?.trim() || null;
    return { id: r.friend_id, name: alias || baseName, color: colorFromId(r.friend_id), alias, baseName };
  });
}

