/** 계획(batch) 멤버 목록 (status='pending'이면 pending=true → '초대중') */
export async function loadPlanMembers(batchId: string): Promise<Member[]> {
  const sb = getSupabase();
  if (!sb) return [];
  const { data, error } = await sb.from('plan_members').select('member_id, status').eq('batch_id', batchId);
  if (error || !data) {
    if (error) console.warn('[collab] 멤버 로드 실패:', error.message);
    return [];
  }
  const rows = data as { member_id: string; status: string }[];
  const names = await loadProfiles(rows.map((r) => r.member_id));
  return rows.map((r) => ({ ...toMember(r.member_id, names), pending: r.status === 'pending' }));
}

export interface PendingInvite {
  batchId: string;
  title: string;
  inviterId: string;
  inviterName: string;
}

/** 내가 받은(수락 대기) 계획 초대 목록 — 알림용 */
export async function loadPendingInvites(): Promise<PendingInvite[]> {
  const sb = getSupabase();
  if (!sb) return [];
  const me = await ensureSession();
  if (!me) return [];
  const { data, error } = await sb
    .from('plan_members')
    .select('batch_id, owner_id')
    .eq('member_id', me)
    .eq('status', 'pending');
  if (error || !data || data.length === 0) return [];
  const rows = data as { batch_id: string; owner_id: string }[];
  // 계획 제목(memo의 [제목]) + 초대자 이름
  const names = await loadProfiles(rows.map((r) => r.owner_id));
  const { data: plans } = await sb
    .from('imjang_plans')
    .select('batch_id, memo, complex_name')
    .in('batch_id', rows.map((r) => r.batch_id));
  const titleOf = (batchId: string) => {
    const p = (plans ?? []).find((x: { batch_id: string }) => x.batch_id === batchId) as
      | { memo?: string; complex_name?: string }
      | undefined;
    const m = p?.memo ?? '';
    if (m.startsWith('[')) {
      const end = m.indexOf(']');
      if (end > 0) return m.slice(1, end);
    }
    return p?.complex_name || '임장 계획';
  };
  return rows.map((r) => ({
    batchId: r.batch_id,
    title: titleOf(r.batch_id),
    inviterId: r.owner_id,
    inviterName: displayName(r.owner_id, names),
  }));
}

