// 같은 batch를 동시에 구독하는 화면이 둘 이상(상세 미리보기 + 채팅)일 때 채널 토픽 충돌 방지
let pcChannelSeq = 0;

/** 메모 실시간 구독 (INSERT). 반환: 구독 해제 함수 */
export function subscribePlanComments(
  batchId: string,
  onInsert: (row: { id: string; author_id: string; text: string; created_at: string }) => void,
): () => void {
  const sb = getSupabase();
  if (!sb) return () => {};
  const topic = `pc:${batchId}:${++pcChannelSeq}`;
  let channel: ReturnType<typeof sb.channel> | null = null;
  let cancelled = false;
  void (async () => {
    // RLS 보호 테이블의 postgres_changes는 realtime 연결에 사용자 JWT가 필요
    const { data } = await sb.auth.getSession();
    const token = data.session?.access_token;
    const rt = sb.realtime as unknown as { setAuth?: (t: string) => void };
    if (token && typeof rt.setAuth === 'function') rt.setAuth(token);
    if (cancelled) return;
    channel = sb
      .channel(topic)
      .on(
        'postgres_changes',
        { event: 'INSERT', schema: 'public', table: 'plan_comments', filter: `batch_id=eq.${batchId}` },
        (payload: { new: { id: string; author_id: string; text: string; created_at: string } }) => {
          onInsert(payload.new);
        },
      )
      .subscribe();
  })();
  return () => {
    cancelled = true;
    if (channel) void sb.removeChannel(channel);
  };
}

/** 여러 batch의 최근 메모를 한 번에 로드 (알림/NEW 뱃지용). 본인 작성은 제외. */
export async function loadCommentsForBatches(
  batchIds: string[],
  excludeAuthorId: string,
): Promise<PlanComment[]> {
  const sb = getSupabase();
  if (!sb || batchIds.length === 0) return [];
  const { data, error } = await sb
    .from('plan_comments')
    .select('id, batch_id, author_id, text, created_at')
    .in('batch_id', batchIds)
    .neq('author_id', excludeAuthorId)
    .order('created_at', { ascending: false })
    .limit(100);
  if (error || !data) {
    if (error) console.warn('[collab] 메모 일괄 로드 실패:', error.message);
    return [];
  }
  const rows = data as CommentRow[];
  const names = await loadProfiles(rows.map((r) => r.author_id));
  return rows.map((r) => ({
    id: r.id,
    batchId: r.batch_id,
    authorId: r.author_id,
    authorName: displayName(r.author_id, names),
    text: r.text,
    createdAt: new Date(r.created_at).getTime(),
  }));
}

/** 내 모든 계획의 메모 INSERT 전역 구독 (알림용). RLS가 내가 볼 수 있는 batch로 제한. */
export function subscribeAllPlanComments(
  onInsert: (row: CommentRow) => void,
): () => void {
  const sb = getSupabase();
  if (!sb) return () => {};
  let channel: ReturnType<typeof sb.channel> | null = null;
  let cancelled = false;
  void (async () => {
    const { data } = await sb.auth.getSession();
    const token = data.session?.access_token;
    const rt = sb.realtime as unknown as { setAuth?: (t: string) => void };
    if (token && typeof rt.setAuth === 'function') rt.setAuth(token);
    if (cancelled) return;
    channel = sb
      .channel('pc:all')
      .on(
        'postgres_changes',
        { event: 'INSERT', schema: 'public', table: 'plan_comments' },
        (payload: { new: CommentRow }) => {
          onInsert(payload.new);
        },
      )
      .subscribe();
  })();
  return () => {
    cancelled = true;
    if (channel) void sb.removeChannel(channel);
  };
}

/** 한 단지에 대한 멤버별 임장노트 (내 노트 + 같은 계획 멤버의 공유 노트) */
export interface MemberNote {
  userId: string;
  authorName: string;
  rating: number;
  checks: Record<string, EvalState>;
  photos: PhotoRef[];
  oneliner: string;
  shared: boolean;
  createdAt: number;
  isMine: boolean;
}

export async function loadSharedNotesForComplex(
  complexId: string,
  myId: string | null,
): Promise<MemberNote[]> {
  const sb = getSupabase();
  if (!sb) return [];
  const { data, error } = await sb.rpc('load_shared_notes_for_complex', { p_complex_id: complexId });
  if (error || !data) {
    if (error) console.warn('[collab] 멤버 노트 로드 실패:', error.message);
    return [];
  }
  const rows = data as {
    user_id: string; rating: number; checks: Record<string, EvalState> | null;
    photos: PhotoRef[] | null; oneliner: string; shared: boolean; created_at: string;
  }[];
  const names = await loadProfiles(rows.map((r) => r.user_id));
  return rows
    .map((r) => ({
      userId: r.user_id,
      authorName: displayName(r.user_id, names),
      rating: r.rating ?? 0,
      checks: r.checks ?? {},
      photos: r.photos ?? [],
      oneliner: r.oneliner ?? '',
      shared: r.shared,
      createdAt: r.created_at ? new Date(r.created_at).getTime() : Date.now(),
      isMine: !!myId && r.user_id === myId,
    }))
    // 내 노트를 항상 맨 위로, 그다음 최신순
    .sort((a, b) => (a.isMine === b.isMine ? b.createdAt - a.createdAt : a.isMine ? -1 : 1));
}

