/** 공유받은 계획(내가 멤버인 batch) — imjang_plans 행들 */
export async function loadSharedPlans(): Promise<ImjangPlan[]> {
  const sb = getSupabase();
  if (!sb) return [];
  // 수락(joined)한 공유 계획만 — pending(초대중)은 알림에만 표시
  const { data: mem, error: memErr } = await sb.from('plan_members').select('batch_id, status');
  if (memErr || !mem || mem.length === 0) return [];
  const batchIds = [
    ...new Set(
      (mem as { batch_id: string; status: string }[])
        .filter((m) => m.status === 'joined')
        .map((m) => m.batch_id),
    ),
  ];
  if (batchIds.length === 0) return [];
  const { data, error } = await sb
    .from('imjang_plans')
    .select('complex_id, complex_name, complex_type, lat, lng, planned_date, memo, done, created_at, batch_id')
    .in('batch_id', batchIds);
  if (error || !data) {
    if (error) console.warn('[collab] 공유계획 로드 실패:', error.message);
    return [];
  }
  return data.map((r: {
    complex_id: string; complex_name: string; complex_type: ImjangPlan['complexType'];
    lat: number | null; lng: number | null; planned_date: string | null; memo: string;
    done: boolean; created_at: string; batch_id: string | null;
  }) => ({
    complexId: r.complex_id,
    complexName: r.complex_name,
    complexType: r.complex_type,
    lat: r.lat ?? undefined,
    lng: r.lng ?? undefined,
    plannedDate: r.planned_date ?? undefined,
    memo: r.memo,
    done: r.done,
    createdAt: new Date(r.created_at).getTime(),
    batchId: r.batch_id ?? undefined,
    shared: true,
  }));
}
