import { useRef, useState } from 'react';
import { Icon } from './Icon';
import { useApp } from '@/store/AppStore';
import type { ComplexFilter, PropertyType } from '@/types/domain';

const TYPES: PropertyType[] = ['아파트', '오피스텔', '빌라', '다가구'];
const PRICE_MAX = 250000; // 25억
const HH_MAX = 2000;

function priceFmt(v: number): string {
  if (v >= 10000) {
    const e = v / 10000;
    return (e % 1 === 0 ? e.toFixed(0) : e.toFixed(1)) + '억';
  }
  return v === 0 ? '0' : v.toLocaleString() + '만';
}

function hhFmt(v: number): string {
  if (v >= 1000) return (v / 1000).toFixed(v % 1000 === 0 ? 0 : 1) + '천';
  return v === 0 ? '0' : v.toLocaleString();
}

export function FilterBar({ floating = false }: { floating?: boolean }) {
  const { filter, setFilter, filteredComplexes, complexes } = useApp();
  const [sheetOpen, setSheetOpen] = useState(false);

  const selectType = (t: PropertyType) => {
    setFilter({ ...filter, types: [t] });
  };

  const advancedActive =
    filter.priceMin != null ||
    filter.priceMax != null ||
    filter.householdsMin != null ||
    filter.householdsMax != null;

  const hidden = complexes.length - filteredComplexes.length;
  // 단일 선택. types 비어있으면 기본 '아파트'로 동작.
  const selectedType: PropertyType = filter.types[0] ?? '아파트';

  return (
    <>
      <div className="filter-row" style={floating ? { padding: '8px 14px 10px' } : undefined}>
        {TYPES.map((t) => (
          <button
            key={t}
            type="button"
            className={'filter-chip' + (selectedType === t ? ' on' : '')}
            onClick={() => selectType(t)}
          >
            {t}
          </button>
        ))}
        <button
          type="button"
          className={'filter-chip' + (advancedActive ? ' on' : '')}
          onClick={() => setSheetOpen(true)}
        >
          <Icon name="sliders" size={13} />
          상세
        </button>
        {advancedActive && (
          <button
            type="button"
            className="filter-reset"
            onClick={() => setFilter({ types: [selectedType] })}
          >
            초기화
          </button>
        )}
        {hidden > 0 && <span className="filter-hidden num">{`${hidden}곳 숨김`}</span>}
      </div>

      {sheetOpen && (
        <FilterSheet
          filter={filter}
          onApply={(f) => {
            setFilter(f);
            setSheetOpen(false);
          }}
          onClose={() => setSheetOpen(false)}
        />
      )}
    </>
  );
}

interface RangeSliderProps {
  min: number;
  max: number;
  step: number;
  lo: number;
  hi: number;
  onChange: (which: 'lo' | 'hi', v: number) => void;
  fmt: (v: number) => string;
  maxLabel?: string;
}

function RangeSlider({ min, max, step, lo, hi, onChange, fmt, maxLabel }: RangeSliderProps) {
  const trackRef = useRef<HTMLDivElement>(null);
  const span = max - min || 1;
  const pct = (v: number) => ((v - min) / span) * 100;

  const beginDrag = (which: 'lo' | 'hi') => (e: React.PointerEvent | React.TouchEvent) => {
    e.preventDefault();
    e.stopPropagation();
    const track = trackRef.current;
    if (!track) return;
    const move = (ev: PointerEvent | TouchEvent) => {
      const rect = track.getBoundingClientRect();
      const cx =
        'touches' in ev
          ? (ev as TouchEvent).touches[0].clientX
          : (ev as PointerEvent).clientX;
      let r = (cx - rect.left) / rect.width;
      r = Math.max(0, Math.min(1, r));
      let v = Math.round((min + r * span) / step) * step;
      if (which === 'lo') v = Math.min(v, hi - step);
      else v = Math.max(v, lo + step);
      v = Math.max(min, Math.min(max, v));
      onChange(which, v);
    };
    const end = () => {
      window.removeEventListener('pointermove', move as EventListener);
      window.removeEventListener('pointerup', end);
      window.removeEventListener('touchmove', move as EventListener);
      window.removeEventListener('touchend', end);
    };
    window.addEventListener('pointermove', move as EventListener);
    window.addEventListener('pointerup', end);
    window.addEventListener('touchmove', move as EventListener, { passive: false });
    window.addEventListener('touchend', end);
  };

  const atMin = lo <= min;
  const atMax = hi >= max;
  const label =
    atMin && atMax ? '전체' : `${fmt(lo)} ~ ${atMax ? maxLabel ?? fmt(hi) : fmt(hi)}`;

  return (
    <div>
      <div className={'range-val' + (atMin && atMax ? ' all' : '')}>{label}</div>
      <div className="range-wrap">
        <div className="range-track" ref={trackRef}>
          <div
            className="range-fill"
            style={{ left: pct(lo) + '%', right: 100 - pct(hi) + '%' }}
          />
          <div
            className="range-thumb"
            style={{ left: pct(lo) + '%' }}
            onPointerDown={beginDrag('lo')}
            onTouchStart={beginDrag('lo')}
          />
          <div
            className="range-thumb"
            style={{ left: pct(hi) + '%' }}
            onPointerDown={beginDrag('hi')}
            onTouchStart={beginDrag('hi')}
          />
        </div>
        <div className="range-ends">
          <span>{fmt(min)}</span>
          <span>{maxLabel ?? fmt(max)}</span>
        </div>
      </div>
    </div>
  );
}

function FilterSheet({
  filter,
  onApply,
  onClose,
}: {
  filter: ComplexFilter;
  onApply: (f: ComplexFilter) => void;
  onClose: () => void;
}) {
  const [draft, setDraft] = useState<ComplexFilter>(filter);
  const loPrice = draft.priceMin ?? 0;
  const hiPrice = draft.priceMax ?? PRICE_MAX;
  const loHH = draft.householdsMin ?? 0;
  const hiHH = draft.householdsMax ?? HH_MAX;

  const setPrice = (which: 'lo' | 'hi', v: number) => {
    if (import.meta.env.DEV) console.debug('[filter-sheet] setPrice', which, v);
    if (which === 'lo')
      setDraft((d) => ({ ...d, priceMin: v <= 0 ? undefined : v }));
    else setDraft((d) => ({ ...d, priceMax: v >= PRICE_MAX ? undefined : v }));
  };
  const setHH = (which: 'lo' | 'hi', v: number) => {
    if (import.meta.env.DEV) console.debug('[filter-sheet] setHH', which, v);
    if (which === 'lo')
      setDraft((d) => ({ ...d, householdsMin: v <= 0 ? undefined : v }));
    else setDraft((d) => ({ ...d, householdsMax: v >= HH_MAX ? undefined : v }));
  };

  return (
    <div className="sheet-scrim" onClick={onClose} style={{ zIndex: 120 }}>
      <div className="filter-sheet" onClick={(e) => e.stopPropagation()}>
        <div className="sheet-grip" />
        <div className="row between" style={{ marginBottom: 18, padding: '0 2px' }}>
          <div style={{ fontWeight: 800, fontSize: 18, letterSpacing: '-.02em' }}>상세 필터</div>
          <button onClick={onClose} type="button" style={{ color: 'var(--ink-3)', padding: 4 }}>
            <Icon name="x" size={20} />
          </button>
        </div>

        <div className="sect-cap" style={{ marginBottom: 6 }}>가격대 (대표 시세)</div>
        <RangeSlider
          min={0}
          max={PRICE_MAX}
          step={5000}
          lo={loPrice}
          hi={hiPrice}
          onChange={setPrice}
          fmt={priceFmt}
          maxLabel="25억+"
        />

        <div className="sect-cap" style={{ margin: '22px 0 6px' }}>세대수</div>
        <RangeSlider
          min={0}
          max={HH_MAX}
          step={50}
          lo={loHH}
          hi={hiHH}
          onChange={setHH}
          fmt={hhFmt}
          maxLabel="2천+"
        />

        <div className="row gap8" style={{ marginTop: 20 }}>
          <button
            className="btn btn-ghost"
            type="button"
            style={{ flex: 1 }}
            onClick={() => setDraft({ types: draft.types })}
          >
            초기화
          </button>
          <button
            className="btn btn-primary"
            type="button"
            style={{ flex: 1 }}
            onClick={() => {
              if (import.meta.env.DEV) console.debug('[filter-sheet] 적용 클릭', draft);
              onApply(draft);
            }}
          >
            적용
          </button>
        </div>
      </div>
    </div>
  );
}
