import type { UserProfile } from '@/types/domain';
import { getSupabase } from '@/lib/supabase';
import { Capacitor } from '@capacitor/core';
import { Browser } from '@capacitor/browser';
import { App as CapacitorApp } from '@capacitor/app';

const REDIRECT_NATIVE = 'kr.publicad.imjangnote://auth-callback';

let deepLinkAttached = false;
function attachDeepLinkOnce(): void {
  if (deepLinkAttached) return;
  if (!Capacitor.isNativePlatform()) return;
  deepLinkAttached = true;
  CapacitorApp.addListener('appUrlOpen', async (event: { url: string }) => {
    const sb = getSupabase();
    if (!sb) return;
    try {
      const url = event.url;
      if (!url.includes('auth-callback')) return;
      await Browser.close();
      const hash = url.split('#')[1];
      const query = url.split('?')[1]?.split('#')[0];
      // PKCE flow: ?code=... — exchangeCodeForSession은 전체 URL이 아니라 code 값을 받아야 함
      if (query?.includes('code=')) {
        const code = new URLSearchParams(query).get('code');
        if (code) {
          const { error } = await sb.auth.exchangeCodeForSession(code);
          if (error) console.warn('[auth] exchangeCodeForSession 실패', error.message);
        }
        return;
      }
      // Implicit flow: #access_token=...&refresh_token=...
      if (hash?.includes('access_token=')) {
        const params = new URLSearchParams(hash);
        const access_token = params.get('access_token');
        const refresh_token = params.get('refresh_token');
        if (access_token && refresh_token) {
          await sb.auth.setSession({ access_token, refresh_token });
        }
      }
    } catch (e) {
      console.warn('[auth] deep link 처리 실패', e);
    }
  });
}

interface Identity { provider?: string; last_sign_in_at?: string | null }
function toProfile(user: { id: string; email?: string | null; user_metadata?: Record<string, unknown>; app_metadata?: Record<string, unknown>; identities?: Identity[] } | null): UserProfile | null {
  if (!user) return null;
  const meta = (user.user_metadata ?? {}) as Record<string, unknown>;
  const app = (user.app_metadata ?? {}) as Record<string, unknown>;
  // provider 우선순위:
  // 1) user_metadata.provider (naver-callback에서 명시한 커스텀)
  // 2) 가장 최근 로그인한 identity의 provider — 계정이 여러 소셜로 연결(link)된 경우
  //    app_metadata.provider는 '최초' provider라 부정확(예: kakao로 만든 계정에 google 연결 시 여전히 kakao).
  // 3) app_metadata.provider  4) 'email'
  const identities = Array.isArray(user.identities) ? user.identities : [];
  const latestIdentity = identities.length
    ? [...identities].sort(
        (a, b) => new Date(b.last_sign_in_at ?? 0).getTime() - new Date(a.last_sign_in_at ?? 0).getTime(),
      )[0]
    : null;
  const provider =
    (typeof meta.provider === 'string' ? meta.provider : null) ??
    (latestIdentity && typeof latestIdentity.provider === 'string' ? latestIdentity.provider : null) ??
    (typeof app.provider === 'string' ? app.provider : null) ??
    'email';
  return {
    id: user.id,
    email: user.email ?? null,
    displayName:
      (typeof meta.full_name === 'string' ? meta.full_name : null) ??
      (typeof meta.name === 'string' ? meta.name : null) ??
      user.email ??
      null,
    avatarUrl: typeof meta.avatar_url === 'string' ? meta.avatar_url : null,
    provider,
    isAnonymous: (user as { is_anonymous?: boolean }).is_anonymous === true,
  };
}

/** location.hash에 access_token이 있으면 setSession (implicit/magiclink 흐름 호환). 적용된 user를 반환. */
async function consumeHashSessionOnce(): Promise<UserProfile | null> {
  if (typeof window === 'undefined') return null;
  const hash = window.location.hash;
  if (!hash.includes('access_token=')) return null;
  const sb = getSupabase();
  if (!sb) return null;
  try {
    const params = new URLSearchParams(hash.slice(1));
    const access_token = params.get('access_token');
    const refresh_token = params.get('refresh_token');
    if (access_token && refresh_token) {
      const { data } = await sb.auth.setSession({ access_token, refresh_token });
      // hash 제거 (재진입 시 중복 처리 방지)
      window.history.replaceState(null, '', window.location.pathname + window.location.search);
      return toProfile(data.user as never);
    }
  } catch (e) {
    console.warn('[auth] hash session consume 실패', e);
  }
  return null;
}

/** 익명(게스트) 세션은 비로그인으로 취급 — 협업/친구는 로그인 필수라 게스트 개념을 두지 않는다. */
function isAnon(u: { is_anonymous?: boolean } | null | undefined): boolean {
  return !!u && u.is_anonymous === true;
}

export async function getCurrentUser(): Promise<UserProfile | null> {
  const fromHash = await consumeHashSessionOnce();
  if (fromHash) return fromHash;
  const sb = getSupabase();
  if (!sb) return null;
  const { data } = await sb.auth.getUser();
  if (isAnon(data.user as never)) return null;
  return toProfile(data.user as never);
}

export function onAuthChange(cb: (u: UserProfile | null) => void): (() => void) | null {
  const sb = getSupabase();
  if (!sb) return null;
  const { data: sub } = sb.auth.onAuthStateChange((_evt, session) => {
    const u = session?.user;
    cb(isAnon(u as never) ? null : toProfile((u as never) ?? null));
  });
  return () => sub.subscription.unsubscribe();
}

export async function signInWithEmail(email: string, password: string): Promise<void> {
  const sb = getSupabase();
  if (!sb) throw new Error('Supabase 미구성');
  const { error } = await sb.auth.signInWithPassword({ email, password });
  if (error) throw error;
}

export async function signUpWithEmail(email: string, password: string): Promise<void> {
  const sb = getSupabase();
  if (!sb) throw new Error('Supabase 미구성');
  const { error } = await sb.auth.signUp({ email, password });
  if (error) throw error;
}

export type OAuthProvider = 'google' | 'apple' | 'kakao' | 'naver';

const NAVER_CLIENT_ID = 'hqfk61HqxYEbCLCkAHcc';
const NAVER_CALLBACK = 'https://ofvkbhzmnbxugtillslb.supabase.co/functions/v1/naver-callback';

function startNaverOAuth(): void {
  // state = <random>.<base64-redirect> 형식으로 콜백에 redirect 정보 전달
  const isNative = Capacitor.isNativePlatform();
  const redirect = isNative ? REDIRECT_NATIVE : `${location.origin}`;
  const rand = crypto.randomUUID();
  const enc = btoa(redirect).replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
  const state = `${rand}.${enc}`;
  const url = `https://nid.naver.com/oauth2.0/authorize?response_type=code` +
    `&client_id=${encodeURIComponent(NAVER_CLIENT_ID)}` +
    `&redirect_uri=${encodeURIComponent(NAVER_CALLBACK)}` +
    `&state=${encodeURIComponent(state)}`;
  if (isNative) {
    // 네이티브: SafariViewController로 열고 magic link 콜백은 deep link로 받음
    attachDeepLinkOnce();
    void Browser.open({ url, presentationStyle: 'popover' });
  } else {
    location.href = url;
  }
}

/** 익명 세션을 영구 계정으로 업그레이드 (linkIdentity). 시작했으면 true, 폴백 필요 시 false. */
async function linkAnonymousIdentity(provider: OAuthProvider): Promise<boolean> {
  const sb = getSupabase();
  if (!sb) return false;
  const linker = sb.auth as unknown as {
    linkIdentity?: (o: { provider: string; options?: Record<string, unknown> }) => Promise<{
      data: { url?: string } | null;
      error: { message: string } | null;
    }>;
  };
  if (typeof linker.linkIdentity !== 'function') return false;
  const isNative = Capacitor.isNativePlatform();
  if (isNative) {
    attachDeepLinkOnce();
    const { data, error } = await linker.linkIdentity({
      provider,
      options: { redirectTo: REDIRECT_NATIVE, skipBrowserRedirect: true },
    });
    if (error) {
      console.warn('[auth] linkIdentity(native) 실패', error.message);
      return false;
    }
    if (data?.url) {
      await Browser.open({ url: data.url, presentationStyle: 'popover' });
      return true;
    }
    return false;
  }
  // 웹: linkIdentity가 location 리다이렉트 처리
  const { error } = await linker.linkIdentity({ provider, options: { redirectTo: `${location.origin}` } });
  if (error) {
    console.warn('[auth] linkIdentity(web) 실패', error.message);
    return false;
  }
  return true;
}

export async function signInWithOAuth(provider: OAuthProvider): Promise<void> {
  const sb = getSupabase();
  if (!sb) throw new Error('Supabase 미구성');
  // OAuth로 외부 도메인 이동 직전, 현재 tab을 다시 한 번 명시 저장 (race 방지)
  try {
    const cur = window.sessionStorage.getItem('imjang.tab');
    if (cur) window.sessionStorage.setItem('imjang.tab', cur);
    window.sessionStorage.setItem('imjang.splashDone', '1');
  } catch { /* ignore */ }
  // Naver는 Supabase 표준 provider가 아님 — Edge Function 경유 custom 흐름
  if (provider === 'naver') {
    startNaverOAuth();
    return;
  }
  // 현재 세션이 익명(임시계정)이면 linkIdentity로 동일 user id를 유지한 채 영구 전환.
  // → 익명 동안 받은 친구/멤버/메모가 그대로 로그인 계정으로 이어진다(요구사항 2).
  try {
    const { data: sess } = await sb.auth.getSession();
    const isAnon = (sess.session?.user as { is_anonymous?: boolean } | null)?.is_anonymous === true;
    if (isAnon && (await linkAnonymousIdentity(provider))) return;
  } catch (e) {
    console.warn('[auth] 익명 연결 시도 실패, 일반 로그인 폴백', e);
  }
  const isNative = Capacitor.isNativePlatform();
  if (isNative) {
    // 네이티브: SafariViewController로 OAuth URL 열고 deep link로 콜백 수신
    attachDeepLinkOnce();
    const { data, error } = await sb.auth.signInWithOAuth({
      provider,
      options: { redirectTo: REDIRECT_NATIVE, skipBrowserRedirect: true },
    });
    if (error) throw error;
    if (!data?.url) throw new Error('OAuth URL을 받지 못했어요');
    await Browser.open({ url: data.url, presentationStyle: 'popover' });
    return;
  }
  // 웹: Supabase가 location.href 리다이렉트로 처리
  const { error } = await sb.auth.signInWithOAuth({
    provider,
    options: { redirectTo: `${location.origin}` },
  });
  if (error) throw error;
}

/** 게스트(익명) 로그인 — Supabase Anonymous Sign-in 활성화 필요. plans/sessions 클라우드 저장 가능. */
export async function signInAnonymously(): Promise<void> {
  const sb = getSupabase();
  if (!sb) throw new Error('Supabase 미구성');
  // @supabase/supabase-js v2.43+ 에서 signInAnonymously 지원
  const auth = sb.auth as unknown as { signInAnonymously: () => Promise<{ error: { message: string } | null }> };
  if (typeof auth.signInAnonymously !== 'function') {
    throw new Error('Supabase 클라이언트가 익명 로그인을 지원하지 않아요 (v2.43+ 필요)');
  }
  const { error } = await auth.signInAnonymously();
  if (error) throw new Error(error.message);
}

export async function signOut(): Promise<void> {
  const sb = getSupabase();
  if (!sb) return;
  await sb.auth.signOut();
}

export async function sendMagicLink(email: string): Promise<void> {
  const sb = getSupabase();
  if (!sb) throw new Error('Supabase 미구성');
  const { error } = await sb.auth.signInWithOtp({
    email,
    options: {
      emailRedirectTo: Capacitor.isNativePlatform()
        ? 'kr.publicad.imjangnote://auth-callback'
        : `${location.origin}`,
    },
  });
  if (error) throw error;
}
