import { Fragment, useEffect, useMemo, useRef, useState } from 'react';
import { Icon } from '@/components/Icon';
import { MonthCalendar } from '@/components/MonthCalendar';
import { FilterBar } from '@/components/FilterBar';
import { useApp } from '@/store/AppStore';
import { wonText } from '@/lib/format';
import { HomeMapKakao as HomeMap } from '@/screens/HomeMapKakao';
import { searchAll, type SearchHit } from '@/lib/regionSearch';
import { repArea } from '@/store/AppStore';

function dateLabel(v: string): string {
  if (!v) return '미정';
  const d = new Date(v + 'T00:00:00');
  const DOW = ['일', '월', '화', '수', '목', '금', '토'];
  return `${d.getMonth() + 1}월 ${d.getDate()}일 (${DOW[d.getDay()]})`;
}

export function AddPlanSheet() {
  const { complexes, filteredComplexes, savePlans, setTab, refreshComplexesAt, area, popOverlay, setMapTarget, openDetail } = useApp();
  const onClose = popOverlay;
  const today = new Date().toISOString().slice(0, 10);

  // 각 임장 계획은 독립 — 새 계획 picker는 다른 계획의 단지를 '담김'으로 표시하지 않는다.
  // (같은 단지를 여러 계획에 독립적으로 넣을 수 있음)
  // available = 선택 가능한 전체 단지 — route 계산·선택 단지 조회용.
  const available = complexes;

  const [sel, setSel] = useState<string[]>([]);
  // 현재 영역의 마지막 토큰(주로 동/읍/면)을 기본값으로
  const defaultQ = useMemo(() => {
    const parts = (area.name || '').trim().split(/\s+/).filter(Boolean);
    return parts.length ? parts[parts.length - 1] : '';
  }, [area.name]);
  const [q, setQ] = useState(defaultQ);
  const [focused, setFocused] = useState(false);
  const [date, setDate] = useState<string>(today);
  const [showCal, setShowCal] = useState(false);
  const [memo, setMemo] = useState('');
  const [title, setTitle] = useState('');

  const [regionResults, setRegionResults] = useState<SearchHit[]>([]);
  const [searching, setSearching] = useState(false);
  const [regionLoading, setRegionLoading] = useState(false);
  const [showAll, setShowAll] = useState(false);
  const [mapFullscreen, setMapFullscreen] = useState(false);
  const debounceRef = useRef<number | null>(null);
  const LIST_LIMIT = 5;

  // 선택 단지: 필터 무관, sel 추가순(번호순)으로 항상 최상단 표시 (선택한 건 절대 사라지지 않게).
  const selectedCards = useMemo(
    () =>
      sel
        .map((id) => available.find((c) => c.id === id))
        .filter((c): c is (typeof available)[number] => !!c),
    [sel, available],
  );
  // 미선택 단지: 시세탭 필터(유형/가격/세대/무거래) 적용 + 거리순.
  const unselectedCards = useMemo(
    () =>
      filteredComplexes
        .filter((c) => !sel.includes(c.id))
        .sort((a, b) => (a.distM ?? 0) - (b.distM ?? 0)),
    [filteredComplexes, sel],
  );
  // 표시: 선택(전체) + 미선택(LIST_LIMIT 제한).
  const visibleList = useMemo(
    () =>
      showAll
        ? [...selectedCards, ...unselectedCards]
        : [...selectedCards, ...unselectedCards.slice(0, LIST_LIMIT)],
    [selectedCards, unselectedCards, showAll],
  );

  // 두 좌표 거리 (m)
  function distanceM(a: { lat: number; lng: number }, b: { lat: number; lng: number }) {
    const R = 6371000;
    const dLat = ((b.lat - a.lat) * Math.PI) / 180;
    const dLng = ((b.lng - a.lng) * Math.PI) / 180;
    const la1 = (a.lat * Math.PI) / 180;
    const la2 = (b.lat * Math.PI) / 180;
    const x = Math.sin(dLat / 2) ** 2 + Math.cos(la1) * Math.cos(la2) * Math.sin(dLng / 2) ** 2;
    return 2 * R * Math.asin(Math.sqrt(x));
  }
  // 선택 순서대로 단지간 거리 + 총 거리
  const route = useMemo(() => {
    const byId = new Map(available.map((c) => [c.id, c]));
    const pts = sel.map((id) => byId.get(id)).filter((c): c is typeof available[0] => !!c);
    let total = 0;
    const legs: Record<string, number> = {}; // 다음 단지로 가는 거리, key = 이전 단지 id
    for (let i = 0; i < pts.length - 1; i++) {
      const d = distanceM(pts[i], pts[i + 1]);
      legs[pts[i].id] = d;
      total += d;
    }
    return { legs, total };
  }, [available, sel]);

  function distLabel(m: number): string {
    return m >= 1000 ? `${(m / 1000).toFixed(1)}km` : `${Math.round(m)}m`;
  }

  useEffect(() => {
    if (debounceRef.current) window.clearTimeout(debounceRef.current);
    const term = q.trim();
    if (!term) {
      setRegionResults([]);
      setSearching(false);
      return;
    }
    debounceRef.current = window.setTimeout(async () => {
      setSearching(true);
      const hits = await searchAll(term);
      setRegionResults(hits);
      setSearching(false);
    }, 250);
    return () => {
      if (debounceRef.current) window.clearTimeout(debounceRef.current);
    };
  }, [q]);

  async function pickHit(h: SearchHit) {
    setQ('');
    setRegionResults([]);
    setRegionLoading(true);
    setShowAll(false);
    setSel([]);
    setMapTarget({ lat: h.lat, lng: h.lng }); // 지도를 새 좌표로 즉시 이동
    try {
      await refreshComplexesAt({ lat: h.lat, lng: h.lng });
      if (h.kind === 'complex') {
        // 단지 선택 후엔 해당 단지를 자동 선택
        setSel([h.id]);
      }
    } finally {
      setRegionLoading(false);
    }
  }

  const toggle = (id: string) =>
    setSel((s) => (s.includes(id) ? s.filter((x) => x !== id) : [...s, id]));

  const submit = async () => {
    if (!sel.length) return;
    const baseTime = Date.now();
    // batch별 고유 seq — crypto.randomUUID로 ms 충돌 0
    const batchId =
      typeof crypto !== 'undefined' && 'randomUUID' in crypto
        ? crypto.randomUUID()
        : `b${baseTime}-${Math.random().toString(36).slice(2, 10)}`;
    const combinedMemo = title.trim()
      ? memo.trim()
        ? `[${title.trim()}] ${memo.trim()}`
        : `[${title.trim()}]`
      : memo;
    const items = sel
      .map((id, i) => {
        const c = complexes.find((x) => x.id === id);
        if (!c) return null;
        return {
          complexId: c.id,
          complexName: c.name,
          complexType: c.type,
          lat: c.lat,
          lng: c.lng,
          plannedDate: date || undefined,
          memo: combinedMemo,
          done: false,
          createdAt: baseTime + i,
          batchId,
        };
      })
      .filter((x): x is NonNullable<typeof x> => !!x);
    await savePlans(items);
    setTab('record');
    onClose();
  };

  return (
    <div className="screen push-enter" style={{ background: 'var(--bg)' }}>
      <div className="navbar flush">
        <button className="backbtn" onClick={onClose} type="button">
          <Icon name="back" size={22} />
        </button>
        <div className="grow" style={{ fontWeight: 800, fontSize: 16, textAlign: 'center' }}>
          임장 계획 추가
        </div>
        <div style={{ width: 36 }} />
      </div>
      <div className="scroll pad" style={{ paddingTop: 4, paddingBottom: 40 }}>

        <input
          className="plan-title-in"
          placeholder="임장계획 제목"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
        />
        <div style={{ position: 'relative' }}>
          <div className="plan-search">
            <Icon name="loc" size={16} color="var(--accent)" fill />
            <input
              className="plan-search-in"
              placeholder="동·지역명 검색"
              value={q}
              onChange={(e) => setQ(e.target.value)}
              onFocus={() => setFocused(true)}
              onBlur={() => setTimeout(() => setFocused(false), 200)}
            />
            {q && (
              <button
                type="button"
                onClick={() => setQ('')}
                style={{ color: 'var(--ink-4)', padding: 2 }}
              >
                <Icon name="x" size={15} />
              </button>
            )}
          </div>
          {focused && q.trim() && (
            <div className="search-drop">
              {searching && regionResults.length === 0 ? (
                <div className="search-empty">검색 중…</div>
              ) : regionResults.length === 0 ? (
                <div className="search-empty">{`"${q}" 검색 결과가 없어요`}</div>
              ) : (
                regionResults.map((r) => (
                  <button
                    key={r.kind + ':' + r.id}
                    type="button"
                    className="search-res"
                    onMouseDown={(e) => e.preventDefault()}
                    onClick={() => void pickHit(r)}
                  >
                    {r.kind === 'complex' ? (
                      <Icon name="build" size={15} color="var(--accent)" stroke={2.2} />
                    ) : (
                      <Icon name="loc" size={15} color="var(--accent)" />
                    )}
                    <div style={{ flex: 1, textAlign: 'left', minWidth: 0 }}>
                      <div
                        style={{
                          fontWeight: 700,
                          fontSize: 14,
                          whiteSpace: 'nowrap',
                          overflow: 'hidden',
                          textOverflow: 'ellipsis',
                        }}
                      >
                        {r.kind === 'complex' ? r.name : r.dong || r.name}
                      </div>
                      {r.kind === 'complex' ? (
                        <>
                          {r.roadAddr && (
                            <div
                              className="muted"
                              style={{
                                fontSize: 11.5,
                                fontWeight: 600,
                                marginTop: 1,
                                whiteSpace: 'nowrap',
                                overflow: 'hidden',
                                textOverflow: 'ellipsis',
                              }}
                            >
                              {r.roadAddr}
                            </div>
                          )}
                          {r.jibunAddr && (
                            <div
                              className="muted"
                              style={{
                                fontSize: 11,
                                fontWeight: 600,
                                marginTop: 1,
                                whiteSpace: 'nowrap',
                                overflow: 'hidden',
                                textOverflow: 'ellipsis',
                                color: 'var(--ink-4)',
                              }}
                            >
                              <span
                                style={{
                                  display: 'inline-block',
                                  fontSize: 9.5,
                                  fontWeight: 700,
                                  padding: '1px 4px',
                                  marginRight: 4,
                                  background: 'var(--surface-2)',
                                  borderRadius: 4,
                                  color: 'var(--ink-3)',
                                }}
                              >
                                지번
                              </span>
                              {r.jibunAddr}
                            </div>
                          )}
                          {!r.roadAddr && !r.jibunAddr && (
                            <div
                              className="muted"
                              style={{ fontSize: 11.5, fontWeight: 600, marginTop: 1 }}
                            >
                              {r.type}
                              {r.households != null && ` · ${r.households.toLocaleString()}세대`}
                            </div>
                          )}
                        </>
                      ) : (
                        <div
                          className="muted"
                          style={{
                            fontSize: 11.5,
                            fontWeight: 600,
                            marginTop: 1,
                            whiteSpace: 'nowrap',
                            overflow: 'hidden',
                            textOverflow: 'ellipsis',
                          }}
                        >
                          {r.gu || r.name}
                        </div>
                      )}
                    </div>
                    <span className="search-cnt">{r.kind === 'complex' ? '단지' : '이동'}</span>
                  </button>
                ))
              )}
            </div>
          )}
        </div>
        {regionLoading && (
          <div
            className="muted"
            style={{ fontSize: 12.5, fontWeight: 600, marginTop: 10, textAlign: 'center' }}
          >
            해당 지역 단지를 불러오는 중…
          </div>
        )}

        <div className="row between" style={{ margin: '16px 2px 8px' }}>
          <span className="sect-cap">단지 선택</span>
          <span
            className="sect-cap"
            style={{ color: sel.length ? 'var(--accent)' : 'var(--ink-3)' }}
          >
            {sel.length ? `${sel.length}개 선택됨` : '여러 개 선택 가능'}
          </span>
        </div>

        {/* 시세탭과 동일한 단지 필터 (유형/상세) */}
        <FilterBar />

        {available.length === 0 ? (
          <div
            className="muted"
            style={{ fontSize: 12.5, fontWeight: 600, padding: '8px 2px 16px' }}
          >
            주변 단지를 모두 담았거나, 시세 목록을 먼저 불러와주세요.
          </div>
        ) : (
          <>
            <div
              className="plan-map"
              style={{
                height: mapFullscreen ? 'calc(100vh - 320px)' : 420,
                transition: 'height 0.25s ease',
                position: 'relative',
              }}
            >
              <HomeMap
                mode="picker"
                selectedIds={sel}
                onToggleSelect={(id) =>
                  setSel((s) => (s.includes(id) ? s.filter((x) => x !== id) : [...s, id]))
                }
                containerClassName=""
                containerStyle={{ width: '100%', height: '100%', overflow: 'hidden', borderRadius: 16 }}
                hideTopBar
                hideFilterBar
                hideControls
                hideMiniCard
              />
              {/* 총 거리 배지 — 지도 위 floating (fullscreen에서도 보임) */}
              {sel.length >= 2 && (
                <div
                  className="row between"
                  style={{
                    position: 'absolute',
                    top: 10,
                    left: 10,
                    right: 10,
                    zIndex: 9,
                    padding: '8px 12px',
                    background: 'rgba(255,255,255,.95)',
                    backdropFilter: 'blur(8px)',
                    borderRadius: 10,
                    boxShadow: 'var(--sh-card)',
                    fontSize: 12,
                    fontWeight: 700,
                  }}
                >
                  <span style={{ color: 'var(--ink-2)' }}>{`${sel.length}곳 동선`}</span>
                  <span className="num" style={{ color: 'var(--accent)' }}>
                    {`총 ${distLabel(route.total)}`}
                  </span>
                </div>
              )}
            </div>
            <div
              onTouchStart={(e) => { (e.currentTarget as unknown as { _sy?: number })._sy = e.touches[0].clientY; }}
              onTouchEnd={(e) => {
                const start = (e.currentTarget as unknown as { _sy?: number })._sy ?? 0;
                const delta = e.changedTouches[0].clientY - start;
                if (delta < -30) setMapFullscreen(true);
                else if (delta > 30) setMapFullscreen(false);
              }}
              onClick={() => setMapFullscreen((v) => !v)}
              style={{
                marginTop: 2,
                marginBottom: 4,
                padding: '6px 0',
                display: 'flex',
                justifyContent: 'center',
                cursor: 'pointer',
                touchAction: 'none',
              }}
              title={mapFullscreen ? '아래로 슬라이드: 리스트 보기' : '위로 슬라이드: 지도 전체 보기'}
            >
              <div
                style={{
                  width: 44,
                  height: 5,
                  borderRadius: 999,
                  background: 'var(--line-strong)',
                }}
              />
            </div>
            {/* 리스트 영역 — fullscreen일 때 숨김 */}
            <div
              className="pick-list"
              style={{
                marginBottom: 20,
                display: mapFullscreen ? 'none' : 'flex',
                flexDirection: 'column',
                gap: 0,
              }}
            >
            {visibleList.map((c, idx, arr) => {
              const on = sel.includes(c.id);
              const order = on ? sel.indexOf(c.id) + 1 : null;
              const ra = repArea(c);
              // 다음 카드도 동일 sel 순서로 selected면 그 사이에 leg 거리 표시
              const next = arr[idx + 1];
              const nextOrder = next && sel.includes(next.id) ? sel.indexOf(next.id) + 1 : null;
              const showLeg = on && nextOrder === (order ?? -2) + 1 && route.legs[c.id] != null;
              return (
                <Fragment key={c.id}>
                <div
                  className={'card complex-card' + (on ? ' on' : '')}
                  role="button"
                  tabIndex={0}
                  onClick={() => toggle(c.id)}
                  style={{
                    cursor: 'pointer',
                    border: on ? '1.5px solid var(--accent)' : undefined,
                  }}
                >
                  <div style={{ minWidth: 0 }}>
                    <div>
                      <div className="row between" style={{ gap: 8, alignItems: 'center' }}>
                        {order != null && (
                          <span
                            className="num"
                            style={{
                              flexShrink: 0,
                              minWidth: 20,
                              height: 20,
                              borderRadius: 10,
                              background: 'var(--accent)',
                              color: '#fff',
                              display: 'inline-flex',
                              alignItems: 'center',
                              justifyContent: 'center',
                              fontWeight: 800,
                              fontSize: 11,
                              padding: '0 6px',
                            }}
                          >
                            {order}
                          </span>
                        )}
                        <div
                          style={{
                            fontWeight: 700,
                            fontSize: 15.5,
                            letterSpacing: '-.02em',
                            whiteSpace: 'nowrap',
                            overflow: 'hidden',
                            textOverflow: 'ellipsis',
                            flex: 1,
                            minWidth: 0,
                          }}
                        >
                          {c.name}
                        </div>
                        <div className="price-big num" style={{ flexShrink: 0 }}>
                          {ra.price > 0 ? wonText(ra.price) : '거래 없음'}
                        </div>
                      </div>
                      <div className="row between" style={{ marginTop: 9, gap: 8, alignItems: 'center' }}>
                        <div className="row gap8" style={{ flexWrap: 'wrap', alignItems: 'center', rowGap: 6 }}>
                          <span className="card-dist">
                            <Icon name="loc" size={11} stroke={2.4} />
                            {(c.distM ?? 0) + 'm'}
                          </span>
                          <span
                            className="muted"
                            style={{ fontSize: 12, fontWeight: 600, whiteSpace: 'nowrap' }}
                          >
                            {`${c.type} · ${ra.m2}㎡ 기준`}
                          </span>
                        </div>
                        <button
                          className="btn btn-primary"
                          style={{
                            width: 'auto',
                            height: 26,
                            padding: '0 12px',
                            fontSize: 12,
                            fontWeight: 700,
                            borderRadius: 8,
                            flexShrink: 0,
                          }}
                          onClick={(e) => { e.stopPropagation(); openDetail(c.id); }}
                          type="button"
                        >
                          상세
                        </button>
                      </div>
                    </div>
                  </div>
                </div>
                {showLeg && (
                  <div
                    style={{
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      gap: 8,
                      marginTop: 0,
                      marginBottom: 14,
                      fontSize: 11.5,
                      fontWeight: 700,
                      color: 'var(--ink-3)',
                    }}
                  >
                    <span style={{ flex: '0 0 12px', height: 14, borderLeft: '2px dashed var(--line-strong)' }} />
                    <span className="num">{`${distLabel(route.legs[c.id])} 이동`}</span>
                    <span style={{ flex: '0 0 12px', height: 14, borderLeft: '2px dashed var(--line-strong)' }} />
                  </div>
                )}
                </Fragment>
              );
            })}
            </div>
            {!showAll && unselectedCards.length > LIST_LIMIT && (
              <button
                type="button"
                onClick={() => setShowAll(true)}
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  gap: 6,
                  width: '100%',
                  padding: '12px',
                  marginTop: -8,
                  marginBottom: 20,
                  background: 'var(--surface)',
                  border: '1.5px solid var(--line-strong)',
                  borderRadius: 12,
                  fontWeight: 700,
                  fontSize: 13,
                  color: 'var(--ink-2)',
                  cursor: 'pointer',
                }}
              >
                {`더보기 (${unselectedCards.length - LIST_LIMIT}개)`}
                <Icon name="chevD" size={14} color="var(--ink-3)" />
              </button>
            )}
          </>
        )}

        <div className="sect-cap" style={{ marginBottom: 8, marginLeft: 2 }}>
          방문 예정일
        </div>
        <button
          type="button"
          className="date-pick-row"
          onClick={() => setShowCal((v) => !v)}
        >
          <div className="row gap8">
            <Icon name="calendar" size={16} color="var(--accent)" stroke={2.2} />
            <span
              style={{
                fontWeight: 700,
                fontSize: 14,
                color: date ? 'var(--ink)' : 'var(--ink-3)',
              }}
            >
              {dateLabel(date)}
            </span>
          </div>
          <Icon
            name={showCal ? 'chevD' : 'chevR'}
            size={17}
            color="var(--ink-4)"
          />
        </button>
        {showCal && (
          <div className="card" style={{ padding: '14px 16px', marginTop: 8 }}>
            <MonthCalendar
              value={date}
              onChange={(v) => {
                setDate(v);
                setShowCal(false);
              }}
            />
          </div>
        )}

        <div style={{ height: 16 }} />
        <div className="sect-cap" style={{ marginBottom: 8, marginLeft: 2 }}>
          메모
        </div>
        <textarea
          className="plan-memo"
          value={memo}
          onChange={(e) => setMemo(e.target.value)}
          placeholder="예) 오전에 84㎡ 로열층 매물 보기로 함"
        />

        <button
          type="button"
          className="btn btn-primary"
          style={{
            marginTop: 18,
            opacity: sel.length ? 1 : 0.45,
            pointerEvents: sel.length ? 'auto' : 'none',
          }}
          disabled={!sel.length}
          onClick={() => void submit()}
        >
          <Icon name="check" size={18} stroke={2.4} />
          {sel.length > 1 ? `${sel.length}개 계획에 추가` : '계획에 추가'}
        </button>
        <div style={{ height: 8 }} />
      </div>
    </div>
  );
}
