// Kakao Maps 기반 HomeMap — 시세탭/임장계획 picker 공용

import { useEffect, useMemo, useRef, useState } from 'react';
import { Icon } from '@/components/Icon';
import { Stars } from '@/components/Stars';
import { TypeChip } from '@/components/Toast';
import { FilterBar } from '@/components/FilterBar';
import { HomeTopBar } from './HomeList';
import { useApp, repArea, complexById } from '@/store/AppStore';
import { wonText, pyeong } from '@/lib/format';
import { loadKakaoMaps, type KakaoMap, type KakaoCustomOverlay, type KakaoMaps } from '@/lib/kakaoMaps';
import { makeComplexMarkerEl, makeMeMarkerEl } from '@/lib/mapMarkers';
import { Capacitor } from '@capacitor/core';
import { ENV } from '@/lib/env';
import type { Complex } from '@/types/domain';

// 앱은 server.url로 등록된 https origin(github.io)에서 웹앱을 그대로 로드 → iOS도 origin이 등록돼 있어
// Kakao SDK를 직접 호출 가능 → iframe 우회 불필요. 아래 iframe 분기는 false로 비활성(추후 코드 정리).
const USE_IFRAME_MAP = false;
let EMBED_ORIGIN = '';
try { EMBED_ORIGIN = new URL(ENV.kakaoEmbedUrl).origin; } catch { /* noop */ }

export interface HomeMapKakaoProps {
  mode?: 'home' | 'picker';
  selectedIds?: string[];
  onToggleSelect?: (id: string) => void;
  containerStyle?: React.CSSProperties;
  containerClassName?: string;
  hideTopBar?: boolean;
  hideFilterBar?: boolean;
  hideControls?: boolean;
  hideMiniCard?: boolean;
}

export function HomeMapKakao({
  mode = 'home',
  selectedIds,
  onToggleSelect,
  containerStyle,
  containerClassName,
  hideTopBar,
  hideFilterBar,
  hideControls,
  hideMiniCard,
}: HomeMapKakaoProps = {}) {
  const isPicker = mode === 'picker';
  const pickerSelSet = useMemo(() => new Set(selectedIds ?? []), [selectedIds]);
  const onToggleSelectRef = useRef(onToggleSelect);
  onToggleSelectRef.current = onToggleSelect;
  const {
    filteredComplexes,
    currentLatLng,
    selectedComplexId,
    setSelectedComplexId,
    notes,
    voiceOn,
    openDetail,
    refreshComplexesAt,
    resortComplexesByCenter,
    plans,
    savePlan,
    deletePlan,
    mapTarget,
    setMapTarget,
    view,
  } = useApp();
  const complexes = filteredComplexes;
  const planIds = plans.map((p) => p.complexId);

  const refreshRef = useRef(refreshComplexesAt);
  refreshRef.current = refreshComplexesAt;
  const resortRef = useRef(resortComplexesByCenter);
  resortRef.current = resortComplexesByCenter;

  const containerRef = useRef<HTMLDivElement | null>(null);
  const mapRef = useRef<KakaoMap | null>(null);
  const kakaoRef = useRef<KakaoMaps | null>(null);
  const overlaysRef = useRef<KakaoCustomOverlay[]>([]);
  const meOverlayRef = useRef<KakaoCustomOverlay | null>(null);
  const pickerPolylineRef = useRef<{ setMap: (m: unknown) => void } | null>(null);
  const pickerLegLabelsRef = useRef<KakaoCustomOverlay[]>([]);
  const fittedRef = useRef(false);
  const visibleOnceRef = useRef(false);
  const [clusterPicker, setClusterPicker] = useState<Complex[] | null>(null);
  const [trailOn, setTrailOn] = useState(true);
  // 카카오 Places로 단지명 검색해 정확 좌표 캐시 (마커가 도로 위 → 단지 중앙으로 보정)
  const correctedCoordsRef = useRef<Map<string, { lat: number; lng: number }>>(new Map());
  const [coordsTick, setCoordsTick] = useState(0);
  const [kakaoLoaded, setKakaoLoaded] = useState(false);
  // iOS iframe 브리지용
  const iframeRef = useRef<HTMLIFrameElement | null>(null);
  const [iframeReady, setIframeReady] = useState(false);
  const lastFetchedRef = useRef<{ lat: number; lng: number } | null>(null);
  const userMovedRef = useRef(false);           // 사용자가 지도 드래그/지역검색하면 자동 내위치 center 중단
  const meInitialCenteredRef = useRef(false);   // 내위치 center는 최초 1회만 (이후 GPS 갱신은 마커만 이동)
  const lastCenteredRef = useRef<{ lat: number; lng: number } | null>(null);
  const iframeFittedRef = useRef(false);         // GPS 없을 때 첫 단지로 center (1회)
  const postToMap = useRef((msg: Record<string, unknown>) => {
    try {
      iframeRef.current?.contentWindow?.postMessage(JSON.stringify(msg), '*');
    } catch { /* noop */ }
  }).current;
  // currentLatLng을 ResizeObserver 등 closure 안에서 최신 값으로 참조하기 위한 ref
  const currentLatLngRef = useRef(currentLatLng);
  useEffect(() => { currentLatLngRef.current = currentLatLng; }, [currentLatLng]);
  const complexesRef = useRef(complexes);
  useEffect(() => { complexesRef.current = complexes; }, [complexes]);
  // mapTarget도 closure 안에서 최신 참조용
  const mapTargetRef = useRef(mapTarget);
  useEffect(() => { mapTargetRef.current = mapTarget; }, [mapTarget]);

  // 초기 캐시 로드
  useEffect(() => {
    try {
      const raw = localStorage.getItem('imjang.complexCoords');
      if (!raw) return;
      const obj = JSON.parse(raw) as Record<string, { lat: number; lng: number }>;
      for (const [k, v] of Object.entries(obj)) {
        if (v?.lat != null && v?.lng != null) correctedCoordsRef.current.set(k, v);
      }
      setCoordsTick((t) => t + 1);
    } catch {
      /* noop */
    }
  }, []);

  // 단지 좌표 보정 — 서버측에서 1회 배치 보정한 좌표맵(static)을 로드해 마커를 단지 중앙에 표시.
  //   raw(행안부) 좌표가 역/대표지점으로 찍혀 건물과 어긋나는 단지(신검단 등 신축) 대응.
  //   ⚠️ 클라이언트 API 호출 없음 — 정적 파일만 1회 읽음(외부 API 안전 정책 준수).
  //   생성 스크립트: scripts/correct-coords.py (Kakao 키워드검색 1회 배치, 이름매칭+600m상한+메인POI).
  useEffect(() => {
    let cancelled = false;
    fetch(`${import.meta.env.BASE_URL}complexCoords.json`)
      .then((r) => (r.ok ? r.json() : null))
      .then((obj: Record<string, { lat: number; lng: number }> | null) => {
        if (cancelled || !obj) return;
        let n = 0;
        for (const [k, v] of Object.entries(obj)) {
          if (v?.lat != null && v?.lng != null) { correctedCoordsRef.current.set(k, v); n++; } // static=권위소스
        }
        if (n > 0) setCoordsTick((t) => t + 1);
      })
      .catch(() => { /* 파일 없으면 raw 좌표 사용 */ });
    return () => { cancelled = true; };
  }, []);

  const sel = selectedComplexId ? complexById(complexes, selectedComplexId) : null;

  // 1) 카카오 SDK 로드 + 지도 초기화 (iOS는 iframe 사용 → skip)
  useEffect(() => {
    if (USE_IFRAME_MAP) return;
    let cancelled = false;
    void (async () => {
      const kakao = await loadKakaoMaps();
      if (!kakao || cancelled) return;
      const el = containerRef.current;
      if (!el) return;
      kakaoRef.current = kakao;
      setKakaoLoaded(true);

      const center = currentLatLng
        ? new kakao.LatLng(currentLatLng.lat, currentLatLng.lng)
        : complexes[0]
          ? new kakao.LatLng(complexes[0].lat, complexes[0].lng)
          : new kakao.LatLng(37.5665, 126.978);
      const map = new kakao.Map(el, { center, level: 3 });
      mapRef.current = map;
      // 컨테이너 크기 변경 시 자동 relayout
      let prevW = el.clientWidth, prevH = el.clientHeight;
      let relayoutTimer: number | null = null;
      const ro = new ResizeObserver(() => {
        try {
          const w = el.clientWidth, h = el.clientHeight;
          if (w === 0 || h === 0) { prevW = w; prevH = h; return; }
          const wasHidden = prevW === 0 || prevH === 0;
          const changed = w !== prevW || h !== prevH;
          if (!changed) return;
          prevW = w; prevH = h;
          // 디바운스로 매 frame 호출 방지
          if (relayoutTimer) window.clearTimeout(relayoutTimer);
          relayoutTimer = window.setTimeout(() => {
            try {
              map.relayout();
              if (wasHidden) {
                if (!visibleOnceRef.current) {
                  // 첫 visible 전환: mapTarget > 내 위치 > 첫 단지 우선순위로 setCenter
                  visibleOnceRef.current = true;
                  const t = mapTargetRef.current;
                  const c = t ?? currentLatLngRef.current ?? complexesRef.current[0];
                  if (c) {
                    map.setCenter(new kakao.LatLng(c.lat, c.lng));
                    map.setLevel(3);
                    if (t) setMapTarget(null);
                  }
                } else {
                  // 이후 visible 전환: 사용자가 본 마지막 view 유지
                  map.setCenter(map.getCenter());
                }
              }
            } catch {/* noop */}
          }, 80);
        } catch {/* noop */}
      });
      ro.observe(el);
      (map as unknown as { __ro?: ResizeObserver }).__ro = ro;

      // dragend(실제 이동)로만 새 영역 데이터 로드 (디바운스 + 거리 임계).
      // 줌(zoom_changed)은 의도적으로 제외 — 줌은 중심이 그대로이므로 단지 집합·정렬을
      // 바꾸지 않아야 한다. (줌 레벨과 무관하게 동일한 '가까운 순' 리스트 유지)
      let moveTimer: number | null = null;
      let lastFetched: { lat: number; lng: number } | null = null;
      const onMoveEnd = () => {
        const m = mapRef.current;
        if (!m) return;
        const c = m.getCenter();
        const lat = c.getLat();
        const lng = c.getLng();
        // 1) 이동 거리만큼만 로컬 거리 재정렬 — 드래그로 다른 영역을 보면 그 중심 최근접순으로 갱신.
        //    (API 호출 없음. 서버 fetch는 아래 300m 게이트로 별도 제한.)
        if (lastFetched) {
          const dy0 = (lat - lastFetched.lat) * 110540;
          const dx0 = (lng - lastFetched.lng) * 111320 * Math.cos((lat * Math.PI) / 180);
          // 미세 이동(줌 후 관성 등)은 무시 — 50m 미만이면 재정렬 안 함.
          if (Math.hypot(dx0, dy0) < 50) return;
        }
        resortRef.current?.({ lat, lng });
        // 2) 서버 단지 재조회는 300m 이상 이동 시에만 (API 절약).
        if (lastFetched) {
          const dy = (lat - lastFetched.lat) * 110540;
          const dx = (lng - lastFetched.lng) * 111320 * Math.cos((lat * Math.PI) / 180);
          if (Math.hypot(dx, dy) < 300) return;
        }
        if (moveTimer) window.clearTimeout(moveTimer);
        moveTimer = window.setTimeout(() => {
          moveTimer = null;
          lastFetched = { lat, lng };
          refreshRef.current?.({ lat, lng });
        }, 1200);
      };
      // 첫 진입 기준점 — 이후 이동 거리 계산용. 초기 center로 세팅.
      {
        const c0 = map.getCenter();
        lastFetched = { lat: c0.getLat(), lng: c0.getLng() };
      }
      kakao.event.addListener(map, 'dragend', onMoveEnd);

      // 빈 영역 클릭 시 선택 해제
      kakao.event.addListener(map, 'click', () => setSelectedComplexId(null));
    })();
    return () => {
      cancelled = true;
      const m = mapRef.current as unknown as { __ro?: ResizeObserver } | null;
      m?.__ro?.disconnect();
      overlaysRef.current.forEach((o) => o.setMap(null));
      overlaysRef.current = [];
      meOverlayRef.current?.setMap(null);
      meOverlayRef.current = null;
      pickerPolylineRef.current?.setMap(null);
      pickerPolylineRef.current = null;
      pickerLegLabelsRef.current.forEach((o) => o.setMap(null));
      pickerLegLabelsRef.current = [];
      mapRef.current = null;
    };
    // 1회만 — 이후 변경은 별도 effect로
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // ===== iOS iframe 지도 브리지 (USE_IFRAME_MAP일 때만 동작) =====
  const voiceOnRef = useRef(voiceOn);
  voiceOnRef.current = voiceOn;

  // 단지 → embed 페이로드 (가격은 부모에서 계산해 경량 전송)
  const complexPayload = useMemo(() => {
    if (!USE_IFRAME_MAP) return [];
    const pickerOrder = isPicker
      ? new Map((selectedIds ?? []).map((id, i) => [id, i + 1]))
      : null;
    return complexes.map((c) => {
      const prices = (c.areas ?? [])
        .map((a) => { const last = a.trend?.[a.trend.length - 1]; return last?.last ?? last?.max ?? a.price; })
        .filter((p) => p > 0);
      const pos = correctedCoordsRef.current.get(c.id) ?? { lat: c.lat, lng: c.lng };
      return {
        id: c.id, name: c.name, type: c.type,
        lat: pos.lat, lng: pos.lng,
        households: c.households ?? 0,
        priceMin: prices.length ? Math.min(...prices) : null,
        priceMax: prices.length ? Math.max(...prices) : null,
        hasNote: !!notes[c.id],
        selected: isPicker ? pickerSelSet.has(c.id) : c.id === selectedComplexId,
        order: isPicker ? pickerOrder?.get(c.id) : undefined,
      };
    });
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [complexes, notes, selectedComplexId, isPicker, pickerSelSet, selectedIds, coordsTick]);

  // 부모→iframe: 단지/모드 갱신 + 첫 단지 로드 시 center 1회 (내위치 우선, 없으면 첫 단지)
  useEffect(() => {
    if (!USE_IFRAME_MAP || !iframeReady) return;
    postToMap({ type: 'setMode', picker: isPicker });
    postToMap({ type: 'setComplexes', complexes: complexPayload });
    // GPS가 아직 없을 때만 첫 단지로 center (GPS 도착 시 me-effect가 내위치로 재center)
    if (!iframeFittedRef.current && !userMovedRef.current && !lastCenteredRef.current && complexPayload.length > 0 && (isPicker || !currentLatLngRef.current)) {
      iframeFittedRef.current = true;
      const t = currentLatLngRef.current ?? complexPayload[0];
      console.log('[mapbridge] center→firstComplex/initial', t.lat.toFixed(5), t.lng.toFixed(5), 'hasGPS', !!currentLatLngRef.current);
      postToMap({ type: 'setCenter', lat: t.lat, lng: t.lng, level: 3 });
      lastFetchedRef.current = { lat: t.lat, lng: t.lng };
      lastCenteredRef.current = { lat: t.lat, lng: t.lng };
    }
  }, [complexPayload, iframeReady, isPicker, postToMap]);

  // 선택 변경 → select + panTo
  useEffect(() => {
    if (!USE_IFRAME_MAP || !iframeReady) return;
    postToMap({ type: 'select', id: selectedComplexId });
    if (selectedComplexId) {
      const c = complexById(complexes, selectedComplexId);
      if (c) postToMap({ type: 'panTo', lat: c.lat, lng: c.lng });
    }
  }, [selectedComplexId, iframeReady, complexes, postToMap]);

  // 내 위치 → setMe + 첫 좌표 도착 시 center
  useEffect(() => {
    if (!USE_IFRAME_MAP || !iframeReady || !currentLatLng) return;
    // 내위치 마커는 GPS 갱신마다 따라 이동 (지도는 안 움직임)
    postToMap({ type: 'setMe', pos: { lat: currentLatLng.lat, lng: currentLatLng.lng } });
    // picker는 list/map 탭 개념이 없으므로 여기서 최초 1회 내위치 center.
    // home은 아래 '지도 탭 진입' effect가 진입할 때마다 center.
    if (isPicker && !meInitialCenteredRef.current && !userMovedRef.current) {
      meInitialCenteredRef.current = true;
      lastFetchedRef.current = { lat: currentLatLng.lat, lng: currentLatLng.lng };
      postToMap({ type: 'setCenter', lat: currentLatLng.lat, lng: currentLatLng.lng, level: 4 });
    }
  }, [currentLatLng, iframeReady, isPicker, postToMap]);

  // home 지도 탭 진입(view→'map')마다 내위치로 center. 진입 후 사용자가 드래그하면 유지(userMoved).
  // 탭을 벗어나면 플래그 리셋 → 다음 진입 때 다시 center.
  useEffect(() => {
    if (!USE_IFRAME_MAP || isPicker) return;
    if (view !== 'map') {
      meInitialCenteredRef.current = false;
      userMovedRef.current = false;
      return;
    }
    if (!iframeReady || !currentLatLng) return;
    if (meInitialCenteredRef.current || userMovedRef.current) return;
    meInitialCenteredRef.current = true;
    lastFetchedRef.current = { lat: currentLatLng.lat, lng: currentLatLng.lng };
    console.log('[mapbridge] map-entry center→me', currentLatLng.lat.toFixed(5), currentLatLng.lng.toFixed(5));
    postToMap({ type: 'setCenter', lat: currentLatLng.lat, lng: currentLatLng.lng, level: 4 });
  }, [view, iframeReady, currentLatLng, isPicker, postToMap]);

  // 지도 탭이 보일 때(또는 picker) iframe이 0→실제 사이즈로 바뀌므로 relayout 트리거 → embed가 전체 재렌더.
  // (list뷰에선 iframe이 0x0이라 마커가 (0,0)에 박힘 — 보일 때 다시 그려 건물 위로 맞춤)
  useEffect(() => {
    if (!USE_IFRAME_MAP || !iframeReady) return;
    if (!isPicker && view !== 'map') return;
    const timers = [120, 450, 1000].map((d) => window.setTimeout(() => postToMap({ type: 'relayout' }), d));
    return () => { timers.forEach((t) => window.clearTimeout(t)); };
  }, [view, iframeReady, isPicker, postToMap]);

  // picker 경로 polyline
  useEffect(() => {
    if (!USE_IFRAME_MAP || !iframeReady) return;
    if (!isPicker || !selectedIds || selectedIds.length < 2) { postToMap({ type: 'pickerRoute', points: [] }); return; }
    const pts = selectedIds
      .map((id) => complexes.find((c) => c.id === id))
      .filter((c): c is Complex => !!c)
      .map((c) => { const p = correctedCoordsRef.current.get(c.id) ?? { lat: c.lat, lng: c.lng }; return { lat: p.lat, lng: p.lng }; });
    postToMap({ type: 'pickerRoute', points: pts });
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isPicker, selectedIds, complexes, iframeReady, coordsTick]);

  // mapTarget(지역검색 등 외부 trigger) → center
  useEffect(() => {
    if (!USE_IFRAME_MAP || !iframeReady || !mapTarget) return;
    if (!isPicker && view !== 'map') return;
    userMovedRef.current = true; // 지역검색 등 외부 center → 자동 내위치 center 중단
    postToMap({ type: 'setCenter', lat: mapTarget.lat, lng: mapTarget.lng, level: 3 });
    lastFetchedRef.current = { lat: mapTarget.lat, lng: mapTarget.lng };
    lastCenteredRef.current = { lat: mapTarget.lat, lng: mapTarget.lng };
    setMapTarget(null);
  }, [mapTarget, iframeReady, isPicker, view, setMapTarget, postToMap]);

  // iframe → 부모: 이벤트 수신
  useEffect(() => {
    if (!USE_IFRAME_MAP) return;
    const onMsg = (ev: MessageEvent) => {
      if (EMBED_ORIGIN && ev.origin !== EMBED_ORIGIN) return;
      if (typeof ev.data !== 'string') return;
      let msg: { type?: string; id?: string; ids?: string[]; lat?: number; lng?: number };
      try { msg = JSON.parse(ev.data); } catch { return; }
      if (!msg || !msg.type) return;
      switch (msg.type) {
        case 'log':
          console.log('[mapembed]', (msg as { m?: string }).m);
          break;
        case 'ready':
          console.log('[mapbridge] iframe ready');
          setIframeReady(true);
          break;
        case 'markerClick': {
          const id = msg.id;
          if (!id) break;
          if (isPicker) { onToggleSelectRef.current?.(id); break; }
          setSelectedComplexId(id);
          if (voiceOnRef.current) {
            const c = complexById(complexesRef.current, id);
            if (c) {
              try {
                const u = new SpeechSynthesisUtterance(`${c.name}, ${repArea(c).m2}제곱미터 ${wonText(repArea(c).price)}`);
                u.lang = 'ko-KR'; u.rate = 1.05; speechSynthesis.cancel(); speechSynthesis.speak(u);
              } catch { /* noop */ }
            }
          }
          break;
        }
        case 'cluster': {
          const list = (msg.ids ?? []).map((id) => complexById(complexesRef.current, id)).filter((c): c is Complex => !!c);
          if (list.length) setClusterPicker(list);
          break;
        }
        case 'userMoved':
          // 사용자가 지도를 드래그/줌 → 자동 내위치 center 중단 (작은 이동 포함)
          userMovedRef.current = true;
          break;
        case 'mapClick':
          if (!isPicker) setSelectedComplexId(null);
          break;
        case 'moveEnd': {
          const lat = msg.lat, lng = msg.lng;
          if (lat == null || lng == null) break;
          userMovedRef.current = true; // 사용자가 지도를 움직임 → 자동 내위치 center 중단
          resortRef.current?.({ lat, lng });
          const lf = lastFetchedRef.current;
          if (lf) {
            const dy = (lat - lf.lat) * 110540;
            const dx = (lng - lf.lng) * 111320 * Math.cos((lat * Math.PI) / 180);
            if (Math.hypot(dx, dy) < 300) break;
          }
          lastFetchedRef.current = { lat, lng };
          refreshRef.current?.({ lat, lng });
          break;
        }
      }
    };
    window.addEventListener('message', onMsg);
    return () => window.removeEventListener('message', onMsg);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isPicker]);

  // 2) 내 위치 마커 + 첫 좌표 도착 시 지도 중앙을 내 위치로
  const firstCenterRef = useRef(false);
  useEffect(() => {
    const kakao = kakaoRef.current;
    const map = mapRef.current;
    if (!kakao || !map || !currentLatLng) return;
    const pos = new kakao.LatLng(currentLatLng.lat, currentLatLng.lng);
    const existing = meOverlayRef.current;
    if (!existing) {
      const ov = new kakao.CustomOverlay({
        position: pos,
        content: makeMeMarkerEl(),
        yAnchor: 0.5,
        xAnchor: 0.5,
        zIndex: 5,
      });
      ov.setMap(map);
      meOverlayRef.current = ov;
    } else {
      existing.setPosition(pos);
    }
    // 처음 위치 받았을 때 지도 중앙을 내 위치로 이동 (default 서울시청 → 내 위치)
    if (!firstCenterRef.current) {
      firstCenterRef.current = true;
      map.setCenter(pos);
      map.setLevel(3);
    }
  }, [currentLatLng, kakaoLoaded]);

  // 3) 단지 마커 (filteredComplexes 변경마다 재배치)
  useEffect(() => {
    const kakao = kakaoRef.current;
    const map = mapRef.current;
    if (!kakao || !map) return;

    overlaysRef.current.forEach((o) => o.setMap(null));
    overlaysRef.current = [];

    // picker: selectedIds 순서로 번호 부여
    const pickerOrder = isPicker
      ? new Map((selectedIds ?? []).map((id, i) => [id, i + 1]))
      : null;
    for (const c of complexes) {
      const isSel = isPicker ? pickerSelSet.has(c.id) : c.id === selectedComplexId;
      const order = pickerOrder?.get(c.id);
      const el = makeComplexMarkerEl(c, {
        hasNote: !!notes[c.id],
        selected: isSel,
        order,
        onClick: () => {
          if (isPicker) {
            onToggleSelectRef.current?.(c.id);
            return;
          }
          // 클러스터 픽커: 36px 이내 겹치는 마커는 모아서 시트로
          const m = mapRef.current;
          const proj = m?.getProjection();
          const PICK_PX = 36;
          let overlapping: Complex[] = [c];
          if (m && proj) {
            const cp = proj.pointFromCoords(new kakao.LatLng(c.lat, c.lng));
            overlapping = complexes.filter((o) => {
              if (o.id === c.id) return true;
              const op = proj.pointFromCoords(new kakao.LatLng(o.lat, o.lng));
              return Math.hypot(op.x - cp.x, op.y - cp.y) <= PICK_PX;
            });
          }
          if (overlapping.length > 1) {
            setClusterPicker(overlapping);
            return;
          }
          setSelectedComplexId(c.id);
          if (voiceOn) {
            try {
              const u = new SpeechSynthesisUtterance(
                `${c.name}, ${repArea(c).m2}제곱미터 ${wonText(repArea(c).price)}`,
              );
              u.lang = 'ko-KR';
              u.rate = 1.05;
              speechSynthesis.cancel();
              speechSynthesis.speak(u);
            } catch {/* noop */}
          }
        },
      });
      const pos = correctedCoordsRef.current.get(c.id) ?? { lat: c.lat, lng: c.lng };
      const overlay = new kakao.CustomOverlay({
        position: new kakao.LatLng(pos.lat, pos.lng),
        content: el,
        yAnchor: 1,
        xAnchor: 0.5,
        zIndex: isSel ? 7 : 5,
        clickable: true,
      });
      overlay.setMap(map);
      overlaysRef.current.push(overlay);
    }

    // 첫 단지 로드 시 setCenter 1회 — picker/home 모두 기본 줌 레벨 3
    // 우선순위: 내 위치 > 첫 단지. home은 currentLatLng 있으면 me-effect가 처리.
    if (!fittedRef.current && complexes.length > 0 && (isPicker || !currentLatLng)) {
      fittedRef.current = true;
      const target = currentLatLng ?? complexes[0];
      try {
        map.setCenter(new kakao.LatLng(target.lat, target.lng));
        map.setLevel(3);
      } catch {/* noop */}
    }
  }, [complexes, notes, selectedComplexId, voiceOn, setSelectedComplexId, currentLatLng, isPicker, pickerSelSet, coordsTick, kakaoLoaded, selectedIds]);

  // 3.5) picker 모드: 선택 순서대로 polyline (경로) + 각 leg 중간점 거리 라벨
  useEffect(() => {
    const kakao = kakaoRef.current as (KakaoMaps & {
      Polyline: new (opts: Record<string, unknown>) => { setMap: (m: unknown) => void };
    }) | null;
    const map = mapRef.current;
    if (!kakao || !map) return;
    pickerPolylineRef.current?.setMap(null);
    pickerPolylineRef.current = null;
    pickerLegLabelsRef.current.forEach((o) => o.setMap(null));
    pickerLegLabelsRef.current = [];
    if (!isPicker || !selectedIds || selectedIds.length < 2) return;

    const pts = selectedIds
      .map((id) => complexes.find((c) => c.id === id))
      .filter((c): c is Complex => !!c)
      .map((c) => {
        const pos = correctedCoordsRef.current.get(c.id) ?? { lat: c.lat, lng: c.lng };
        return { lat: pos.lat, lng: pos.lng };
      });
    if (pts.length < 2) return;

    // polyline
    const line = new kakao.Polyline({
      path: pts.map((p) => new kakao.LatLng(p.lat, p.lng)),
      strokeWeight: 3,
      strokeColor: '#3182F6',
      strokeOpacity: 0.85,
      strokeStyle: 'solid',
    });
    line.setMap(map);
    pickerPolylineRef.current = line;

    // 각 leg 중간점에 거리 라벨
    function hm(a: { lat: number; lng: number }, b: { lat: number; lng: number }) {
      const R = 6371000;
      const dLat = ((b.lat - a.lat) * Math.PI) / 180;
      const dLng = ((b.lng - a.lng) * Math.PI) / 180;
      const la1 = (a.lat * Math.PI) / 180;
      const la2 = (b.lat * Math.PI) / 180;
      const x = Math.sin(dLat / 2) ** 2 + Math.cos(la1) * Math.cos(la2) * Math.sin(dLng / 2) ** 2;
      return 2 * R * Math.asin(Math.sqrt(x));
    }
    function fmtM(m: number) { return m >= 1000 ? `${(m / 1000).toFixed(1)}km` : `${Math.round(m)}m`; }
    for (let i = 0; i < pts.length - 1; i++) {
      const a = pts[i], b = pts[i + 1];
      const mid = { lat: (a.lat + b.lat) / 2, lng: (a.lng + b.lng) / 2 };
      const d = hm(a, b);
      const el = document.createElement('div');
      el.style.cssText = [
        'background:rgba(255,255,255,.95)',
        'border:1.5px solid #3182F6',
        'border-radius:10px',
        'padding:2px 7px',
        'font-size:10.5px',
        'font-weight:800',
        'color:#1456C7',
        'box-shadow:0 2px 6px rgba(17,24,39,.18)',
        'white-space:nowrap',
        'pointer-events:none',
      ].join(';');
      el.textContent = fmtM(d);
      const ov = new kakao.CustomOverlay({
        position: new kakao.LatLng(mid.lat, mid.lng),
        content: el,
        yAnchor: 0.5,
        xAnchor: 0.5,
        zIndex: 6,
      });
      ov.setMap(map);
      pickerLegLabelsRef.current.push(ov);
    }
  }, [isPicker, selectedIds, complexes, coordsTick, kakaoLoaded]);

  // 4) 선택된 단지 panTo
  useEffect(() => {
    const kakao = kakaoRef.current;
    const map = mapRef.current;
    if (!kakao || !map || !selectedComplexId) return;
    const c = complexById(complexes, selectedComplexId);
    if (!c) return;
    map.panTo(new kakao.LatLng(c.lat, c.lng));
  }, [selectedComplexId, complexes]);

  // 4.5) mapTarget(지역 검색 등 외부 trigger) 변경 시 지도 이동.
  //   - picker: 항상 즉시 적용
  //   - home: view='map'(지도 보일 때)만 적용. list 모드면 ResizeObserver가 visible 전환에서 처리하도록 mapTarget 유지.
  useEffect(() => {
    const kakao = kakaoRef.current;
    const map = mapRef.current;
    if (!kakao || !map || !mapTarget) return;
    if (!isPicker && view !== 'map') return;
    const target = mapTarget;
    // 다른 effect(me-effect, ResizeObserver, fitted)가 모두 fire된 후에 적용되도록 지연
    const t = window.setTimeout(() => {
      try {
        map.setCenter(new kakao.LatLng(target.lat, target.lng));
        map.setLevel(3);
        setMapTarget(null);
      } catch {/* noop */}
    }, 300);
    return () => window.clearTimeout(t);
  }, [mapTarget, kakaoLoaded, setMapTarget, isPicker, view]);

  function recenter() {
    if (!currentLatLng) return;
    if (USE_IFRAME_MAP) {
      userMovedRef.current = false; // 현위치 버튼 → 자동 내위치 follow 재개
      lastCenteredRef.current = { lat: currentLatLng.lat, lng: currentLatLng.lng };
      postToMap({ type: 'setCenter', lat: currentLatLng.lat, lng: currentLatLng.lng, level: 3 });
      return;
    }
    const kakao = kakaoRef.current;
    const map = mapRef.current;
    if (!kakao || !map || !currentLatLng) return;
    const pos = new kakao.LatLng(currentLatLng.lat, currentLatLng.lng);
    // setCenter로 즉시 화면 정중앙에 + 줌 적절히
    map.setCenter(pos);
    map.setLevel(3);
  }

  const showTopBar = !hideTopBar && !isPicker;
  const showFilterBar = !hideFilterBar && !isPicker;
  const showControls = !hideControls;
  const showMiniCard = !hideMiniCard && !isPicker;
  return (
    <div
      className={containerClassName ?? 'screen fade-in'}
      style={
        containerStyle
          ? { background: 'var(--map-land)', position: 'relative', ...containerStyle }
          : { background: 'var(--map-land)' }
      }
    >
      <style>{`
        @keyframes imjangPulse {
          0% { transform: scale(0.9); opacity: 0.55; }
          70% { transform: scale(2.4); opacity: 0; }
          100% { opacity: 0; }
        }
      `}</style>
      <style>{`
        /* 카카오 지도 타일만 톤 다운 — 마커(우리 CustomOverlay)는 영향 안 받음 */
        .kakao-map-bg > div:first-child { filter: grayscale(0.4) saturate(0.5) brightness(1.05) hue-rotate(-12deg) contrast(0.96); }
      `}</style>
      {USE_IFRAME_MAP ? (
        <iframe
          ref={iframeRef}
          title="지도"
          src={`${ENV.kakaoEmbedUrl}?appkey=${ENV.kakaoJsKey}&v=20260627k`}
          className="kakao-map-bg"
          style={{ position: 'absolute', inset: 0, width: '100%', height: '100%', border: 0 }}
        />
      ) : (
        <div
          ref={containerRef}
          className="kakao-map-bg"
          style={{ position: 'absolute', inset: 0 }}
        />
      )}
      {showControls && (
        <div
          className="map-controls"
          style={{
            bottom: sel
              ? 'calc(var(--safe-bottom, 0px) + 18px + 124px)'
              : 'calc(var(--safe-bottom, 0px) + 18px)',
          }}
        >
          <button
            className={'map-fab' + (trailOn ? ' on' : '')}
            onClick={() => setTrailOn((v) => !v)}
            type="button"
            title="동선"
          >
            <Icon name="foot" size={22} />
          </button>
          <button className="map-fab" onClick={recenter} type="button" title="현위치">
            <Icon name="target" size={22} />
          </button>
        </div>
      )}
      {/* picker 모드: 내 위치 버튼만 별도 노출 (containerStyle 안 absolute) */}
      {isPicker && (
        <button
          className="map-fab"
          onClick={recenter}
          type="button"
          title="현위치"
          style={{ position: 'absolute', right: 10, bottom: 10, zIndex: 8 }}
        >
          <Icon name="target" size={20} />
        </button>
      )}
      {showTopBar && <HomeTopBar floating />}
      {showFilterBar && <div
        style={{
          position: 'absolute',
          left: 8,
          right: 8,
          top: 'calc(var(--safe-top) + 130px)',
          zIndex: 7,
          background: 'rgba(255,255,255,.92)',
          backdropFilter: 'blur(12px)',
          borderRadius: 14,
          boxShadow: 'var(--sh-card)',
        }}
      >
        <FilterBar floating />
      </div>}
      {!isPicker && clusterPicker && (
        <div className="mini-card" key="cluster">
          <div className="row between" style={{ marginBottom: 8 }}>
            <div style={{ fontWeight: 800, fontSize: 14 }}>
              {`이 위치에 ${clusterPicker.length}곳`}
            </div>
            <button
              onClick={() => setClusterPicker(null)}
              style={{ color: 'var(--ink-3)', padding: 2 }}
              type="button"
            >
              <Icon name="x" size={18} />
            </button>
          </div>
          <div
            style={{
              display: 'flex',
              flexDirection: 'column',
              gap: 8,
              maxHeight: 260,
              overflow: 'auto',
            }}
          >
            {clusterPicker.map((p) => {
              const pr = repArea(p);
              return (
                <button
                  key={p.id}
                  onClick={() => {
                    setSelectedComplexId(p.id);
                    setClusterPicker(null);
                  }}
                  type="button"
                  style={{
                    display: 'flex',
                    alignItems: 'center',
                    gap: 10,
                    padding: '10px 12px',
                    background: 'var(--bg)',
                    borderRadius: 12,
                    textAlign: 'left',
                  }}
                >
                  <TypeChip type={p.type} />
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div
                      style={{
                        fontWeight: 800,
                        fontSize: 14,
                        whiteSpace: 'nowrap',
                        overflow: 'hidden',
                        textOverflow: 'ellipsis',
                      }}
                    >
                      {p.name}
                    </div>
                    <div
                      className="muted"
                      style={{ fontSize: 11.5, fontWeight: 600, marginTop: 2 }}
                    >
                      {`${pr.m2}㎡ ${wonText(pr.price)}`}
                      {p.households ? ` · ${p.households.toLocaleString()}세대` : ''}
                    </div>
                  </div>
                  <Icon name="chevR" size={16} />
                </button>
              );
            })}
          </div>
        </div>
      )}
      {showMiniCard && sel && !clusterPicker && (
        <div className="mini-card" key={sel.id}>
          <div className="row between">
            <div className="row gap6">
              <span className={'dist-badge' + (sel.near ? ' near' : '')}>
                {(sel.distM ?? 0) + 'm'}
              </span>
              <TypeChip type={sel.type} />
              {notes[sel.id] && <Stars rating={notes[sel.id]!.rating} />}
            </div>
            <button
              onClick={() => setSelectedComplexId(null)}
              style={{ color: 'var(--ink-3)', padding: 2 }}
              type="button"
            >
              <Icon name="x" size={18} />
            </button>
          </div>
          <div style={{ fontWeight: 700, fontSize: 16, marginTop: 8, letterSpacing: '-.02em' }}>
            {sel.name}
          </div>
          <div className="row between" style={{ marginTop: 8, alignItems: 'flex-end', gap: 10 }}>
            <div>
              {(() => {
                const prices = (sel.areas ?? [])
                  .map((a) => {
                    const last = a.trend?.[a.trend.length - 1];
                    return last?.last ?? last?.max ?? a.price;
                  })
                  .filter((p) => p > 0);
                if (prices.length === 0) {
                  return <span className="price-big num" style={{ fontSize: 15 }}>거래없음</span>;
                }
                const min = Math.min(...prices);
                const max = Math.max(...prices);
                const m2s = (sel.areas ?? []).map((a) => a.m2).filter((m) => m > 0);
                const minM2 = Math.min(...m2s);
                const maxM2 = Math.max(...m2s);
                return (
                  <>
                    <div className="price-cap">
                      {minM2 === maxM2 ? `${minM2}㎡` : `${minM2}~${maxM2}㎡`}
                    </div>
                    <span className="price-big num">
                      {min === max ? wonText(min) : `${wonText(min)}~${wonText(max)}`}
                    </span>
                  </>
                );
              })()}
            </div>
            <div className="row gap8">
              <button
                type="button"
                className={'save-pin' + (planIds.includes(sel.id) ? ' on' : '')}
                onClick={() => {
                  const inPlan = plans.find((p) => p.complexId === sel.id);
                  if (inPlan) void deletePlan(sel.id);
                  else
                    void savePlan({
                      complexId: sel.id,
                      complexName: sel.name,
                      complexType: sel.type,
                      lat: sel.lat,
                      lng: sel.lng,
                      memo: '',
                      done: false,
                      createdAt: Date.now(),
                    });
                }}
                title="담기"
              >
                <Icon name="bookmark" size={19} fill={planIds.includes(sel.id)} />
              </button>
              <button
                className="btn btn-primary btn-sm"
                style={{ width: 'auto', padding: '0 16px' }}
                onClick={() => openDetail(sel.id)}
                type="button"
              >
                상세
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
