import { useEffect, useRef } from 'react';
import { loadKakaoMaps, type KakaoMap, type KakaoCustomOverlay, type KakaoMaps } from '@/lib/kakaoMaps';
import { makeComplexMarkerEl, makeLegLabelEl } from '@/lib/mapMarkers';
import type { Complex } from '@/types/domain';

interface Stop {
  complex: Complex;
}

function distM(a: { lat: number; lng: number }, b: { lat: number; lng: number }): number {
  const R = 6371000;
  const dLat = ((b.lat - a.lat) * Math.PI) / 180;
  const dLng = ((b.lng - a.lng) * Math.PI) / 180;
  const la1 = (a.lat * Math.PI) / 180;
  const la2 = (b.lat * Math.PI) / 180;
  const x = Math.sin(dLat / 2) ** 2 + Math.cos(la1) * Math.cos(la2) * Math.sin(dLng / 2) ** 2;
  return 2 * R * Math.asin(Math.sqrt(x));
}

function fmtM(m: number): string {
  return m >= 1000 ? `${(m / 1000).toFixed(1)}km` : `${Math.round(m)}m`;
}

export function TripMap({
  stops,
  onClickStop,
  height = 190,
}: {
  stops: Stop[];
  onClickStop?: (id: string) => void;
  height?: number;
}) {
  const containerRef = useRef<HTMLDivElement | null>(null);
  const kakaoRef = useRef<KakaoMaps | null>(null);
  const mapRef = useRef<KakaoMap | null>(null);
  const markersRef = useRef<KakaoCustomOverlay[]>([]);
  const polylineRef = useRef<{ setMap: (m: unknown) => void } | null>(null);
  const legLabelsRef = useRef<KakaoCustomOverlay[]>([]);
  const onClickStopRef = useRef(onClickStop);
  const fittedRef = useRef(false);

  useEffect(() => {
    onClickStopRef.current = onClickStop;
  }, [onClickStop]);

  // 1) 지도 초기화 + ResizeObserver
  useEffect(() => {
    let cancelled = false;
    void (async () => {
      const kakao = await loadKakaoMaps();
      if (!kakao || cancelled) return;
      const el = containerRef.current;
      if (!el) return;
      kakaoRef.current = kakao;

      const valid = stops.filter((s) => Number.isFinite(s.complex.lat) && Number.isFinite(s.complex.lng));
      const center = valid.length
        ? new kakao.LatLng(valid[0].complex.lat, valid[0].complex.lng)
        : new kakao.LatLng(37.5665, 126.978);
      const map = new kakao.Map(el, { center, level: 3 });
      mapRef.current = map;

      let prevW = el.clientWidth, prevH = el.clientHeight;
      let relayoutTimer: number | null = null;
      const ro = new ResizeObserver(() => {
        try {
          const w = el.clientWidth, h = el.clientHeight;
          if (w === 0 || h === 0) { prevW = w; prevH = h; return; }
          if (w === prevW && h === prevH) return;
          const wasHidden = prevW === 0 || prevH === 0;
          prevW = w; prevH = h;
          if (relayoutTimer) window.clearTimeout(relayoutTimer);
          relayoutTimer = window.setTimeout(() => {
            try {
              map.relayout();
              if (wasHidden) map.setCenter(map.getCenter());
            } catch {/* noop */}
          }, 80);
        } catch {/* noop */}
      });
      ro.observe(el);
      (map as unknown as { __ro?: ResizeObserver }).__ro = ro;
    })();
    return () => {
      cancelled = true;
      const m = mapRef.current as unknown as { __ro?: ResizeObserver } | null;
      m?.__ro?.disconnect();
      markersRef.current.forEach((o) => o.setMap(null));
      markersRef.current = [];
      legLabelsRef.current.forEach((o) => o.setMap(null));
      legLabelsRef.current = [];
      polylineRef.current?.setMap(null);
      polylineRef.current = null;
      mapRef.current = null;
      fittedRef.current = false;
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // 2) 마커(시세 지도 형식) + polyline + leg 거리 라벨
  useEffect(() => {
    const kakao = kakaoRef.current as (KakaoMaps & {
      Polyline: new (opts: Record<string, unknown>) => { setMap: (m: unknown) => void };
    }) | null;
    const map = mapRef.current;
    if (!kakao || !map) return;

    markersRef.current.forEach((o) => o.setMap(null));
    markersRef.current = [];
    legLabelsRef.current.forEach((o) => o.setMap(null));
    legLabelsRef.current = [];
    polylineRef.current?.setMap(null);
    polylineRef.current = null;

    const valid = stops.filter((s) => Number.isFinite(s.complex.lat) && Number.isFinite(s.complex.lng));
    if (valid.length === 0) return;

    valid.forEach((s, i) => {
      const c = s.complex;
      const el = makeComplexMarkerEl(c, {
        order: i + 1,
        onClick: () => onClickStopRef.current?.(c.id),
      });
      const ov = new kakao.CustomOverlay({
        position: new kakao.LatLng(c.lat, c.lng),
        content: el,
        yAnchor: 1,
        xAnchor: 0.5,
        zIndex: 5,
        clickable: true,
      });
      ov.setMap(map);
      markersRef.current.push(ov);
    });

    if (valid.length >= 2) {
      const line = new kakao.Polyline({
        path: valid.map((s) => new kakao.LatLng(s.complex.lat, s.complex.lng)),
        strokeWeight: 3,
        strokeColor: '#3182F6',
        strokeOpacity: 0.85,
        strokeStyle: 'solid',
      });
      line.setMap(map);
      polylineRef.current = line;

      for (let i = 0; i < valid.length - 1; i++) {
        const a = valid[i].complex, b = valid[i + 1].complex;
        const mid = { lat: (a.lat + b.lat) / 2, lng: (a.lng + b.lng) / 2 };
        const labelEl = makeLegLabelEl(fmtM(distM(a, b)));
        const ov = new kakao.CustomOverlay({
          position: new kakao.LatLng(mid.lat, mid.lng),
          content: labelEl,
          yAnchor: 0.5,
          xAnchor: 0.5,
          zIndex: 6,
        });
        ov.setMap(map);
        legLabelsRef.current.push(ov);
      }
    }

    if (!fittedRef.current) {
      fittedRef.current = true;
      // 시세 지도와 동일한 level 3 통일 — 단지 여러 개일 때는 평균 좌표를 중심으로
      const avgLat = valid.reduce((s, x) => s + x.complex.lat, 0) / valid.length;
      const avgLng = valid.reduce((s, x) => s + x.complex.lng, 0) / valid.length;
      map.setCenter(new kakao.LatLng(avgLat, avgLng));
      map.setLevel(3);
    }
  }, [stops]);

  return (
    <>
      <style>{`
        /* 시세 지도와 동일한 톤다운 — 카카오 타일만 적용, 우리 CustomOverlay는 영향 없음 */
        .kakao-map-bg > div:first-child { filter: grayscale(0.4) saturate(0.5) brightness(1.05) hue-rotate(-12deg) contrast(0.96); }
      `}</style>
      <div
        ref={containerRef}
        className="kakao-map-bg"
        style={{ width: '100%', height: '100%', minHeight: height }}
      />
    </>
  );
}
