import type { Complex } from '@/types/domain';
import { getSupabase } from '@/lib/supabase';
import type { LatLng } from '@/lib/geo';

interface NearbyResult extends Complex {
  areaName?: string;
}

export interface NearbyFetchResult {
  areaName: string;          // 지역명 (단지 0개여도 채워짐)
  complexes: NearbyResult[];
}

// 좌표→법정동→RTMS 캐시 파이프라인.
// Supabase Edge Function 'rtms-fetch'에 좌표를 던지면 서버가:
//   1) Kakao coord2regioncode로 법정동코드 확인
//   2) RTMS API 호출 (apt/officetel/rowhouse)
//   3) 단지·평형 집계 후 캐시 저장
//   4) 가까운 N개 단지 목록 반환

// ===== 중복 호출 방지 =====
//   1) 50m 단위 좌표 양자화 — 1m 단위 GPS jitter는 같은 키로 묶임
//   2) 60초 TTL 결과 캐시 — 같은 양자화 키는 캐시에서 즉시 반환
//   3) inflight dedup — 동시에 들어온 같은 좌표 호출은 같은 promise 공유
//   4) 호출 카운터 — 콘솔로 실제 서버 호출 횟수 가시화

const QUANTUM_M = 200; // 200m 격자로 양자화 — 짧은 이동은 같은 키로 묶임
const CACHE_TTL_MS = 30 * 60_000; // 30분 메모리 캐시
const PERSIST_TTL_MS = 24 * 3600_000; // 24시간 localStorage 캐시 (즉시 표시용)
const cache = new Map<string, { result: NearbyFetchResult; at: number }>();
const inflight = new Map<string, Promise<NearbyFetchResult>>();
// v6: PostgREST LIKE * wildcard 버그 fix 후 — v5 캐시는 빈 응답 저장됐을 수 있어 stale.
const LS_PREFIX = 'imjang.rtms.v6.';

function lsRead(key: string): { result: NearbyFetchResult; at: number } | null {
  try {
    const raw = localStorage.getItem(LS_PREFIX + key);
    if (!raw) return null;
    const v = JSON.parse(raw);
    if (Date.now() - v.at > PERSIST_TTL_MS) return null;
    return v;
  } catch { return null; }
}
function lsWrite(key: string, result: NearbyFetchResult) {
  try {
    localStorage.setItem(LS_PREFIX + key, JSON.stringify({ result, at: Date.now() }));
  } catch { /* quota exceeded */ }
}
let serverCallCount = 0;
let cacheHitCount = 0;

// ===== Rate limit (무한루프 차단용 안전장치) =====
// rtms-fetch는 외부 API가 아닌 Supabase Edge Function의 DB read이지만,
// 비정상 케이스(useEffect dependency loop 등)로 폭주 시 Supabase invocation quota 소진 위험.
// 한도는 정상 사용 충분 + 무한루프 차단 기준.
const RATE_LIMIT_PER_MIN = 60;       // 분당 60회 (정상: 1-5회, 무한루프 차단)
const SESSION_HARD_CAP = 500;        // 세션 500회 (정상 임장 1회: 20-50회)
const BURST_WINDOW_MS = 1000;
const BURST_THRESHOLD = 15;          // 1초 15회 초과 → 무한루프 의심 (HMR·탭 전환 false positive 방지)
const SESSION_BLOCK_RECOVERY_MS = 30_000; // 세션 차단 30초 후 자동 복구 (개발 환경 영구 차단 방지)
const callTimes: number[] = [];
let sessionTotalCalls = 0;
let sessionBlocked = false;
let sessionBlockedAt = 0;

function checkRateLimit(): { ok: boolean; reason?: string } {
  // 차단 자동 복구
  if (sessionBlocked && Date.now() - sessionBlockedAt > SESSION_BLOCK_RECOVERY_MS) {
    sessionBlocked = false;
    callTimes.length = 0;
    console.info('[rtms-fetch] 세션 차단 자동 복구');
  }
  if (sessionBlocked) return { ok: false, reason: '세션 차단됨 (burst 감지) — 자동 복구 대기' };
  const now = Date.now();
  while (callTimes.length > 0 && now - callTimes[0] > 60_000) callTimes.shift();
  if (callTimes.length >= RATE_LIMIT_PER_MIN) {
    return { ok: false, reason: `분당 ${RATE_LIMIT_PER_MIN}회 초과 (현재 ${callTimes.length})` };
  }
  const burst = callTimes.filter((t) => now - t < BURST_WINDOW_MS).length;
  if (burst >= BURST_THRESHOLD) {
    sessionBlocked = true;
    sessionBlockedAt = Date.now();
    console.error(`[rtms-fetch] 🚨 burst 감지: ${BURST_WINDOW_MS}ms 내 ${burst}회 호출 → 세션 ${SESSION_BLOCK_RECOVERY_MS/1000}초 차단`);
    return { ok: false, reason: `burst ${burst}/1s — 세션 차단` };
  }
  if (sessionTotalCalls >= SESSION_HARD_CAP) {
    return { ok: false, reason: `세션 누적 ${SESSION_HARD_CAP}회 한도 초과` };
  }
  return { ok: true };
}

function recordCall() {
  callTimes.push(Date.now());
  sessionTotalCalls++;
}

function quantizeKey(pos: LatLng): string {
  // 위도 1도 ≈ 111.32km. 정수 격자 인덱스로 묶어 부동소수점 비교 회피.
  const step = QUANTUM_M / 111320;
  const qlat = Math.round(pos.lat / step);
  const qlng = Math.round(pos.lng / step);
  return `${qlat},${qlng}`;
}

const EMPTY: NearbyFetchResult = { areaName: '', complexes: [] };

export async function fetchNearbyComplexes(
  pos: LatLng,
  opts: { radiusM?: number; force?: boolean } = {},
): Promise<NearbyFetchResult> {
  const sb = getSupabase();
  if (!sb) return EMPTY;
  const radiusM = opts.radiusM ?? 1500;

  if (opts.force) {
    serverCallCount++;
    console.debug(`[rtms] force 호출 #${serverCallCount} (cache hit ${cacheHitCount}회)`);
    return actualFetch(pos, radiusM);
  }

  const key = quantizeKey(pos);

  // 1) 메모리 캐시 hit
  const cached = cache.get(key);
  if (cached && Date.now() - cached.at < CACHE_TTL_MS) {
    cacheHitCount++;
    return cached.result;
  }

  // 1b) localStorage hit — 즉시 반환 + 백그라운드 갱신 (stale-while-revalidate)
  const persisted = lsRead(key);
  if (persisted) {
    cacheHitCount++;
    cache.set(key, persisted);
    // 백그라운드 갱신 — UI 차단 X
    if (!inflight.has(key)) {
      const bg = actualFetch(pos, radiusM)
        .then((fresh) => {
          if (fresh.complexes.length > 0 || fresh.areaName) {
            cache.set(key, { result: fresh, at: Date.now() });
            lsWrite(key, fresh);
          }
          return fresh;
        })
        .finally(() => inflight.delete(key));
      inflight.set(key, bg);
    }
    return persisted.result;
  }

  // 2) inflight dedup
  const pending = inflight.get(key);
  if (pending) {
    cacheHitCount++;
    return pending;
  }

  // 3) 새 호출
  serverCallCount++;
  console.debug(`[rtms] 서버 호출 #${serverCallCount} key=${key} (캐시 ${cache.size}건, 진행 중 ${inflight.size}건)`);
  const p = actualFetch(pos, radiusM)
    .then((result) => {
      cache.set(key, { result, at: Date.now() });
      if (result.complexes.length > 0 || result.areaName) lsWrite(key, result);
      return result;
    })
    .finally(() => {
      inflight.delete(key);
    });
  inflight.set(key, p);
  return p;
}

async function actualFetch(pos: LatLng, radiusM: number): Promise<NearbyFetchResult> {
  const sb = getSupabase();
  if (!sb) return EMPTY;
  // Rate limit 점검 (양자화·캐시·inflight 모두 우회 시 최후 안전장치)
  const gate = checkRateLimit();
  if (!gate.ok) {
    console.warn(`[rtms-fetch] 차단됨: ${gate.reason}`);
    return EMPTY;
  }
  recordCall();
  try {
    const { data, error } = await sb.functions.invoke<{
      area: { name: string };
      complexes: Complex[];
    }>('rtms-fetch', { body: { lat: pos.lat, lng: pos.lng, radiusM } });
    if (error) throw error;
    if (!data) return EMPTY;
    const areaName = data.area?.name ?? '';
    // K-APT 마스킹 단지(이름에 * 포함된 다가구) 클라이언트 fallback 필터
    const complexes = data.complexes
      .filter((c) => !c.name?.includes('*'))
      .map((c) => ({ ...c, areaName }));
    return { areaName, complexes };
  } catch (e) {
    console.warn('rtms-fetch 실패:', e);
    return EMPTY;
  }
}

/** 디버그용 — 현재 호출 통계 */
export function getRtmsCallStats() {
  return {
    serverCalls: serverCallCount,
    cacheHits: cacheHitCount,
    cacheSize: cache.size,
    inflight: inflight.size,
  };
}

/** 주소를 "시도 구 동 번지"로 축약 (건물명 등 뒤쪽 토큰 제거) */
function shortAddr(road?: string | null, jibun?: string | null): string {
  const a = (jibun || road || '').trim();
  if (!a) return '';
  const t = a.split(/\s+/);
  const out = t.slice(0, 3); // 시도 구 동(읍/면)
  if (t[3] && /^\d/.test(t[3])) out.push(t[3]); // 번지
  return out.join(' ');
}

/** 단지 id로 이름·유형·주소 조회 (임장노트 기록 리스트 — 주변목록에 없는 단지도 해석) */
export async function loadComplexNames(
  ids: string[],
): Promise<Map<string, { name: string; type: string; addr: string }>> {
  const out = new Map<string, { name: string; type: string; addr: string }>();
  const sb = getSupabase();
  if (!sb || ids.length === 0) return out;
  const { data, error } = await sb.rpc('complex_cards_by_ids', { ids });
  if (error || !data) {
    if (error) console.warn('[prices] 단지 정보 조회 실패:', error.message);
    return out;
  }
  for (const r of data as { id: string; name: string; type: string; road_addr: string | null; jibun_addr: string | null }[]) {
    out.set(r.id, { name: r.name, type: r.type, addr: shortAddr(r.road_addr, r.jibun_addr) });
  }
  return out;
}
