import { useEffect, useRef, useState } from 'react';
import { Icon } from '@/components/Icon';
import { Avatar } from '@/components/Avatar';
import { useApp } from '@/store/AppStore';
import { usePlanComments } from '@/hooks/usePlanComments';
import { colorFromId } from '@/services/collab';

interface Props {
  batchId: string;
  label: string;
}

function timeLabel(ts: number): string {
  const diff = Date.now() - ts;
  if (diff < 60_000) return '방금';
  if (diff < 3600_000) return `${Math.floor(diff / 60_000)}분 전`;
  const d = new Date(ts);
  return `${d.getMonth() + 1}.${d.getDate()} ${String(d.getHours()).padStart(2, '0')}:${String(d.getMinutes()).padStart(2, '0')}`;
}

export function PlanChat({ batchId, label }: Props) {
  const { user, popOverlay, markPlanRead } = useApp();
  const { comments, send, displayAuthor } = usePlanComments(batchId);
  const [draft, setDraft] = useState('');
  const scrollRef = useRef<HTMLDivElement | null>(null);

  // 새 메모가 들어오면(또는 최초 로드 시) 항상 맨 아래로 스크롤
  useEffect(() => {
    const el = scrollRef.current;
    if (el) el.scrollTop = el.scrollHeight;
  }, [comments.length]);

  // 채팅을 떠날 때 읽음 처리 — 보는 동안 도착한 메모까지 NEW 해제
  useEffect(() => {
    return () => {
      if (batchId) markPlanRead(batchId);
    };
  }, [batchId, markPlanRead]);

  async function onSend() {
    const ok = await send(draft);
    if (ok) setDraft('');
  }

  return (
    <div className="screen push-enter" style={{ background: 'var(--bg)', display: 'flex', flexDirection: 'column' }}>
      <div className="navbar flush">
        <button className="backbtn" onClick={popOverlay} type="button">
          <Icon name="back" size={22} />
        </button>
        <div
          style={{
            fontWeight: 800,
            fontSize: 16,
            letterSpacing: '-.02em',
            overflow: 'hidden',
            textOverflow: 'ellipsis',
            whiteSpace: 'nowrap',
          }}
        >
          {label || '멤버 메모'}
        </div>
        <div className="grow" />
      </div>
      <div ref={scrollRef} className="scroll" style={{ flex: 1, paddingTop: 10 }}>
        <div className="pad">
          {comments.length === 0 ? (
            <div className="card" style={{ padding: '28px 0', textAlign: 'center' }}>
              <div className="muted" style={{ fontSize: 12.5, fontWeight: 600 }}>아직 멤버 메모가 없어요</div>
              <div className="muted" style={{ fontSize: 12, fontWeight: 600, marginTop: 4 }}>첫 메모를 남겨보세요</div>
            </div>
          ) : (
            comments.map((c) => {
              const mine = !!user && c.authorId === user.id;
              const authorLabel = displayAuthor(c.authorId, c.authorName);
              return (
                <div key={c.id} className="cmt-wrap">
                  <div className={'cmt' + (mine ? ' me' : '')}>
                    {!mine && (
                      <Avatar m={{ id: c.authorId, name: authorLabel, color: colorFromId(c.authorId) }} size={30} />
                    )}
                    <div className="cmt-body">
                      <div className="cmt-meta">
                        <span className="cmt-name">{mine ? '나' : authorLabel}</span>
                        <span className="cmt-time">{timeLabel(c.createdAt)}</span>
                      </div>
                      <div className={'cmt-bubble' + (mine ? ' me' : '')}>{c.text}</div>
                    </div>
                  </div>
                </div>
              );
            })
          )}
          <div style={{ height: 12 }} />
        </div>
      </div>
      <div style={{ flex: '0 0 auto' }}>
        <div className="cmt-bar">
          <input
            className="cmt-input"
            placeholder="멤버에게 메모 남기기"
            value={draft}
            onChange={(e) => setDraft(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === 'Enter') void onSend();
            }}
          />
          <button
            type="button"
            className={'cmt-send' + (draft.trim() ? ' on' : '')}
            onClick={() => void onSend()}
          >
            <Icon name="arrowR" size={18} stroke={2.4} />
          </button>
        </div>
      </div>
    </div>
  );
}
