import { Icon } from './Icon';

interface StarsProps {
  rating?: number;
  size?: 'sm' | 'lg';
  interactive?: boolean;
  onRate?: (n: number) => void;
}

export function Stars({ rating = 0, size, interactive = false, onRate }: StarsProps) {
  return (
    <div className={'stars' + (size === 'lg' ? ' lg' : '')}>
      {[1, 2, 3, 4, 5].map((i) => {
        const filled = i <= Math.round(rating);
        return (
          <span
            key={i}
            onClick={
              interactive
                ? (e) => {
                    e.stopPropagation();
                    onRate?.(i);
                  }
                : undefined
            }
            style={{
              cursor: interactive ? 'pointer' : 'default',
              lineHeight: 0,
              padding: interactive ? '2px' : 0,
            }}
          >
            <Icon
              name="star"
              fill={filled}
              size={size === 'lg' ? (interactive ? 34 : 26) : 15}
              color={filled ? 'var(--gold)' : 'var(--line-strong)'}
            />
          </span>
        );
      })}
    </div>
  );
}
