import { useEffect, useState } from 'react';
import { Icon } from '@/components/Icon';
import { Avatar, type Member } from '@/components/Avatar';
import { useApp } from '@/store/AppStore';
import { loadPlanMembers } from '@/services/collab';
import { tryShareOrCopy } from './Friends';

interface Props {
  sessionLabel?: string;
  members: Member[];
  /** 있으면 멤버를 직접 로드/갱신 (prop 타이밍 의존 제거) */
  batchId?: string;
  /** 초대 링크 생성 (계획/친구). 반환된 URL을 공유/복사한다. */
  onCreateInviteLink?: () => Promise<string | null>;
  /** 친구를 계획에 바로 초대 (성공 시 true). 제공되면 친구 목록을 표시한다. */
  onInviteFriend?: (friendId: string) => Promise<boolean>;
  onClose: () => void;
}

export function ShareSheet({ sessionLabel, members, batchId, onCreateInviteLink, onInviteFriend, onClose }: Props) {
  const { showToast, friends } = useApp();
  const [busy, setBusy] = useState(false);
  // batchId가 있으면 시트가 직접 멤버를 로드/갱신 (부모 prop 타이밍 무관)
  const [memberList, setMemberList] = useState<Member[]>(members);
  useEffect(() => {
    if (!batchId) return;
    let alive = true;
    void loadPlanMembers(batchId).then((m) => { if (alive) setMemberList(m); });
    return () => { alive = false; };
  }, [batchId]);
  const shown = batchId ? memberList : members;
  const memberStatus = new Map(shown.map((m) => [m.id, m.pending ? 'pending' : 'joined']));

  async function inviteFriend(id: string, name: string) {
    if (!onInviteFriend) return;
    const ok = await onInviteFriend(id);
    if (ok) {
      showToast(`${name}님을 초대했어요`);
      if (batchId) setMemberList(await loadPlanMembers(batchId));
    } else {
      showToast('초대에 실패했어요');
    }
  }

  async function handleInvite() {
    if (!onCreateInviteLink) return;
    setBusy(true);
    try {
      const link = await onCreateInviteLink();
      if (!link) {
        showToast('초대 링크를 만들지 못했어요');
        return;
      }
      const r = await tryShareOrCopy(link, '단지노트 함께 임장 초대');
      showToast(r === 'share' ? '초대 링크를 공유했어요' : '초대 링크를 복사했어요');
    } finally {
      setBusy(false);
    }
  }

  return (
    <div className="sheet-scrim" onClick={onClose} style={{ zIndex: 120 }}>
      <div className="filter-sheet" onClick={(e) => e.stopPropagation()} style={{ maxHeight: '90%', overflowY: 'auto' }}>
        <div className="sheet-grip" />
        <div className="row between" style={{ marginBottom: 4, padding: '0 2px' }}>
          <div style={{ fontWeight: 800, fontSize: 18, letterSpacing: '-.02em' }}>함께 임장</div>
          <button
            type="button"
            onClick={onClose}
            style={{ color: 'var(--ink-3)', padding: 4, background: 'none', border: 'none', cursor: 'pointer' }}
          >
            <Icon name="x" size={20} />
          </button>
        </div>
        {sessionLabel && (
          <div className="share-ctx">
            <Icon name="build" size={13} stroke={2.2} />
            {sessionLabel + ' 함께 보기'}
          </div>
        )}
        <div
          className="muted"
          style={{ fontSize: 12.5, fontWeight: 600, margin: '10px 0 18px', padding: '0 2px', lineHeight: 1.5 }}
        >
          링크로 초대하면 함께 보는 사람끼리 멤버 메모를 실시간으로 공유해요.
          {' '}받은 사람은 로그인 없이도 바로 참여할 수 있어요.
        </div>
        <div className="sect-cap" style={{ marginBottom: 8, marginLeft: 2 }}>
          {`멤버 ${shown.length}명`}
        </div>
        <div className="card" style={{ padding: '4px 14px', marginBottom: 20 }}>
          {shown.length === 0 && (
            <div className="muted" style={{ padding: '20px 0', textAlign: 'center', fontSize: 12.5, fontWeight: 600 }}>
              아직 멤버가 없어요
            </div>
          )}
          {shown.map((m, i) => (
            <div key={m.id} className={'member-row' + (i ? ' br' : '')}>
              <Avatar m={m} size={36} />
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ fontWeight: 700, fontSize: 14 }}>{m.name}</div>
                {m.pending && (
                  <div className="muted" style={{ fontSize: 11.5, fontWeight: 600, marginTop: 1 }}>
                    초대중
                  </div>
                )}
              </div>
            </div>
          ))}
        </div>
        {onInviteFriend && friends.length > 0 && (
          <>
            <div className="sect-cap" style={{ marginBottom: 8, marginLeft: 2 }}>친구 초대</div>
            <div className="card" style={{ padding: '4px 14px', marginBottom: 16 }}>
              {friends.map((f, i) => {
                const st = memberStatus.get(f.id);
                const done = st != null; // 이미 멤버(초대중/참여중)면 버튼 비활성
                const label = st === 'pending' ? '초대중' : st === 'joined' ? '참여 중' : '초대';
                return (
                  <div key={f.id} className={'member-row' + (i ? ' br' : '')}>
                    <Avatar m={f} size={34} />
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{ fontWeight: 700, fontSize: 14, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
                        {f.name}
                      </div>
                      <div className="num muted" style={{ fontSize: 11, fontWeight: 600, marginTop: 1 }}>
                        {f.id.slice(0, 8)}
                      </div>
                    </div>
                    <button
                      type="button"
                      className="plan-member-btn"
                      disabled={done}
                      onClick={() => void inviteFriend(f.id, f.name)}
                      style={done ? { background: 'var(--surface-2)', color: 'var(--ink-3)' } : undefined}
                    >
                      {label}
                    </button>
                  </div>
                );
              })}
            </div>
          </>
        )}
        {onCreateInviteLink && (
          <button
            type="button"
            className="btn btn-primary"
            style={{ marginBottom: 14 }}
            disabled={busy}
            onClick={() => void handleInvite()}
          >
            <Icon name="share" size={17} stroke={2.2} />
            초대 링크 만들기
          </button>
        )}
      </div>
    </div>
  );
}
