import { Icon } from '@/components/Icon';
import { Stars } from '@/components/Stars';
import { TypeChip } from '@/components/Toast';
import { MapScene, TrailLayer } from '@/components/MapScene';
import { useApp, repArea, complexById } from '@/store/AppStore';
import { wonShort } from '@/lib/format';

export function SessionDetail({ id }: { id: string }) {
  const { sessions, complexes, notes, popOverlay, openCompare, openNote, showToast } = useApp();
  const s = sessions.find((x) => x.id === id);
  if (!s) return null;

  const visited = s.complexIds
    .map((cid) => complexById(complexes, cid))
    .filter((c): c is NonNullable<typeof c> => !!c);

  const rated = visited
    .map((c) => notes[c.id])
    .filter((n): n is NonNullable<typeof n> => !!n && !!n.rating);
  const avg = rated.length ? rated.reduce((a, n) => a + n.rating, 0) / rated.length : 0;

  const trailFallback: [number, number][] = s.trail ?? [];

  return (
    <div className="screen push-enter" style={{ background: 'var(--bg)' }}>
      <div className="navbar flush">
        <button className="backbtn" onClick={popOverlay} type="button">
          <Icon name="back" size={22} />
        </button>
        <h2>{s.dateLabel ?? s.date}</h2>
        <div className="grow" />
        <button
          className="backbtn"
          onClick={() => showToast('세션 요약을 이미지로 내보냈어요')}
          type="button"
        >
          <Icon name="share" size={20} />
        </button>
      </div>
      <div className="scroll pad" style={{ paddingTop: 4 }}>
        <div
          className="row gap4"
          style={{ marginBottom: 12, color: 'var(--ink-3)', fontWeight: 700, fontSize: 13.5 }}
        >
          <Icon name="loc" size={14} color="var(--ink-4)" /> {s.areaName}
        </div>
        <div className="card" style={{ padding: '16px 8px', marginBottom: 14 }}>
          <div className="stat-3">
            <div className="s">
              <div className="stat-val num">{visited.length}</div>
              <div className="stat-lab">방문 단지</div>
            </div>
            <div className="s">
              <div className="stat-val num">{(s.distanceM / 1000).toFixed(1) + 'km'}</div>
              <div className="stat-lab">총 이동거리</div>
            </div>
            <div className="s">
              <div className="stat-val num">{s.durationMin + '분'}</div>
              <div className="stat-lab">소요시간</div>
            </div>
          </div>
        </div>
        <div
          style={{
            position: 'relative',
            height: 220,
            borderRadius: 18,
            overflow: 'hidden',
            boxShadow: 'var(--sh-card)',
            marginBottom: 8,
          }}
        >
          <MapScene dim>
            {trailFallback.length >= 2 && <TrailLayer points={trailFallback} />}
            {visited.map((c) => {
              const n = notes[c.id];
              const mx = c.mx ?? 0.5;
              const my = c.my ?? 0.5;
              return (
                <div
                  key={c.id}
                  className="map-marker"
                  style={{ left: mx * 100 + '%', top: my * 100 + '%' }}
                >
                  <div
                    className={'price-pin' + (n ? ' noted' : '')}
                    style={{ padding: '4px 7px', fontSize: 11 }}
                  >
                    {n && <Icon name="star" size={10} fill color="var(--gold)" />}
                    {wonShort(repArea(c).price)}
                  </div>
                </div>
              );
            })}
            {trailFallback.length > 0 && (
              <div
                className="map-marker"
                style={{
                  left: trailFallback[0][0] * 100 + '%',
                  top: trailFallback[0][1] * 100 + '%',
                  zIndex: 6,
                }}
              >
                <div
                  style={{
                    background: 'var(--ink)',
                    color: '#fff',
                    borderRadius: 999,
                    padding: '3px 8px',
                    fontSize: 10,
                    fontWeight: 800,
                  }}
                >
                  출발
                </div>
              </div>
            )}
          </MapScene>
        </div>
        <div className="sect-cap" style={{ textAlign: 'center', marginBottom: 16 }}>
          점선은 임장 동선(발자취)이에요
        </div>
        <div className="sect-title" style={{ marginBottom: 8 }}>
          방문한 단지 {visited.length}
        </div>
        {visited.map((c) => {
          const n = notes[c.id];
          return (
            <div
              key={c.id}
              className="card"
              style={{ padding: 14, marginBottom: 8, display: 'flex', alignItems: 'center', gap: 12 }}
              onClick={() => openNote(c.id)}
            >
              <div style={{ flex: 1 }}>
                <div className="row gap6">
                  <TypeChip type={c.type} />
                  {n && <Stars rating={n.rating} />}
                </div>
                <div style={{ fontWeight: 700, fontSize: 14, marginTop: 6 }}>{c.name}</div>
                {n?.oneliner && (
                  <div
                    className="muted"
                    style={{
                      fontSize: 12,
                      fontWeight: 600,
                      marginTop: 3,
                      overflow: 'hidden',
                      textOverflow: 'ellipsis',
                      whiteSpace: 'nowrap',
                    }}
                  >
                    {n.oneliner}
                  </div>
                )}
              </div>
              <div style={{ textAlign: 'right' }}>
                <div className="price-big num" style={{ fontSize: 15 }}>
                  {wonShort(repArea(c).price)}
                </div>
                <div className="price-cap">{repArea(c).m2 + '㎡'}</div>
              </div>
              <Icon name="chevR" size={18} color="var(--ink-4)" />
            </div>
          );
        })}
        <div style={{ height: 18 }} />
      </div>
      <div
        style={{
          padding: '10px 20px calc(env(safe-area-inset-bottom) + 18px)',
          background: 'var(--bg)',
          borderTop: '1px solid var(--line)',
        }}
      >
        <button className="btn btn-primary" onClick={() => openCompare(id)} type="button">
          <Icon name="compare" size={20} />
          단지 비교하기
        </button>
      </div>
    </div>
  );
}
