export const ENV = {
  supabaseUrl: import.meta.env.VITE_SUPABASE_URL ?? '',
  supabaseAnonKey: import.meta.env.VITE_SUPABASE_ANON_KEY ?? '',
  kakaoJsKey: import.meta.env.VITE_KAKAO_JAVASCRIPT_KEY ?? '',
  // iOS WKWebView는 origin이 capacitor://localhost라 Kakao Maps JS SDK 도메인검증(referer)에 걸림.
  // → iOS에서만 등록된 https origin에 호스팅한 지도 페이지를 iframe으로 로드(postMessage 브리지).
  // 이 origin(https://lasidos.github.io)은 Kakao JS SDK 도메인에 등록돼 있어야 함.
  kakaoEmbedUrl: import.meta.env.VITE_KAKAO_EMBED_URL ?? 'https://lasidos.github.io/imjang-map/',
};

export const hasSupabase = () =>
  !!ENV.supabaseUrl && !!ENV.supabaseAnonKey;

export const hasKakaoMaps = () => !!ENV.kakaoJsKey;
