interface IconProps {
  name: string;
  size?: number;
  stroke?: number;
  fill?: boolean;
  color?: string;
  style?: CSSProperties;
}

export function Icon({ name, size = 22, stroke = 1.9, fill = false, color, style }: IconProps) {
  const d = ICONS[name] ?? '';
  const segments = d.split(' M');
  return (
    <svg
      width={size}
      height={size}
      viewBox="0 0 24 24"
      fill={fill ? 'currentColor' : 'none'}
      stroke={fill ? 'none' : 'currentColor'}
      strokeWidth={stroke}
      strokeLinecap="round"
      strokeLinejoin="round"
      style={{ color, ...style }}
    >
      {segments.map((seg, i) => (
        <path key={i} d={(i ? 'M' : '') + seg} />
      ))}
    </svg>
  );
}
