import type { Complex, ComplexFilter } from '@/types/domain';

/**
 * 단지 목록에 ComplexFilter 적용.
 * - types: 빈 배열이면 전체 통과
 * - priceMin/Max: c.rep (만원 단위) 기준 범위
 * - householdsMin/Max: c.households 기준 범위 (null이면 통과 조건에 따라)
 */
export function applyComplexFilter<T extends Complex>(
  complexes: T[],
  filter: ComplexFilter,
): T[] {
  return complexes.filter((c) => {
    if (filter.types.length > 0 && !filter.types.includes(c.type)) return false;
    if (filter.priceMin != null && c.rep < filter.priceMin) return false;
    if (filter.priceMax != null && c.rep > filter.priceMax) return false;
    if (filter.householdsMin != null && (c.households ?? 0) < filter.householdsMin) return false;
    if (filter.householdsMax != null && c.households != null && c.households > filter.householdsMax) return false;
    return true;
  });
}
