import type { ImjangPlan, PropertyType } from '@/types/domain';
import { getSupabase } from '@/lib/supabase';
import { Preferences } from '@capacitor/preferences';

const LOCAL_KEY = 'imjang_plans_v1';

interface DbRow {
  complex_id: string;
  complex_name: string;
  complex_type: PropertyType;
  lat: number | null;
  lng: number | null;
  planned_date: string | null;
  memo: string;
  done: boolean;
  created_at: string;
  batch_id: string | null;
}

function rowToPlan(r: DbRow): ImjangPlan {
  return {
    complexId: r.complex_id,
    complexName: r.complex_name,
    complexType: r.complex_type,
    lat: r.lat ?? undefined,
    lng: r.lng ?? undefined,
    plannedDate: r.planned_date ?? undefined,
    memo: r.memo,
    done: r.done,
    createdAt: new Date(r.created_at).getTime(),
    batchId: r.batch_id ?? undefined,
  };
}

export async function loadPlansForUser(userId: string | null): Promise<ImjangPlan[]> {
  const sb = getSupabase();
  if (sb && userId) {
    try {
      const { data, error } = await sb
        .from('imjang_plans')
        .select('complex_id, complex_name, complex_type, lat, lng, planned_date, memo, done, created_at, batch_id')
        .eq('user_id', userId)
        .order('planned_date', { ascending: true, nullsFirst: false })
        .order('created_at', { ascending: false });
      if (error) throw error;
      return (data ?? []).map(rowToPlan);
    } catch (e) {
      console.warn('계획 로드 실패, 로컬 사용', e);
    }
  }
  const stored = await Preferences.get({ key: LOCAL_KEY });
  if (!stored.value) return [];
  try {
    return JSON.parse(stored.value) as ImjangPlan[];
  } catch {
    return [];
  }
}

async function saveLocal(plans: ImjangPlan[]): Promise<void> {
  await Preferences.set({ key: LOCAL_KEY, value: JSON.stringify(plans) });
}

/**
 * 익명(로그아웃) 상태에서 로컬 Preferences에 저장한 임장 계획을 로그인 계정으로 이전.
 * 로그인 직후 1회 호출. 성공 시에만 로컬을 비워(실패하면 보존) 데이터 유실 방지.
 * upsert(onConflict user_id,batch_id,complex_id)라 같은 (계획,단지)만 덮어쓰기.
 */
export async function migrateLocalPlansToUser(userId: string): Promise<boolean> {
  const sb = getSupabase();
  if (!sb || !userId) return false;
  const stored = await Preferences.get({ key: LOCAL_KEY });
  if (!stored.value) return false;
  let local: ImjangPlan[];
  try {
    local = JSON.parse(stored.value) as ImjangPlan[];
  } catch {
    await Preferences.remove({ key: LOCAL_KEY });
    return false;
  }
  if (!Array.isArray(local) || local.length === 0) {
    await Preferences.remove({ key: LOCAL_KEY });
    return false;
  }
  try {
    const rows = local.map((p) => ({
      user_id: userId,
      complex_id: p.complexId,
      complex_name: p.complexName,
      complex_type: p.complexType,
      lat: p.lat ?? null,
      lng: p.lng ?? null,
      planned_date: p.plannedDate ?? null,
      memo: p.memo,
      done: p.done,
      batch_id: planBatchId(p),
    }));
    const { error } = await sb
      .from('imjang_plans')
      .upsert(rows, { onConflict: 'user_id,batch_id,complex_id' });
    if (error) throw error;
    await Preferences.remove({ key: LOCAL_KEY }); // 이전 완료 → 로컬 정리
    return true;
  } catch (e) {
    console.warn('익명 계획 계정 이전 실패, 로컬 보존:', e);
    return false;
  }
}

/** batchId 보장 — 누락 시 complexId 기반 legacy batch (구버전 단일 계획 호환) */
export function planBatchId(p: { batchId?: string; complexId: string }): string {
  return p.batchId ?? 'legacy-' + p.complexId;
}

/** 계획 단지 추가/수정. 식별: (batch_id, complex_id) — 같은 단지가 여러 계획에 독립 존재. */
export async function upsertPlan(
  userId: string | null,
  plan: ImjangPlan,
  existing: ImjangPlan[],
): Promise<ImjangPlan[]> {
  const bid = planBatchId(plan);
  const norm = { ...plan, batchId: bid };
  // 같은 (batch, 단지)만 교체 — 다른 계획의 같은 단지는 건드리지 않음
  const next = existing
    .filter((p) => !(planBatchId(p) === bid && p.complexId === plan.complexId))
    .concat(norm);
  const sb = getSupabase();
  if (sb && userId) {
    try {
      const { error } = await sb.from('imjang_plans').upsert(
        {
          user_id: userId,
          complex_id: plan.complexId,
          complex_name: plan.complexName,
          complex_type: plan.complexType,
          lat: plan.lat ?? null,
          lng: plan.lng ?? null,
          planned_date: plan.plannedDate ?? null,
          memo: plan.memo,
          done: plan.done,
          batch_id: bid,
        },
        { onConflict: 'user_id,batch_id,complex_id' },
      );
      if (error) throw error;
      return next;
    } catch (e) {
      console.warn('계획 저장 실패, 로컬에 저장', e);
    }
  }
  await saveLocal(next);
  return next;
}

/** 한 계획(batch)에서 단지 하나만 제거 (코스에서 단지 빼기) */
export async function removePlanItem(
  userId: string | null,
  batchId: string,
  complexId: string,
  existing: ImjangPlan[],
): Promise<ImjangPlan[]> {
  const next = existing.filter(
    (p) => !(planBatchId(p) === batchId && p.complexId === complexId),
  );
  const sb = getSupabase();
  if (sb && userId) {
    try {
      const { error } = await sb
        .from('imjang_plans')
        .delete()
        .eq('user_id', userId)
        .eq('batch_id', batchId)
        .eq('complex_id', complexId);
      if (error) throw error;
      return next;
    } catch (e) {
      console.warn('계획 단지 삭제 실패, 로컬에 반영', e);
    }
  }
  await saveLocal(next);
  return next;
}

/** 계획(batch) 전체 삭제 */
export async function removePlanBatch(
  userId: string | null,
  batchId: string,
  existing: ImjangPlan[],
): Promise<ImjangPlan[]> {
  const next = existing.filter((p) => planBatchId(p) !== batchId);
  const sb = getSupabase();
  if (sb && userId) {
    try {
      const { error } = await sb
        .from('imjang_plans')
        .delete()
        .eq('user_id', userId)
        .eq('batch_id', batchId);
      if (error) throw error;
      return next;
    } catch (e) {
      console.warn('계획 삭제 실패, 로컬에 반영', e);
    }
  }
  await saveLocal(next);
  return next;
}

/** 단지를 모든 계획에서 제거 (지도/상세 북마크 토글 off) */
export async function removePlanByComplex(
  userId: string | null,
  complexId: string,
  existing: ImjangPlan[],
): Promise<ImjangPlan[]> {
  const next = existing.filter((p) => p.complexId !== complexId);
  const sb = getSupabase();
  if (sb && userId) {
    try {
      const { error } = await sb
        .from('imjang_plans')
        .delete()
        .eq('user_id', userId)
        .eq('complex_id', complexId);
      if (error) throw error;
      return next;
    } catch (e) {
      console.warn('계획 삭제 실패, 로컬에 반영', e);
    }
  }
  await saveLocal(next);
  return next;
}
