import { useState } from 'react';
import { Icon } from '@/components/Icon';
import { signInWithOAuth, type OAuthProvider } from '@/services/auth';
import { hasSupabase } from '@/lib/env';
import { useApp } from '@/store/AppStore';

interface Props {
  onClose?: () => void;
  /** Gate(Splash 이후 강제 노출) 모드 — X 버튼 숨김 */
  gate?: boolean;
}

export function AuthScreen({ onClose, gate = false }: Props = {}) {
  const { showToast } = useApp();
  const [busy, setBusy] = useState(false);

  async function doOAuth(provider: OAuthProvider) {
    if (!hasSupabase()) {
      showToast('Supabase 미구성: .env에 키 추가 후 사용 가능해요');
      return;
    }
    setBusy(true);
    try {
      await signInWithOAuth(provider);
    } catch (e: unknown) {
      showToast((e as Error).message ?? '로그인 실패');
    } finally {
      setBusy(false);
    }
  }

  return (
    <div className="screen push-enter" style={{ background: 'var(--bg)' }}>
      {!gate && (
        <div className="navbar flush">
          <button className="backbtn" onClick={onClose} type="button">
            <Icon name="x" size={22} />
          </button>
        </div>
      )}
      {gate && <div style={{ height: 'var(--safe-top)' }} />}
      <div className="scroll pad" style={{ paddingTop: 8 }}>
        <div style={{ textAlign: 'center', marginBottom: 30 }}>
          <div className="auth-logo">
            <Icon name="loc" size={32} fill />
          </div>
          <div
            style={{
              fontWeight: 800,
              fontSize: 21,
              marginTop: 16,
              letterSpacing: '-.03em',
            }}
          >
            로그인하고 기기 간 동기화
          </div>
          <div
            className="muted"
            style={{ fontSize: 13, fontWeight: 600, marginTop: 7, lineHeight: 1.55 }}
          >
            임장노트·사진·세션을 클라우드에 보관해
            <br />
            기기를 바꿔도 그대로 이어쓸 수 있어요.
          </div>
        </div>

        <div className="col gap8">
          <button
            className="btn btn-line"
            onClick={() => doOAuth('google')}
            type="button"
            disabled={busy}
          >
            <Icon name="google" size={19} fill />
            Google로 계속
          </button>
          <button
            className="btn btn-line"
            onClick={() => doOAuth('apple')}
            type="button"
            disabled={busy}
          >
            <Icon name="apple" size={20} fill />
            Apple로 계속
          </button>
          <button
            className="btn"
            style={{ background: '#FEE500', color: '#191600' }}
            onClick={() => doOAuth('kakao')}
            type="button"
            disabled={busy}
          >
            <Icon name="kakao" size={19} fill />
            카카오로 계속
          </button>
          <button
            className="btn"
            style={{ background: '#03C75A', color: '#fff' }}
            onClick={() => doOAuth('naver')}
            type="button"
            disabled={busy}
          >
            <Icon name="naver" size={17} fill />
            네이버로 계속
          </button>
        </div>

        <div
          className="muted"
          style={{
            fontSize: 11.5,
            fontWeight: 600,
            marginTop: 24,
            textAlign: 'center',
            lineHeight: 1.55,
          }}
        >
          계속하면 서비스 이용약관과 개인정보 처리방침에
          <br />
          동의한 것으로 봅니다.
        </div>
        <div style={{ height: 24 }} />
      </div>
    </div>
  );
}
