import { useEffect, useState } from 'react';
import { Icon } from '@/components/Icon';
import { TypeChip } from '@/components/Toast';
import { Stars } from '@/components/Stars';
import { Avatar } from '@/components/Avatar';
import { TripMap } from '@/components/TripMap';
import { useApp, complexById } from '@/store/AppStore';
import { planBatchId } from '@/services/plans';
import { createInvite, inviteFriendToPlan, colorFromId } from '@/services/collab';
import { usePlanComments } from '@/hooks/usePlanComments';
import { wonShort } from '@/lib/format';
import { ShareSheet } from './ShareSheet';
import type { Complex } from '@/types/domain';

interface Props {
  complexIds: string[];
  label: string;
  batchId: string;
}

function timeLabel(ts: number): string {
  const diff = Date.now() - ts;
  if (diff < 60_000) return '방금';
  if (diff < 3600_000) return `${Math.floor(diff / 60_000)}분 전`;
  const d = new Date(ts);
  return `${d.getMonth() + 1}.${d.getDate()} ${String(d.getHours()).padStart(2, '0')}:${String(d.getMinutes()).padStart(2, '0')}`;
}

export function TripDetail({ complexIds, label, batchId }: Props) {
  const { complexes, notes, plans, user, popOverlay, openDetail, openPlanChat, savePlans, deletePlanItem, renamePlanBatch, confirmAlert, markPlanRead } = useApp();
  // 멤버 메모(채팅) 상태 — 상세 미리보기와 채팅 화면이 동일 훅 공유
  const { comments, members, reloadMembers, displayAuthor } = usePlanComments(batchId);
  const [shareOpen, setShareOpen] = useState(false);
  const [mapFullscreen, setMapFullscreen] = useState(false);
  const [dateEditing, setDateEditing] = useState(false);
  const [titleEditing, setTitleEditing] = useState(false);
  const [titleDraft, setTitleDraft] = useState('');

  // 이 계획(batch)을 구성하는 plans (날짜/제목/메모 편집 대상) — batchId로 정확히 식별
  const tripPlans = plans.filter((p) => planBatchId(p) === batchId);
  // 공유받은 계획(내가 호스트가 아님)은 제목·날짜·단지 편집 불가 (호스트만 편집).
  // 멤버 메모는 협업 목적이라 모든 멤버가 작성 가능.
  const canEdit = !tripPlans.some((p) => p.shared);
  const currentDate = tripPlans[0]?.plannedDate ?? '';
  // 계획 제목 — plan memo의 [제목] 접두에 저장됨
  const tripTitle = (() => {
    const m = tripPlans[0]?.memo ?? '';
    if (m.startsWith('[')) {
      const end = m.indexOf(']');
      if (end > 0) return m.slice(1, end);
    }
    return '';
  })();

  async function changeTitle(t: string) {
    setTitleEditing(false);
    if (t.trim() === tripTitle) return;
    await renamePlanBatch(batchId, t);
  }
  const headerLabel = (() => {
    if (!currentDate) return label || '날짜 미정';
    const d = new Date(currentDate + 'T00:00:00');
    const DOW = ['일', '월', '화', '수', '목', '금', '토'];
    return `${d.getMonth() + 1}월 ${d.getDate()}일 (${DOW[d.getDay()]})`;
  })();

  async function changeDate(newDate: string) {
    if (!newDate || newDate === currentDate) { setDateEditing(false); return; }
    const updated = tripPlans.map((p) => ({ ...p, plannedDate: newDate }));
    await savePlans(updated);
    setDateEditing(false);
  }

  async function removeStop(id: string, name: string) {
    if (liveIds.length <= 1) {
      const ok = await confirmAlert({
        title: '계획 삭제',
        message: `마지막 단지를 빼면 이 임장 계획이 사라져요.\n계속할까요?`,
        confirmLabel: '삭제',
        danger: true,
      });
      if (!ok) return;
      await deletePlanItem(batchId, id);
      popOverlay();
      return;
    }
    const ok = await confirmAlert({
      title: '단지 제외',
      message: `"${name}"\n방문 코스에서 뺄까요?`,
      confirmLabel: '제외',
      danger: true,
    });
    if (!ok) return;
    await deletePlanItem(batchId, id);
  }

  // 이 batch에 남아있는 단지만 (코스 순서 유지)
  const liveIds = complexIds.filter((id) => tripPlans.some((p) => p.complexId === id));
  // complexes(시세탭 주변)에 없으면 plan에 저장된 정보로 stub Complex 생성
  const list = liveIds
    .map((id) => {
      const c = complexById(complexes, id);
      if (c) return c;
      const p = tripPlans.find((x) => x.complexId === id);
      if (!p) return null;
      return {
        id: p.complexId,
        name: p.complexName,
        type: p.complexType,
        built: 0,
        lat: p.lat ?? 0,
        lng: p.lng ?? 0,
        rep: 0,
        areas: [],
      } as Complex;
    })
    .filter((c): c is Complex => !!c);

  // 채팅(멤버 메모) 헤더용 계획 표시명 — 리스트 카드와 동일 폴백
  const planDisplayTitle =
    tripTitle ||
    (list[0] ? `${list[0].name}${list.length > 1 ? ` 외 ${list.length - 1}곳` : ''}` : label || '멤버 메모');

  // 상세를 떠날 때(또는 batch 변경 시) 읽음 처리 — 보는 동안 도착한 메모까지 NEW 해제
  useEffect(() => {
    return () => {
      if (batchId) markPlanRead(batchId);
    };
  }, [batchId, markPlanRead]);

  const stops = list
    .filter((c): c is NonNullable<typeof c> => !!c && c.lat != null && c.lng != null)
    .map((c) => ({ complex: c }));

  return (
    <div className="screen push-enter" style={{ background: 'var(--bg)', display: 'flex', flexDirection: 'column' }}>
      <div className="navbar flush">
        <button className="backbtn" onClick={popOverlay} type="button">
          <Icon name="back" size={22} />
        </button>
        <div className="grow" />
      </div>
      <div className="scroll" style={{ paddingTop: 0, flex: 1 }}>
        <div className="pad" style={{ paddingBottom: 16 }}>
          {/* 계획 제목 — 호스트만 클릭 시 인라인 수정. 공유받은 멤버는 표시만. */}
          {!canEdit ? (
            <div
              style={{
                fontSize: 22,
                fontWeight: 800,
                letterSpacing: '-0.02em',
                color: 'var(--ink)',
                overflow: 'hidden',
                textOverflow: 'ellipsis',
                whiteSpace: 'nowrap',
                marginBottom: 8,
              }}
            >
              {tripTitle ||
                (list[0]
                  ? `${list[0].name}${list.length > 1 ? ` 외 ${list.length - 1}곳` : ''}`
                  : '임장 계획')}
            </div>
          ) : titleEditing ? (
            <input
              autoFocus
              defaultValue={titleDraft}
              placeholder="임장계획 제목"
              onBlur={(e) => void changeTitle(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === 'Enter') void changeTitle((e.target as HTMLInputElement).value);
                if (e.key === 'Escape') setTitleEditing(false);
              }}
              style={{
                fontSize: 22,
                fontWeight: 800,
                border: '1.5px solid var(--accent)',
                borderRadius: 10,
                padding: '4px 10px',
                background: 'var(--surface)',
                color: 'var(--ink)',
                width: '100%',
                boxSizing: 'border-box',
                marginBottom: 8,
              }}
            />
          ) : (
            <button
              type="button"
              onClick={() => {
                setTitleDraft(tripTitle);
                setTitleEditing(true);
              }}
              style={{
                background: 'transparent',
                border: 'none',
                padding: 0,
                cursor: 'pointer',
                display: 'flex',
                alignItems: 'center',
                gap: 8,
                maxWidth: '100%',
                marginBottom: 8,
              }}
            >
              <span
                style={{
                  fontSize: 22,
                  fontWeight: 800,
                  letterSpacing: '-0.02em',
                  color: 'var(--ink)',
                  overflow: 'hidden',
                  textOverflow: 'ellipsis',
                  whiteSpace: 'nowrap',
                }}
              >
                {/* 제목 미저장 시 리스트 카드와 동일한 폴백: "단지명 외 N곳" */}
                {tripTitle ||
                  (list[0]
                    ? `${list[0].name}${list.length > 1 ? ` 외 ${list.length - 1}곳` : ''}`
                    : '계획 제목 추가')}
              </span>
              <Icon name="edit" size={16} color="var(--ink-4)" stroke={2} />
            </button>
          )}
          <div className="row gap6" style={{ alignItems: 'center' }}>
            {!canEdit ? (
              <span
                className="trip-hero-date"
                style={{ fontSize: 15, fontWeight: 700, color: 'var(--ink-2)' }}
              >
                {headerLabel}
              </span>
            ) : dateEditing ? (
              <input
                type="date"
                defaultValue={currentDate}
                autoFocus
                onBlur={(e) => void changeDate(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') void changeDate((e.target as HTMLInputElement).value);
                  if (e.key === 'Escape') setDateEditing(false);
                }}
                style={{
                  fontSize: 15,
                  fontWeight: 700,
                  border: '1.5px solid var(--accent)',
                  borderRadius: 8,
                  padding: '3px 8px',
                  background: 'var(--surface)',
                  color: 'var(--ink)',
                }}
              />
            ) : (
              <button
                type="button"
                onClick={() => tripPlans.length > 0 && setDateEditing(true)}
                style={{
                  background: 'transparent',
                  border: 'none',
                  padding: 0,
                  cursor: tripPlans.length > 0 ? 'pointer' : 'default',
                  display: 'flex',
                  alignItems: 'center',
                  gap: 6,
                }}
              >
                <span
                  className="trip-hero-date"
                  style={{ fontSize: 15, fontWeight: 700, color: 'var(--ink-2)' }}
                >
                  {headerLabel}
                </span>
                {tripPlans.length > 0 && (
                  <Icon name="calendar" size={15} color="var(--ink-4)" stroke={2} />
                )}
              </button>
            )}
          </div>
          <div
            className="row between"
            style={{ marginTop: 8, alignItems: 'center', gap: 10 }}
          >
            <div className="muted" style={{ fontSize: 13, fontWeight: 600 }}>
              {`단지 ${list.length}곳`}
            </div>
            <button
              type="button"
              className="plan-member-btn"
              onClick={() => setShareOpen(true)}
            >
              <Icon name="people" size={14} stroke={2} />
              {members.length > 0 ? `멤버 ${members.length}` : '멤버 관리'}
            </button>
          </div>
        </div>

        {stops.length > 0 && (
          <div className="pad">
            <div
              className="plan-map"
              style={{
                height: mapFullscreen ? 'calc(100vh - 320px)' : undefined,
                transition: 'height 0.25s ease',
                position: 'relative',
              }}
            >
              <TripMap stops={stops} onClickStop={(id) => openDetail(id)} />
            </div>
            {/* drag/swipe 핸들 — 위로 swipe = 지도 fullscreen, 아래로 swipe = 원복 */}
            <div
              onTouchStart={(e) => { (e.currentTarget as unknown as { _sy?: number })._sy = e.touches[0].clientY; }}
              onTouchEnd={(e) => {
                const start = (e.currentTarget as unknown as { _sy?: number })._sy ?? 0;
                const delta = e.changedTouches[0].clientY - start;
                if (delta < -30) setMapFullscreen(true);
                else if (delta > 30) setMapFullscreen(false);
              }}
              onClick={() => setMapFullscreen((v) => !v)}
              style={{
                marginTop: 6,
                padding: '8px 0',
                display: 'flex',
                justifyContent: 'center',
                cursor: 'pointer',
                touchAction: 'none',
              }}
              title={mapFullscreen ? '아래로 슬라이드: 리스트 보기' : '위로 슬라이드: 지도 전체 보기'}
            >
              <div
                style={{
                  width: 44,
                  height: 5,
                  borderRadius: 999,
                  background: 'var(--line-strong)',
                }}
              />
            </div>
          </div>
        )}

        <div className="pad" style={{ paddingTop: 20, display: mapFullscreen ? 'none' : undefined }}>
          <div
            className="row gap6"
            style={{ marginBottom: 12, marginLeft: 2, alignItems: 'center' }}
          >
            <Icon name="flag" size={15} color="var(--accent)" stroke={2} />
            <span className="sect-title">방문 코스</span>
          </div>
          <div className="card" style={{ padding: '6px 16px' }}>
            {list.map((c, i) => {
              if (!c) return null;
              const first = i === 0;
              const last = i === list.length - 1;
              return (
                <div
                  key={c.id}
                  className="route-row"
                  style={{ display: 'flex', alignItems: 'center', cursor: 'pointer' }}
                  onClick={() => openDetail(c.id)}
                >
                  <div className={'route-line' + (first ? ' first' : '') + (last ? ' last' : '')}>
                    <div className="route-dot">{i + 1}</div>
                  </div>
                  <div style={{ flex: 1, minWidth: 0, textAlign: 'left', padding: '14px 0' }}>
                    <div
                      style={{
                        fontWeight: 700,
                        fontSize: 14.5,
                        overflow: 'hidden',
                        textOverflow: 'ellipsis',
                        whiteSpace: 'nowrap',
                      }}
                      title={c.name}
                    >
                      {c.name}
                    </div>
                    <div
                      className="row gap6"
                      style={{ fontSize: 11.5, fontWeight: 600, marginTop: 2, alignItems: 'center', color: 'var(--ink-3)' }}
                    >
                      <TypeChip type={c.type} />
                      <span>{`${c.distM ?? '–'}m`}</span>
                      {c.rep > 0 ? (
                        <span className="num" style={{ fontWeight: 800, color: 'var(--accent)' }}>
                          · {wonShort(c.rep)}
                        </span>
                      ) : (
                        <span style={{ color: 'var(--ink-4)' }}>· 가격정보 없음</span>
                      )}
                      {notes[c.id] && <Stars rating={notes[c.id].rating} />}
                    </div>
                  </div>
                  {canEdit && (
                    <button
                      type="button"
                      onClick={(e) => {
                        e.stopPropagation();
                        void removeStop(c.id, c.name);
                      }}
                      title="방문 코스에서 빼기"
                      style={{
                        marginLeft: 10,
                        width: 28,
                        height: 28,
                        borderRadius: '50%',
                        border: 'none',
                        background: 'var(--surface-2)',
                        color: 'var(--ink-3)',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        cursor: 'pointer',
                        flexShrink: 0,
                      }}
                    >
                      <Icon name="x" size={14} stroke={2.2} />
                    </button>
                  )}
                </div>
              );
            })}
          </div>
        </div>

        <div className="pad" style={{ paddingTop: 22 }}>
          <div className="row between" style={{ marginBottom: 14, padding: '0 2px', alignItems: 'center' }}>
            <div className="row gap6" style={{ alignItems: 'center' }}>
              <Icon name="people" size={15} color="var(--accent)" stroke={2} />
              <span className="sect-title">멤버 메모</span>
              {comments.length > 0 && <span className="count-badge">{comments.length}</span>}
            </div>
            <button
              type="button"
              className="plan-member-btn"
              onClick={() => openPlanChat(batchId, planDisplayTitle)}
            >
              더보기
              <Icon name="chevR" size={14} stroke={2.2} />
            </button>
          </div>
          {comments.length === 0 ? (
            <button
              type="button"
              className="card"
              style={{ width: '100%', padding: '22px 0', textAlign: 'center', border: 'none', cursor: 'pointer' }}
              onClick={() => openPlanChat(batchId, planDisplayTitle)}
            >
              <div className="muted" style={{ fontSize: 12.5, fontWeight: 600 }}>아직 멤버 메모가 없어요</div>
              <div style={{ fontSize: 12.5, fontWeight: 700, color: 'var(--accent)', marginTop: 5 }}>메모 남기기</div>
            </button>
          ) : (
            <>
              {/* 최근 메모 2개만 미리보기 — 전체는 채팅 화면(더보기)에서 */}
              {comments.slice(-2).map((c) => {
                const mine = !!user && c.authorId === user.id;
                const authorLabel = displayAuthor(c.authorId, c.authorName);
                return (
                  <div key={c.id} className="cmt-wrap">
                    <div className={'cmt' + (mine ? ' me' : '')}>
                      {!mine && (
                        <Avatar m={{ id: c.authorId, name: authorLabel, color: colorFromId(c.authorId) }} size={30} />
                      )}
                      <div className="cmt-body">
                        <div className="cmt-meta">
                          <span className="cmt-name">{mine ? '나' : authorLabel}</span>
                          <span className="cmt-time">{timeLabel(c.createdAt)}</span>
                        </div>
                        <div className={'cmt-bubble' + (mine ? ' me' : '')}>{c.text}</div>
                      </div>
                    </div>
                  </div>
                );
              })}
              <button
                type="button"
                className="btn btn-ghost"
                style={{ width: '100%', marginTop: 10 }}
                onClick={() => openPlanChat(batchId, planDisplayTitle)}
              >
                {comments.length > 2 ? `메모 ${comments.length}개 모두 보기` : '대화 열기'}
                <Icon name="chevR" size={16} stroke={2.2} />
              </button>
            </>
          )}
          <div style={{ height: 28 }} />
        </div>
      </div>
      {shareOpen && (
        <ShareSheet
          sessionLabel={tripTitle || label}
          members={members}
          batchId={batchId}
          // 초대는 호스트만 — 공유받은 멤버는 멤버 목록 보기만
          onCreateInviteLink={canEdit ? () => createInvite('plan', batchId) : undefined}
          onInviteFriend={
            canEdit
              ? async (fid) => {
                  const ok = await inviteFriendToPlan(batchId, fid);
                  if (ok) await reloadMembers();
                  return ok;
                }
              : undefined
          }
          onClose={() => setShareOpen(false)}
        />
      )}
    </div>
  );
}
