// TripVoice/src/services/LocationService.ts 패턴을 임장노트에 맞게 가져옴.
// 우선순위:
//   1) 네이티브 Capacitor Geolocation (iOS/Android)
//   2) navigator.geolocation HighAccuracy (GPS/WiFi) → 실패 시 LowAccuracy (네트워크)
//   3) IP 기반 (ipinfo.io, CORS 허용, 무료) — 시·구 단위 근사
// 모두 실패해야 진짜 null. 하드코딩된 연남동 같은 폴백은 사용 안 한다.

import { Geolocation, type PermissionStatus } from '@capacitor/geolocation';
import { Capacitor } from '@capacitor/core';
import type { LatLng } from '@/lib/geo';

interface WatchOptions {
  onPosition: (pos: LatLng, source: PositionSource) => void;
  onError?: (err: Error) => void;
}

export type PositionSource = 'native-gps' | 'web-gps-high' | 'web-gps-low' | 'ip';

let watchId: string | null = null;
let webWatchId: number | null = null;

const CACHE_TTL_MS = 60_000;
let cached: { pos: LatLng; source: PositionSource; at: number } | null = null;

/** 권한 요청 — 웹에서도 실제 prompt를 띄움 (getCurrentPosition 호출). */
export async function requestLocationPermission(): Promise<
  PermissionStatus | { location: 'granted' | 'denied' | 'prompt' }
> {
  if (Capacitor.isNativePlatform()) {
    const status = await Geolocation.checkPermissions();
    if (status.location === 'granted') return status;
    return Geolocation.requestPermissions();
  }
  if (!navigator.geolocation) return { location: 'denied' };
  return new Promise((resolve) => {
    let settled = false;
    const finish = (loc: 'granted' | 'denied' | 'prompt') => {
      if (settled) return;
      settled = true;
      resolve({ location: loc });
    };
    navigator.geolocation.getCurrentPosition(
      () => finish('granted'),
      (err) => finish(err.code === 1 ? 'denied' : 'prompt'),
      { enableHighAccuracy: false, timeout: 6000, maximumAge: 0 },
    );
  });
}

// ============ 폴백 체인 ============

async function tryNativeGps(): Promise<{ pos: LatLng; source: PositionSource } | null> {
  if (!Capacitor.isNativePlatform()) return null;
  try {
    const perm = await Geolocation.checkPermissions();
    if (perm.location === 'denied') return null;
    if (perm.location !== 'granted') {
      const req = await Geolocation.requestPermissions();
      if (req.location !== 'granted') return null;
    }
    // 첫 fix는 저정밀(네트워크/셀 기반)로 빠르게 — 최근 OS fix(maximumAge)면 즉시 반환.
    // 정밀 위치는 startLocationWatch의 watchPosition(enableHighAccuracy)이 이후 보정한다.
    const p = await Geolocation.getCurrentPosition({
      enableHighAccuracy: false,
      timeout: 8000,
      maximumAge: 60000,
    });
    return { pos: { lat: p.coords.latitude, lng: p.coords.longitude }, source: 'native-gps' };
  } catch (e) {
    console.warn('[Location] Capacitor Geolocation fail:', (e as Error).message);
    return null;
  }
}

async function tryWebGps(): Promise<{ pos: LatLng; source: PositionSource } | null> {
  if (typeof navigator === 'undefined' || !navigator.geolocation) return null;
  // 1차 HighAccuracy
  try {
    const p = await new Promise<GeolocationPosition>((resolve, reject) => {
      navigator.geolocation.getCurrentPosition(resolve, reject, {
        enableHighAccuracy: true,
        timeout: 10000,
        maximumAge: 60_000,
      });
    });
    return { pos: { lat: p.coords.latitude, lng: p.coords.longitude }, source: 'web-gps-high' };
  } catch (e) {
    console.warn('[Location] web high-accuracy fail:', (e as Error).message);
  }
  // 2차 LowAccuracy (네트워크 기반 — 더 빨리 응답)
  try {
    const p = await new Promise<GeolocationPosition>((resolve, reject) => {
      navigator.geolocation.getCurrentPosition(resolve, reject, {
        enableHighAccuracy: false,
        timeout: 6000,
        maximumAge: 60_000,
      });
    });
    return { pos: { lat: p.coords.latitude, lng: p.coords.longitude }, source: 'web-gps-low' };
  } catch {
    return null;
  }
}

async function tryIp(): Promise<{ pos: LatLng; source: PositionSource } | null> {
  // 여러 IP 위치 서비스를 순차 시도 — CORS 허용되는 서비스들.
  const endpoints: Array<{ url: string; parse: (j: unknown) => LatLng | null }> = [
    {
      url: 'https://ipapi.co/json/',
      parse: (j) => {
        const o = j as { latitude?: number; longitude?: number };
        if (typeof o.latitude !== 'number' || typeof o.longitude !== 'number') return null;
        return { lat: o.latitude, lng: o.longitude };
      },
    },
    {
      url: 'https://get.geojs.io/v1/ip/geo.json',
      parse: (j) => {
        const o = j as { latitude?: string; longitude?: string };
        const lat = parseFloat(o.latitude ?? '');
        const lng = parseFloat(o.longitude ?? '');
        if (!Number.isFinite(lat) || !Number.isFinite(lng)) return null;
        return { lat, lng };
      },
    },
    {
      url: 'https://api.bigdatacloud.net/data/reverse-geocode-client',
      parse: (j) => {
        const o = j as { latitude?: number; longitude?: number };
        if (typeof o.latitude !== 'number' || typeof o.longitude !== 'number') return null;
        return { lat: o.latitude, lng: o.longitude };
      },
    },
  ];
  for (const ep of endpoints) {
    try {
      const r = await fetch(ep.url);
      if (!r.ok) continue;
      const j = (await r.json()) as unknown;
      const pos = ep.parse(j);
      if (pos) return { pos, source: 'ip' };
    } catch (e) {
      console.warn(`[Location] IP fallback ${ep.url} fail:`, (e as Error).message);
    }
  }
  return null;
}

/**
 * 1회성 위치 조회 — 세션 캐시. force=true면 다시 받음.
 * 우선순위: 네이티브 GPS → 웹 GPS (high→low) → IP. 모두 실패해야 throw.
 */
export async function getCurrentPosition(force = false): Promise<LatLng> {
  if (!force && cached && Date.now() - cached.at < CACHE_TTL_MS) {
    return cached.pos;
  }
  const tries = [tryNativeGps, tryWebGps, tryIp];
  for (const fn of tries) {
    const got = await fn();
    if (got) {
      cached = { ...got, at: Date.now() };
      return got.pos;
    }
  }
  throw new Error('위치를 가져올 수 없어요 (GPS·네트워크·IP 모두 실패)');
}

/** 캐시만 확인 — 즉시 반환. 없으면 null. */
export function getCachedPosition(): { pos: LatLng; source: PositionSource } | null {
  if (!cached) return null;
  return { pos: cached.pos, source: cached.source };
}

/** watchPosition — GPS 이동 추적. 첫 위치는 getCurrentPosition을 즉시 호출해 빠르게 채우고,
 *  그 뒤 native/web watchPosition으로 지속 갱신. */
export async function startLocationWatch({ onPosition, onError }: WatchOptions): Promise<void> {
  await stopLocationWatch();

  // 즉시 한 번 — 캐시·IP 폴백으로 첫 위치를 빠르게 채움.
  try {
    const got = getCachedPosition() ?? null;
    if (got) onPosition(got.pos, got.source);
    else {
      const pos = await getCurrentPosition();
      const src = getCachedPosition()?.source ?? 'web-gps-high';
      onPosition(pos, src);
    }
  } catch (e) {
    onError?.(e as Error);
  }

  // 그 다음 watchPosition으로 지속 추적 — 가능한 환경에서만.
  if (Capacitor.isNativePlatform()) {
    try {
      watchId = await Geolocation.watchPosition(
        { enableHighAccuracy: true, timeout: 10000 },
        (pos, err) => {
          if (err) return; // 1회성 실패는 무시 (이미 첫 위치 받음)
          if (pos) {
            const p = { lat: pos.coords.latitude, lng: pos.coords.longitude };
            cached = { pos: p, source: 'native-gps', at: Date.now() };
            onPosition(p, 'native-gps');
          }
        },
      );
    } catch (e) {
      console.warn('[Location] native watchPosition 실패:', (e as Error).message);
    }
    return;
  }

  if (navigator.geolocation) {
    webWatchId = navigator.geolocation.watchPosition(
      (p) => {
        const pos = { lat: p.coords.latitude, lng: p.coords.longitude };
        cached = { pos, source: 'web-gps-high', at: Date.now() };
        onPosition(pos, 'web-gps-high');
      },
      () => {
        // watch 실패는 onError로 올리지 않음 — 이미 첫 위치는 받았을 수 있음
      },
      { enableHighAccuracy: true, timeout: 15000, maximumAge: 5000 },
    );
  }
}

export async function stopLocationWatch(): Promise<void> {
  if (watchId != null) {
    try {
      await Geolocation.clearWatch({ id: watchId });
    } catch {
      /* ignore */
    }
    watchId = null;
  }
  if (webWatchId != null) {
    try {
      navigator.geolocation.clearWatch(webWatchId);
    } catch {
      /* ignore */
    }
    webWatchId = null;
  }
}

