// push.ts — OS 푸시 알림. 네이티브(iOS/Android)에서만 동작.
// 토큰 등록 → register_device_token RPC. 수신/탭 → 'push:refresh' 이벤트로 AppStore 재로드 유도.
import { Capacitor } from '@capacitor/core';
import { getSupabase } from '../lib/supabase';

let started = false;

/** 푸시 수신/탭 시 알림 데이터를 실어 보내는 전역 이벤트. AppStore가 구독해 재로드/이동. */
export const PUSH_EVENT = 'push:refresh';

function emitRefresh(data: unknown) {
  try {
    window.dispatchEvent(new CustomEvent(PUSH_EVENT, { detail: data ?? {} }));
  } catch { /* ignore */ }
}

/** 로그인 후 1회 호출. 권한 요청 → APNs 등록 → 토큰을 서버에 저장. */
export async function initPush(): Promise<void> {
  if (started) return;
  if (!Capacitor.isNativePlatform()) return; // 웹에서는 OS 푸시 없음
  started = true;

  // 동적 import — 웹 번들에 네이티브 플러그인 끌어오지 않도록
  const { PushNotifications } = await import('@capacitor/push-notifications');

  PushNotifications.addListener('registration', (token) => {
    void (async () => {
      try {
        const sb = getSupabase();
        if (!sb) return;
        await sb.rpc('register_device_token', {
          p_token: token.value,
          p_platform: Capacitor.getPlatform(),
        });
      } catch { /* 등록 실패는 무시 (다음 실행 때 재시도) */ }
    })();
  });

  PushNotifications.addListener('registrationError', () => { /* no-op */ });

  // 포그라운드 수신 — 목록/배지 즉시 갱신
  PushNotifications.addListener('pushNotificationReceived', (notif) => {
    emitRefresh(notif?.data);
  });

  // 알림 탭 — 갱신 + 해당 화면으로 이동 (data.kind/batchId/complexId)
  PushNotifications.addListener('pushNotificationActionPerformed', (action) => {
    emitRefresh(action?.notification?.data);
  });

  try {
    const perm = await PushNotifications.checkPermissions();
    let receive = perm.receive;
    if (receive === 'prompt' || receive === 'prompt-with-rationale') {
      receive = (await PushNotifications.requestPermissions()).receive;
    }
    if (receive === 'granted') {
      await PushNotifications.register();
    }
  } catch { /* ignore */ }
}
