import { Icon } from './Icon';

interface BrandStyle {
  label: string;
  iconName: string;
  bg: string;
  color: string;
}

const STYLES: Record<string, BrandStyle> = {
  google: { label: 'Google', iconName: 'google', bg: '#FFFFFF', color: '#191F28' },
  apple: { label: 'Apple', iconName: 'apple', bg: '#191F28', color: '#FFFFFF' },
  kakao: { label: 'Kakao', iconName: 'kakao', bg: '#FEE500', color: '#191600' },
  naver: { label: 'Naver', iconName: 'naver', bg: '#03C75A', color: '#FFFFFF' },
  email: { label: 'Email', iconName: 'won', bg: 'var(--surface-2)', color: 'var(--ink-3)' },
};

/** 로그인 provider 뱃지 — 작은 동그라미. 어떤 소셜로 로그인했는지 표시. */
export function ProviderBadge({ provider }: { provider: string | null | undefined }) {
  if (!provider) return null;
  const s = STYLES[provider];
  if (!s) return null;
  // Google: 다색 G 로고 (단일색 SVG는 작은 사이즈에서 뭉개짐)
  if (provider === 'google') {
    return (
      <span
        title="Google로 로그인"
        style={{
          display: 'inline-flex',
          alignItems: 'center',
          justifyContent: 'center',
          width: 20,
          height: 20,
          borderRadius: '50%',
          background: '#FFFFFF',
          border: '1px solid var(--line)',
          flexShrink: 0,
        }}
      >
        <svg width="13" height="13" viewBox="0 0 48 48">
          <path fill="#FFC107" d="M43.6 20.5H42V20H24v8h11.3c-1.6 4.7-6.1 8-11.3 8-6.6 0-12-5.4-12-12s5.4-12 12-12c3.1 0 5.8 1.2 7.9 3.1l5.7-5.7C33.6 6.1 29.1 4 24 4 12.9 4 4 12.9 4 24s8.9 20 20 20 20-8.9 20-20c0-1.3-.1-2.4-.4-3.5z"/>
          <path fill="#FF3D00" d="M6.3 14.7l6.6 4.8C14.7 15.1 19 12 24 12c3.1 0 5.8 1.2 7.9 3.1l5.7-5.7C33.6 6.1 29.1 4 24 4 16.3 4 9.7 8.3 6.3 14.7z"/>
          <path fill="#4CAF50" d="M24 44c5 0 9.5-1.9 12.9-5l-6-5.1c-1.9 1.4-4.3 2.2-6.9 2.2-5.2 0-9.6-3.3-11.3-7.9l-6.5 5C9.5 39.6 16.2 44 24 44z"/>
          <path fill="#1976D2" d="M43.6 20.5H42V20H24v8h11.3c-.8 2.3-2.2 4.2-4.1 5.6l6 5.1c-.4.4 6.8-5 6.8-14.7 0-1.3-.1-2.4-.4-3.5z"/>
        </svg>
      </span>
    );
  }
  return (
    <span
      title={`${s.label}로 로그인`}
      style={{
        display: 'inline-flex',
        alignItems: 'center',
        justifyContent: 'center',
        width: 20,
        height: 20,
        borderRadius: '50%',
        background: s.bg,
        color: s.color,
        flexShrink: 0,
      }}
    >
      <Icon name={s.iconName} size={11} fill color="currentColor" />
    </span>
  );
}
