// favorites.ts — 즐겨찾기(관심단지). toggle_favorite / my_favorites RPC 래퍼.
import { getSupabase } from '../lib/supabase';

/** 내 즐겨찾기 단지 id 집합. 비로그인/실패 시 빈 set. */
export async function listFavorites(): Promise<Set<string>> {
  const sb = getSupabase();
  if (!sb) return new Set();
  const { data, error } = await sb.rpc('my_favorites');
  if (error || !data) return new Set();
  return new Set((data as Array<{ complex_id: string }>).map((r) => r.complex_id));
}

/**
 * 즐겨찾기 토글. 새로 추가할 때 현재 대표 실거래가(만원)를 baseline으로 전달.
 * @returns 토글 후 즐겨찾기 상태(true=추가됨). 실패 시 null.
 */
export async function toggleFavorite(complexId: string, price?: number): Promise<boolean | null> {
  const sb = getSupabase();
  if (!sb) return null;
  const { data, error } = await sb.rpc('toggle_favorite', {
    p_complex_id: complexId,
    p_price: price != null && Number.isFinite(price) ? Math.round(price) : null,
  });
  if (error) return null;
  return Boolean(data);
}
