import { Icon } from '@/components/Icon';
import { useApp } from '@/store/AppStore';
import { planBatchId } from '@/services/plans';
import type { ImjangPlan } from '@/types/domain';

function timeLabel(ts: number): string {
  const diff = Date.now() - ts;
  if (diff < 60_000) return '방금';
  if (diff < 3600_000) return `${Math.floor(diff / 60_000)}분 전`;
  if (diff < 86_400_000) return `${Math.floor(diff / 3600_000)}시간 전`;
  const d = new Date(ts);
  return `${d.getMonth() + 1}.${d.getDate()}`;
}

function planTitle(batchPlans: ImjangPlan[]): string {
  // 리스트 카드와 동일하게 선택 순서(createdAt asc) 기준으로 대표 단지 결정
  const ordered = [...batchPlans].sort((a, b) => a.createdAt - b.createdAt);
  const m = ordered[0]?.memo ?? '';
  if (m.startsWith('[')) {
    const end = m.indexOf(']');
    if (end > 0) return m.slice(1, end);
  }
  const head = ordered[0];
  if (!head) return '임장 계획';
  return head.complexName + (ordered.length > 1 ? ` 외 ${ordered.length - 1}곳` : '');
}

export function NotificationsSheet() {
  const { pendingInvites, respondPlanInvite, popOverlay, unreadComments, unreadSharedNotes, plans, openTrip, openMemberNote, friends } = useApp();
  // 작성자 표시명 — 내가 지정한 별명이 있으면 "별명 (사용자명)"
  const authorLabel = (authorId: string, fallback: string): string => {
    const f = friends.find((x) => x.id === authorId);
    if (f?.alias) return `${f.alias} (${f.baseName})`;
    return f?.baseName || fallback;
  };

  // 안 읽은 메모를 계획(batch)별로 묶기 — 최신 메모가 위로
  const byBatch = new Map<string, { count: number; latest: (typeof unreadComments)[number] }>();
  for (const c of unreadComments) {
    const cur = byBatch.get(c.batchId);
    if (cur) {
      cur.count += 1;
      if (c.createdAt > cur.latest.createdAt) cur.latest = c;
    } else {
      byBatch.set(c.batchId, { count: 1, latest: c });
    }
  }
  const commentGroups = [...byBatch.entries()]
    .map(([batchId, v]) => ({ batchId, ...v }))
    .sort((a, b) => b.latest.createdAt - a.latest.createdAt);

  const isEmpty =
    pendingInvites.length === 0 && commentGroups.length === 0 && unreadSharedNotes.length === 0;

  function openPlan(batchId: string) {
    const bp = plans.filter((p) => planBatchId(p) === batchId).sort((a, b) => a.createdAt - b.createdAt);
    if (bp.length === 0) return;
    popOverlay();
    openTrip(bp.map((p) => p.complexId), planTitle(bp), batchId);
  }

  function openShared(r: (typeof unreadSharedNotes)[number]) {
    popOverlay();
    openMemberNote(r.complexId, {
      userId: r.ownerId,
      authorName: r.authorName,
      rating: r.rating,
      checks: r.checks,
      photos: r.photos,
      oneliner: r.oneliner,
      shared: true,
      createdAt: r.createdAt,
      isMine: false,
    });
  }

  return (
    <div className="sheet-scrim" onClick={popOverlay} style={{ zIndex: 120 }}>
      <div
        className="filter-sheet"
        onClick={(e) => e.stopPropagation()}
        style={{ maxHeight: '80%', overflowY: 'auto' }}
      >
        <div className="sheet-grip" />
        <div className="row between" style={{ marginBottom: 12, padding: '0 2px' }}>
          <div style={{ fontWeight: 800, fontSize: 18, letterSpacing: '-.02em' }}>알림</div>
          <button
            type="button"
            onClick={popOverlay}
            style={{ color: 'var(--ink-3)', padding: 4, background: 'none', border: 'none', cursor: 'pointer' }}
          >
            <Icon name="x" size={20} />
          </button>
        </div>

        {isEmpty && (
          <div className="card" style={{ padding: '28px 0', textAlign: 'center', marginBottom: 8 }}>
            <div className="muted" style={{ fontSize: 12.5, fontWeight: 600 }}>새로운 알림이 없어요</div>
          </div>
        )}

        {pendingInvites.length > 0 && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 10, marginBottom: 8 }}>
            {pendingInvites.map((inv) => (
              <div key={inv.batchId} className="card" style={{ padding: 14 }}>
                <div style={{ fontSize: 13, fontWeight: 600, color: 'var(--ink-2)', marginBottom: 2 }}>
                  <b style={{ color: 'var(--ink)' }}>{inv.inviterName}</b>님이 함께 임장에 초대했어요
                </div>
                <div style={{ fontWeight: 800, fontSize: 15, letterSpacing: '-.02em', marginBottom: 12 }}>
                  {inv.title}
                </div>
                <div className="row gap8">
                  <button
                    type="button"
                    className="btn btn-primary btn-sm"
                    style={{ flex: 1 }}
                    onClick={() => void respondPlanInvite(inv.batchId, true)}
                  >
                    수락
                  </button>
                  <button
                    type="button"
                    className="btn btn-ghost btn-sm"
                    style={{ flex: 1 }}
                    onClick={() => void respondPlanInvite(inv.batchId, false)}
                  >
                    거절
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}

        {commentGroups.length > 0 && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 10, marginBottom: 8 }}>
            {commentGroups.map((g) => {
              const bp = plans.filter((p) => planBatchId(p) === g.batchId);
              const title = bp.length > 0 ? planTitle(bp) : '임장 계획';
              return (
                <button
                  key={g.batchId}
                  type="button"
                  className="card"
                  style={{ padding: 14, textAlign: 'left', cursor: 'pointer', border: 'none', width: '100%' }}
                  onClick={() => openPlan(g.batchId)}
                >
                  <div className="row between" style={{ marginBottom: 4 }}>
                    <div style={{ fontSize: 13, fontWeight: 600, color: 'var(--ink-2)' }}>
                      <b style={{ color: 'var(--ink)' }}>{authorLabel(g.latest.authorId, g.latest.authorName)}</b>님이 새 메모를 남겼어요
                      {g.count > 1 && <span className="muted" style={{ fontWeight: 700 }}>{` +${g.count - 1}`}</span>}
                    </div>
                    <span className="muted" style={{ fontSize: 11.5, fontWeight: 600, flexShrink: 0 }}>
                      {timeLabel(g.latest.createdAt)}
                    </span>
                  </div>
                  <div style={{ fontWeight: 800, fontSize: 14.5, letterSpacing: '-.02em', marginBottom: 4 }}>
                    {title}
                  </div>
                  <div
                    className="muted"
                    style={{
                      fontSize: 12.5,
                      fontWeight: 600,
                      overflow: 'hidden',
                      textOverflow: 'ellipsis',
                      whiteSpace: 'nowrap',
                    }}
                  >
                    {g.latest.text}
                  </div>
                </button>
              );
            })}
          </div>
        )}

        {unreadSharedNotes.length > 0 && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 10, marginBottom: 8 }}>
            {unreadSharedNotes.map((r) => (
              <button
                key={`${r.ownerId}-${r.complexId}`}
                type="button"
                className="card"
                style={{ padding: 14, textAlign: 'left', cursor: 'pointer', border: 'none', width: '100%' }}
                onClick={() => openShared(r)}
              >
                <div className="row between" style={{ marginBottom: 4 }}>
                  <div style={{ fontSize: 13, fontWeight: 600, color: 'var(--ink-2)' }}>
                    <b style={{ color: 'var(--ink)' }}>{authorLabel(r.ownerId, r.authorName)}</b>님이 임장노트를 공유했어요
                  </div>
                  <span className="muted" style={{ fontSize: 11.5, fontWeight: 600, flexShrink: 0 }}>
                    {timeLabel(r.createdAt)}
                  </span>
                </div>
                <div
                  className="muted"
                  style={{ fontSize: 12.5, fontWeight: 600, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}
                >
                  {r.oneliner || (r.rating > 0 ? `별점 ${r.rating.toFixed(1)}` : '임장노트 보기')}
                </div>
              </button>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
