import { useEffect, useMemo, useRef, useState } from 'react';
import { Icon } from '@/components/Icon';
import { Spinner } from '@/components/Spinner';
import { FilterBar } from '@/components/FilterBar';
import { BrandHeader } from '@/components/BrandHeader';
import { useApp, repArea } from '@/store/AppStore';
import { pyeong, wonShort, wonText } from '@/lib/format';
import { searchAll, type SearchHit } from '@/lib/regionSearch';
import type { Complex } from '@/types/domain';
import { displayName } from '@/lib/displayName';

function HomeTopBar({ floating = false }: { floating?: boolean }) {
  const {
    area, view, setView, complexes, complexesLoading, locationReady, currentLatLng,
    hasRealLocation, refreshComplexesAt, setMapTarget,
  } = useApp();
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<SearchHit[]>([]);
  const [searching, setSearching] = useState(false);
  const [focused, setFocused] = useState(false);
  const debounceRef = useRef<number | null>(null);
  const inputRef = useRef<HTMLInputElement | null>(null);
  const areaLabel = area.name
    ? area.name
    : currentLatLng
      ? '지역명 확인 중…'
      : locationReady
        ? '위치 확인 안 됨'
        : '위치 확인 중…';
  const ipApprox = locationReady && currentLatLng && !hasRealLocation;
  const q = query.trim();

  // 통합 검색 (단지명 + 지역) — AddPlanSheet와 동일 로직
  useEffect(() => {
    if (debounceRef.current) window.clearTimeout(debounceRef.current);
    if (!q) { setResults([]); setSearching(false); return; }
    debounceRef.current = window.setTimeout(async () => {
      setSearching(true);
      const hits = await searchAll(q);
      setResults(hits);
      setSearching(false);
    }, 250);
    return () => {
      if (debounceRef.current) window.clearTimeout(debounceRef.current);
    };
  }, [q]);

  function pickResult(r: SearchHit) {
    setQuery('');
    setResults([]);
    setFocused(false);
    inputRef.current?.blur();
    setMapTarget({ lat: r.lat, lng: r.lng });
    refreshComplexesAt({ lat: r.lat, lng: r.lng });
  }

  return (
    <div
      style={
        floating
          ? {
              position: 'absolute',
              top: 0,
              left: 0,
              right: 0,
              zIndex: 20,
              padding: 'calc(var(--safe-top) + 20px) 16px 0',
            }
          : undefined
      }
    >
      <div style={{ position: 'relative' }}>
        <div className="home-search">
          <Icon name="loc" size={18} color="var(--accent)" fill />
          {!focused && !q && (
            <>
              <span className="search-area">{areaLabel}</span>
              <span className="search-div" />
            </>
          )}
          <input
            ref={inputRef}
            className="home-search-in"
            placeholder={focused || q ? '동·도로명 검색' : '다른 지역 검색'}
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onFocus={() => setFocused(true)}
            onBlur={() => {
              // 드롭다운 클릭 처리 시간 확보
              setTimeout(() => setFocused(false), 200);
            }}
          />
          {q ? (
            <button className="home-search-x" onClick={() => { setQuery(''); inputRef.current?.focus(); }} type="button">
              <Icon name="x" size={14} stroke={2.4} />
            </button>
          ) : (
            <Icon name="search" size={17} color="var(--ink-3)" />
          )}
        </div>
        {q && (
          <div className="search-drop">
            {searching && results.length === 0 ? (
              <div className="search-empty">검색 중…</div>
            ) : results.length === 0 ? (
              <div className="search-empty">{`“${q}” 검색 결과가 없어요`}</div>
            ) : (
              results.map((r) => (
                <button
                  key={r.kind + ':' + r.id}
                  className="search-res"
                  onMouseDown={(e) => e.preventDefault()}
                  onClick={() => pickResult(r)}
                  type="button"
                >
                  {r.kind === 'complex' ? (
                    <Icon name="build" size={15} color="var(--accent)" stroke={2.2} />
                  ) : (
                    <Icon name="loc" size={15} color="var(--accent)" />
                  )}
                  <div style={{ flex: 1, textAlign: 'left', minWidth: 0 }}>
                    <div
                      style={{
                        fontWeight: 700,
                        fontSize: 14,
                        whiteSpace: 'nowrap',
                        overflow: 'hidden',
                        textOverflow: 'ellipsis',
                      }}
                    >
                      {r.kind === 'complex' ? r.name : r.dong || r.name}
                    </div>
                    {r.kind === 'complex' ? (
                      <>
                        {r.roadAddr && (
                          <div
                            className="muted"
                            style={{
                              fontSize: 11.5,
                              fontWeight: 600,
                              marginTop: 1,
                              whiteSpace: 'nowrap',
                              overflow: 'hidden',
                              textOverflow: 'ellipsis',
                            }}
                          >
                            {r.roadAddr}
                          </div>
                        )}
                        {r.jibunAddr && (
                          <div
                            className="muted"
                            style={{
                              fontSize: 11,
                              fontWeight: 600,
                              marginTop: 1,
                              whiteSpace: 'nowrap',
                              overflow: 'hidden',
                              textOverflow: 'ellipsis',
                              color: 'var(--ink-4)',
                            }}
                          >
                            <span
                              style={{
                                display: 'inline-block',
                                fontSize: 9.5,
                                fontWeight: 700,
                                padding: '1px 4px',
                                marginRight: 4,
                                background: 'var(--surface-2)',
                                borderRadius: 4,
                                color: 'var(--ink-3)',
                              }}
                            >
                              지번
                            </span>
                            {r.jibunAddr}
                          </div>
                        )}
                      </>
                    ) : (
                      <div className="muted" style={{ fontSize: 11.5, fontWeight: 600, marginTop: 1 }}>
                        {r.gu || r.name}
                      </div>
                    )}
                  </div>
                  <span className="search-cnt">{r.kind === 'complex' ? '단지' : '이동'}</span>
                </button>
              ))
            )}
          </div>
        )}
      </div>
      <div className="segment" style={{ marginTop: 10 }}>
        <div
          className="thumb"
          style={{
            width: 'calc(50% - 3px)',
            transform: `translateX(${view === 'map' ? 'calc(100% + 2px)' : '0'})`,
          }}
        />
        <button
          className={view === 'list' ? 'on' : ''}
          onClick={() => setView('list')}
          type="button"
        >
          목록
        </button>
        <button
          className={view === 'map' ? 'on' : ''}
          onClick={() => setView('map')}
          type="button"
        >
          지도
        </button>
      </div>
    </div>
  );
}

function ProximityBanner({ c, onOpen, onClose }: { c: Complex; onOpen: () => void; onClose: () => void }) {
  const ra = repArea(c);
  return (
    <div className="prox-banner" onClick={onOpen}>
      <div className="prox-ico">
        <span className="prox-wave" />
      </div>
      <div className="grow">
        <div style={{ fontWeight: 700, fontSize: 13.5 }}>{displayName(c)} 근처예요</div>
        <div style={{ fontSize: 11.5, opacity: 0.92, fontWeight: 600, marginTop: 1 }}>
          {`${c.distM ?? '–'}m · ${ra.m2}㎡ ${wonShort(ra.price)} · 음성 안내`}
        </div>
      </div>
      <button
        onClick={(e) => {
          e.stopPropagation();
          onClose();
        }}
        style={{ color: '#fff', opacity: 0.85, padding: 4 }}
        type="button"
      >
        <Icon name="x" size={18} />
      </button>
    </div>
  );
}

function ComplexCard({
  c,
  nearest,
  onOpen,
}: {
  c: Complex;
  nearest: boolean;
  onOpen: () => void;
}) {
  const ra = repArea(c);
  return (
    <div className={'card complex-card' + (nearest ? ' nearest' : '')} onClick={onOpen}>
      <div className="row between" style={{ gap: 12, alignItems: 'center' }}>
        <div style={{ minWidth: 0, flex: 1 }}>
          <div className="row gap6" style={{ minWidth: 0 }}>
            <div
              style={{
                fontWeight: 700,
                fontSize: 15.5,
                letterSpacing: '-.02em',
                whiteSpace: 'nowrap',
                overflow: 'hidden',
                textOverflow: 'ellipsis',
              }}
            >
              {displayName(c)}
            </div>
            {nearest && <span className="near-tag">근처</span>}
          </div>
          <div className="row gap8" style={{ marginTop: 9, flexWrap: 'wrap', rowGap: 6 }}>
            <span className="card-dist">
              <Icon name="loc" size={11} stroke={2.4} />
              {(c.distM ?? 0) + 'm'}
            </span>
            <span
              className="muted"
              style={{ fontSize: 12, fontWeight: 600, whiteSpace: 'nowrap' }}
            >
              {c.type + ' · ' + c.built + '년' + (c.households ? ' · ' + c.households.toLocaleString() + '세대' : '')}
            </span>
          </div>
        </div>
        <div style={{ textAlign: 'right', flexShrink: 0 }}>
          {ra.price > 0 ? (
            <>
              <div className="price-big num">{wonText(ra.price)}</div>
              <div className="price-cap" style={{ marginTop: 3 }}>
                {pyeong(ra.m2) + '평'}
              </div>
            </>
          ) : (
            <div className="price-cap" style={{ color: 'var(--ink-3)' }}>거래 없음</div>
          )}
        </div>
      </div>
    </div>
  );
}

export function HomeList() {
  const { filteredComplexes, openDetail, voiceOn, showProxBanner, setShowProxBanner, proxComplex, showToast } = useApp();
  const sorted = useMemo(
    () => [...filteredComplexes].sort((a, b) => (a.distM ?? 0) - (b.distM ?? 0)),
    [filteredComplexes],
  );
  const nearestId = sorted.find((c) => c.near)?.id ?? null;

  return (
    <div className="screen fade-in">
      <div style={{ background: 'var(--surface)', padding: 'calc(var(--safe-top) + 10px) 22px 12px' }}>
        <BrandHeader onBellClick={() => showToast('새 알림이 없어요')} />
      </div>
      <div style={{ background: 'var(--bg)', padding: '12px 22px 10px' }}>
        <HomeTopBar />
      </div>
      <FilterBar />
      <div className="scroll" style={{ paddingTop: 4 }}>
        {voiceOn && showProxBanner && proxComplex && (
          <ProximityBanner
            c={proxComplex}
            onOpen={() => openDetail(proxComplex.id)}
            onClose={() => setShowProxBanner(false)}
          />
        )}
        <div className="pad" style={{ paddingTop: 12 }}>
          {sorted.length === 0 && (
            <div
              className="muted"
              style={{ textAlign: 'center', padding: '56px 0', fontSize: 13.5, fontWeight: 600 }}
            >
              조건에 맞는 단지가 없어요
            </div>
          )}
          {sorted.map((c) => (
            <ComplexCard
              key={c.id}
              c={c}
              nearest={c.id === nearestId}
              onOpen={() => openDetail(c.id)}
            />
          ))}
        </div>
        <div className="legal">
          실거래가는 국토교통부 신고 자료 기반이며 계약일·신고일 시차로 최신성이 제한될 수 있어요.
          참고용이며 법적 효력은 없습니다.
        </div>
      </div>
    </div>
  );
}

export { HomeTopBar };
