// 시세 지도 / 임장 상세 지도 공용 마커 (시세 지도 디자인 기준 통일)
import { wonShort } from '@/lib/format';
import type { Complex } from '@/types/domain';

const ACCENT = '#3182F6';
const NEAR_COLOR = '#FFB200';
const TYPE_COLOR: Record<string, string> = {
  아파트: '#3182F6',
  오피스텔: '#22C55E',
  빌라: '#F59E0B',
  다가구: '#B69FCF',
};

export interface ComplexMarkerOptions {
  hasNote?: boolean;
  selected?: boolean;
  /** 이미 임장 계획에 담긴 단지 — '담김' 뱃지 + 흐리게 표시 (picker 전용) */
  planned?: boolean;
  /** 우상단 번호 뱃지 (1, 2, …) — picker/trip 코스에서 표시 */
  order?: number;
  onClick?: () => void;
}

/** 시세 지도 마커: 단지명 + min~max 가격 + (옵션) 세대수 + (옵션) 번호 뱃지 + 말풍선 꼬리 */
export function makeComplexMarkerEl(c: Complex, opts: ComplexMarkerOptions = {}): HTMLDivElement {
  const { hasNote = false, selected = false, planned = false, order, onClick } = opts;
  const wrap = document.createElement('div');
  wrap.style.cssText =
    'cursor:pointer;display:flex;justify-content:center;position:relative;' +
    (planned && !selected ? 'opacity:.78;' : '');
  const typeColor = TYPE_COLOR[c.type] ?? '#A0A8B5';
  const bg = selected ? ACCENT : '#FFFFFF';
  const color = selected ? '#FFFFFF' : '#191F28';
  const subColor = selected ? 'rgba(255,255,255,.85)' : '#4E5968';
  const border = hasNote ? NEAR_COLOR : selected ? ACCENT : typeColor;

  if (order != null) {
    const badge = document.createElement('div');
    badge.style.cssText = [
      'position:absolute',
      'top:-8px',
      'left:-8px',
      'min-width:20px',
      'height:20px',
      'border-radius:10px',
      `background:${ACCENT}`,
      'color:#fff',
      'font-weight:800',
      'font-size:11px',
      'display:flex',
      'align-items:center',
      'justify-content:center',
      'padding:0 5px',
      'border:1.5px solid #fff',
      'box-shadow:0 2px 6px rgba(17,24,39,.3)',
      'z-index:2',
    ].join(';');
    badge.textContent = String(order);
    wrap.appendChild(badge);
  }

  // 이미 계획에 담긴 단지: 우상단 '담김' 뱃지
  if (planned && !selected) {
    const pb = document.createElement('div');
    pb.style.cssText = [
      'position:absolute',
      'top:-8px',
      'right:-8px',
      'height:18px',
      'border-radius:9px',
      'background:#4E5968',
      'color:#fff',
      'font-weight:800',
      'font-size:10px',
      'display:flex',
      'align-items:center',
      'justify-content:center',
      'padding:0 6px',
      'border:1.5px solid #fff',
      'box-shadow:0 2px 6px rgba(17,24,39,.3)',
      'z-index:2',
      'white-space:nowrap',
    ].join(';');
    pb.textContent = '담김';
    wrap.appendChild(pb);
  }

  const pill = document.createElement('div');
  pill.style.cssText = [
    'position:relative',
    `background:${bg}`,
    `color:${color}`,
    `border:1.5px solid ${border}`,
    'border-radius:14px',
    'padding:6px 10px',
    'display:flex',
    'flex-direction:column',
    'align-items:center',
    'gap:1px',
    'box-shadow:0 4px 12px rgba(17,24,39,.22)',
    'min-width:60px',
    'max-width:160px',
  ].join(';');

  const nameLine = document.createElement('div');
  nameLine.style.cssText = [
    `color:${subColor}`,
    'font-weight:700',
    'font-size:10.5px',
    'letter-spacing:-.01em',
    'line-height:1.15',
    'max-width:140px',
    'overflow:hidden',
    'text-overflow:ellipsis',
    'white-space:nowrap',
  ].join(';');
  nameLine.textContent = (hasNote ? '★ ' : '') + c.name;

  const priceLine = document.createElement('div');
  priceLine.style.cssText = [
    `color:${color}`,
    'font-weight:900',
    'font-size:13px',
    'line-height:1.1',
    'letter-spacing:-.02em',
    'font-feature-settings:"tnum"',
  ].join(';');
  const prices = (c.areas ?? [])
    .map((a) => {
      const last = a.trend?.[a.trend.length - 1];
      return last?.last ?? last?.max ?? a.price;
    })
    .filter((p) => p > 0);
  if (prices.length > 0) {
    const min = Math.min(...prices);
    const max = Math.max(...prices);
    priceLine.textContent = min === max ? wonShort(min) : `${wonShort(min)}~${wonShort(max)}`;
  } else {
    priceLine.textContent = '거래없음';
    priceLine.style.fontSize = '11px';
    priceLine.style.color = subColor;
  }

  pill.appendChild(nameLine);
  pill.appendChild(priceLine);

  if (c.households) {
    const subLine = document.createElement('div');
    subLine.style.cssText = [
      `color:${subColor}`,
      'font-weight:600',
      'font-size:10px',
      'line-height:1.1',
      'font-feature-settings:"tnum"',
    ].join(';');
    subLine.textContent = `${c.households.toLocaleString()}세대`;
    pill.appendChild(subLine);
  }

  const tail = document.createElement('div');
  tail.style.cssText = [
    'position:absolute',
    'left:50%',
    'bottom:-6px',
    'transform:translateX(-50%)',
    'width:0',
    'height:0',
    'border:6px solid transparent',
    `border-top-color:${bg}`,
    'border-bottom:0',
  ].join(';');
  pill.appendChild(tail);
  wrap.appendChild(pill);

  if (onClick) {
    wrap.addEventListener('click', (e) => {
      e.stopPropagation();
      onClick();
    });
  }
  return wrap;
}

/** 내 위치 표시 마커 (펄스 ring + 점) */
export function makeMeMarkerEl(): HTMLDivElement {
  const wrap = document.createElement('div');
  wrap.style.cssText = 'position:relative;width:18px;height:18px;transform:translate(-50%,-50%)';
  const ring = document.createElement('div');
  ring.style.cssText = 'position:absolute;inset:0;border-radius:50%;background:rgba(49,130,246,.18);animation:imjangPulse 1.8s ease-out infinite';
  const dot = document.createElement('div');
  dot.style.cssText = 'position:absolute;inset:3px;border-radius:50%;background:var(--accent);box-shadow:0 0 0 3px #fff,0 2px 6px rgba(0,0,0,.25)';
  wrap.appendChild(ring);
  wrap.appendChild(dot);
  return wrap;
}

/** polyline leg 중간 거리 라벨 */
export function makeLegLabelEl(text: string): HTMLDivElement {
  const el = document.createElement('div');
  el.style.cssText = [
    'background:rgba(255,255,255,.95)',
    'border:1.5px solid #3182F6',
    'border-radius:10px',
    'padding:2px 7px',
    'font-size:10.5px',
    'font-weight:800',
    'color:#1456C7',
    'box-shadow:0 2px 6px rgba(17,24,39,.18)',
    'white-space:nowrap',
    'pointer-events:none',
  ].join(';');
  el.textContent = text;
  return el;
}
