import { useEffect, useRef, useState } from 'react';
import type { Member } from '@/components/Avatar';
import { useApp } from '@/store/AppStore';
import {
  loadPlanMembers,
  loadPlanComments,
  addPlanComment,
  subscribePlanComments,
  type PlanComment,
} from '@/services/collab';

/**
 * 한 계획(batch)의 멤버 메모(채팅) 상태를 공유하는 훅.
 * 상세화면 미리보기와 채팅 화면이 동일 로직을 쓰도록 추출.
 */
export function usePlanComments(batchId: string) {
  const { user, friends } = useApp();
  const [comments, setComments] = useState<PlanComment[]>([]);
  const [members, setMembers] = useState<Member[]>([]);

  // 실시간 INSERT의 작성자 이름 해석 (멤버 + 나)
  const nameForRef = useRef<(id: string) => string>(() => '게스트');
  nameForRef.current = (id: string) => {
    if (user && id === user.id) return user.displayName || '나';
    return members.find((m) => m.id === id)?.name || '게스트';
  };

  useEffect(() => {
    if (!batchId) return;
    let alive = true;
    void (async () => {
      const [m, cs] = await Promise.all([loadPlanMembers(batchId), loadPlanComments(batchId)]);
      if (!alive) return;
      setMembers(m);
      setComments(cs);
    })();
    const unsub = subscribePlanComments(batchId, (row) => {
      setComments((prev) => {
        if (prev.some((c) => c.id === row.id)) return prev; // 중복 방지
        return [
          ...prev,
          {
            id: row.id,
            batchId,
            authorId: row.author_id,
            authorName: nameForRef.current(row.author_id),
            text: row.text,
            createdAt: new Date(row.created_at).getTime(),
          },
        ];
      });
    });
    return () => {
      alive = false;
      unsub();
    };
  }, [batchId]);

  async function reloadMembers() {
    setMembers(await loadPlanMembers(batchId));
  }

  async function send(text: string): Promise<boolean> {
    const t = text.trim();
    if (!t) return false;
    const ok = await addPlanComment(batchId, t);
    if (!ok) return false;
    // 실시간 누락 대비 즉시 재로드 (중복은 id로 제거)
    const cs = await loadPlanComments(batchId);
    setComments((prev) => {
      const ids = new Set(prev.map((c) => c.id));
      const fresh = cs.filter((c) => !ids.has(c.id));
      return fresh.length ? [...prev, ...fresh] : prev;
    });
    return true;
  }

  // 작성자 표시명 — 내가 지정한 별명이 있으면 "별명 (사용자명)"
  const displayAuthor = (authorId: string, fallback: string): string => {
    const f = friends.find((x) => x.id === authorId);
    if (f?.alias) return `${f.alias} (${f.baseName})`;
    return f?.baseName || fallback;
  };

  return { comments, members, reloadMembers, send, displayAuthor };
}
