// Haversine 거리 (미터). 임장 거리 계산은 ~수십~수백 m 수준이라 평면근사도 가능하지만 표준 공식 사용.
const R = 6371000;

export interface LatLng {
  lat: number;
  lng: number;
}

export function distanceM(a: LatLng, b: LatLng): number {
  const dLat = toRad(b.lat - a.lat);
  const dLng = toRad(b.lng - a.lng);
  const lat1 = toRad(a.lat);
  const lat2 = toRad(b.lat);
  const x =
    Math.sin(dLat / 2) ** 2 +
    Math.sin(dLng / 2) ** 2 * Math.cos(lat1) * Math.cos(lat2);
  return 2 * R * Math.asin(Math.sqrt(x));
}

export function totalTrailM(points: LatLng[]): number {
  let sum = 0;
  for (let i = 1; i < points.length; i++) {
    sum += distanceM(points[i - 1], points[i]);
  }
  return sum;
}

function toRad(deg: number): number {
  return (deg * Math.PI) / 180;
}

/** GPS jitter 무시 임계값(m) — 트레일 포인트 추가 여부 판단용 */
export const TRAIL_MIN_DELTA_M = 8;
/** 단지 근접 안내 임계값(m) */
export const PROXIMITY_RADIUS_M = 80;
/** 근접 해제(이탈) 임계값(m) — 재진입 안내 가능해지는 거리 */
export const PROXIMITY_EXIT_M = 160;
