function dt(v: string): string {
  if (!v) return '';
  const d = new Date(v + 'T00:00:00');
  const DOW = ['일', '월', '화', '수', '목', '금', '토'];
  return `${d.getMonth() + 1}월 ${d.getDate()}일 (${DOW[d.getDay()]})`;
}

/** 큰 사진은 긴 변 maxDim 이하로 리사이즈 + JPEG 재인코딩해 용량을 줄인다. 실패/소형이면 원본 반환. */
async function compressImage(blob: Blob, maxDim = 1600, quality = 0.8): Promise<Blob> {
  // 작은 파일은 그대로 (불필요한 재인코딩 방지)
  if (blob.size <= 700 * 1024) return blob;
  try {
    const url = URL.createObjectURL(blob);
    const img = await new Promise<HTMLImageElement>((res, rej) => {
      const im = new Image();
      im.onload = () => res(im);
      im.onerror = rej;
      im.src = url;
    });
    const scale = Math.min(1, maxDim / Math.max(img.width, img.height));
    const w = Math.max(1, Math.round(img.width * scale));
    const h = Math.max(1, Math.round(img.height * scale));
    const canvas = document.createElement('canvas');
    canvas.width = w;
    canvas.height = h;
    const ctx = canvas.getContext('2d');
    if (!ctx) {
      URL.revokeObjectURL(url);
      return blob;
    }
    ctx.drawImage(img, 0, 0, w, h);
    const out = await new Promise<Blob | null>((res) => canvas.toBlob(res, 'image/jpeg', quality));
    URL.revokeObjectURL(url);
    // 압축본이 더 작을 때만 사용
    return out && out.size < blob.size ? out : blob;
  } catch {
    return blob;
  }
}

const PHOTO_COLORS = [
  '#E8D5C4', '#C9B9A8', '#D6C3B0', '#C7D3C0',
  '#BFC9D1', '#D9E0CE', '#E2D2C0', '#B8C7AE',
];

const RATING_LABELS = ['', '별로예요', '그저 그래요', '괜찮아요', '좋아요', '최고예요'];

export function ComplexNote({ id, readOnly = false, viewNote }: { id: string; readOnly?: boolean; viewNote?: MemberNote }) {
  const { complexes, notes, plans, friends, popOverlay, saveNote, user, showToast } = useApp();
  const c = complexById(complexes, id);
  // 읽기 전용(멤버 노트 보기)이면 전달받은 노트, 아니면 내 노트
  const existing =
    readOnly && viewNote
      ? viewNote
      : notes[id] ?? { rating: 0, checks: {}, photos: [], oneliner: '', shared: false };
  const [rating, setRating] = useState<number>(existing.rating ?? 0);
  const [checks, setChecks] = useState<Record<string, EvalState>>({ ...(existing.checks ?? {}) });
  const [photos, setPhotos] = useState<PhotoRef[]>([...(existing.photos ?? [])]);
  const [oneliner, setOneliner] = useState(existing.oneliner ?? '');
  const [shared, setShared] = useState<boolean>(existing.shared ?? false);
  // 이 단지가 임장 계획에 담겨 있을 때만 계획 멤버 공유 토글 노출
  const inPlan = plans.some((p) => p.complexId === id);
  // 친구 직접 공유 — 선택한 친구 id 목록 (계획 멤버 여부와 무관)
  const [shareFriends, setShareFriends] = useState<string[]>([]);
  const [friendPickOpen, setFriendPickOpen] = useState(false);
  const [activeTab, setActiveTab] = useState(0);

  // 내가 이미 이 노트를 공유한 친구 목록 로드 (편집 시)
  useEffect(() => {
    if (readOnly) return;
    let alive = true;
    void loadNoteShares(id).then((ids) => { if (alive) setShareFriends(ids); });
    return () => { alive = false; };
  }, [id, readOnly]);
  const [dir, setDir] = useState(1);
  const [busy, setBusy] = useState(false);
  const [askMan, setAskMan] = useState<string>('');

  if (!c) {
    return (
      <div>
        <div className="sheet-scrim" onClick={popOverlay} />
        <div className="sheet" style={{ height: '40%' }}>
          <div className="sheet-grip" />
          <div className="pad" style={{ padding: 24 }}>단지 정보를 찾을 수 없어요.</div>
        </div>
      </div>
    );
  }

  const evalDone = Object.keys(checks).filter((k) => checks[k]).length;

  const noteTabs = [
    { key: 'price', name: '가격', icon: 'won' },
    { key: 'photo', name: '사진', icon: 'photo' },
    ...CHECKLIST.map((cat) => ({ key: cat.id, name: cat.name, icon: cat.icon })),
    { key: 'memo', name: '한줄평', icon: 'record' },
  ];

  function goTab(i: number) {
    setDir(i > activeTab ? 1 : -1);
    setActiveTab(i);
  }
  function setCheck(k: string, v: EvalState) {
    setChecks((p) => {
      const n = { ...p };
      if (n[k] === v) delete n[k];
      else n[k] = v;
      return n;
    });
  }
  function delPhoto(i: number) {
    setPhotos((p) => p.filter((_, x) => x !== i));
  }

  async function addPhoto() {
    try {
      setBusy(true);
      const photo = await Camera.getPhoto({
        quality: 78,
        resultType: CameraResultType.Uri,
        source: CameraSource.Prompt,
        promptLabelHeader: '사진 추가',
        promptLabelPicture: '촬영',
        promptLabelPhoto: '앨범에서 선택',
        promptLabelCancel: '취소',
        saveToGallery: false,
      });
      // webPath는 웹에선 blob:, 네이티브에선 capacitor:// 로컬 URL — 둘 다 fetch 가능
      const uri = photo.webPath ?? photo.path ?? '';
      let lat: number | undefined;
      let lng: number | undefined;
      try {
        const pos = await getCurrentPosition();
        lat = pos.lat;
        lng = pos.lng;
      } catch {
        /* ignore */
      }
      const t = Date.now();
      let finalUri = uri;
      // Supabase Storage 업로드 — 로그인 상태면 항상 업로드(웹/네이티브 공통). 공개 URL로 저장돼 공유에서도 보임.
      const sb = getSupabase();
      if (sb && user && uri) {
        try {
          const raw = await fetch(uri).then((r) => r.blob());
          // 용량이 크면 압축(리사이즈+JPEG)해서 업로드
          const blob = await compressImage(raw);
          const isPng = blob.type.includes('png');
          const ext = isPng ? 'png' : 'jpg';
          const contentType = isPng ? 'image/png' : 'image/jpeg';
          const path = `${user.id}/${c!.id}/${t}.${ext}`;
          const { error } = await sb.storage.from('imjang-photos').upload(path, blob, {
            contentType,
            upsert: false,
          });
          if (error) throw error;
          const { data } = sb.storage.from('imjang-photos').getPublicUrl(path);
          finalUri = data.publicUrl;
        } catch (e) {
          console.warn('사진 업로드 실패, 로컬 URI 사용', e);
          showToast('사진 업로드에 실패해 이 기기에만 표시돼요');
        }
      } else if (!user) {
        showToast('로그인하면 사진이 안전하게 저장돼요');
      }
      setPhotos((p) => [...p, { uri: finalUri, lat, lng, t }]);
    } catch (e: unknown) {
      // 사용자 취소
      if (!String((e as Error).message ?? e).includes('cancel')) {
        // 폴백: 데모용 컬러 카드
        setPhotos((p) => [...p, { uri: PHOTO_COLORS[(p.length + id.length) % PHOTO_COLORS.length], color: PHOTO_COLORS[(p.length + id.length) % PHOTO_COLORS.length] }]);
      }
    } finally {
      setBusy(false);
    }
  }

  async function save() {
    setBusy(true);
    try {
      // 친구 공유 대상 저장 (계획 멤버 공유는 note.shared로 별도 저장)
      await setNoteShares(id, shareFriends);
      await saveNote(id, { rating, checks, photos, oneliner, shared });
    } finally {
      setBusy(false);
    }
  }

  function renderPhotos() {
    if (readOnly && photos.length === 0) {
      return (
        <div className="card" style={{ padding: '24px 0', textAlign: 'center' }}>
          <div className="muted" style={{ fontSize: 12.5, fontWeight: 600 }}>등록된 사진이 없어요</div>
        </div>
      );
    }
    return (
      <div>
        {!readOnly && (
          <div className="sect-cap" style={{ marginBottom: 10, marginLeft: 2 }}>
            촬영 시 위치·시각이 자동 기록돼요
          </div>
        )}
        <div className="photo-grid">
          {photos.map((p, i) => {
            const isColor = (p.color ?? p.uri).startsWith('#');
            return (
              <div
                key={i}
                className="photo-cell"
                style={isColor ? { background: p.color ?? p.uri } : undefined}
              >
                {!isColor && <img src={p.uri} alt="" />}
                {isColor && (
                  <div
                    style={{
                      position: 'absolute',
                      inset: 0,
                      background:
                        'linear-gradient(160deg,rgba(255,255,255,.25),rgba(0,0,0,.12))',
                    }}
                  />
                )}
                {p.lat != null && p.lng != null && (
                  <span className="geo num">
                    {p.lat.toFixed(2)}·{p.lng.toFixed(2)}
                  </span>
                )}
                {!readOnly && (
                  <button className="photo-del" onClick={() => delPhoto(i)} type="button">
                    <Icon name="x" size={11} />
                  </button>
                )}
              </div>
            );
          })}
          {!readOnly && (
            <button className="photo-add" onClick={addPhoto} type="button" disabled={busy}>
              <Icon name="camera" size={20} />
              촬영
            </button>
          )}
        </div>
      </div>
    );
  }
  function renderChecklist(catIdx: number) {
    const cat = CHECKLIST[catIdx];
    return (
      <div>
        {cat.note && (
          <div className="cat-note" style={{ marginBottom: 9, marginLeft: 2 }}>
            ※ {cat.note}에만 해당
          </div>
        )}
        <div className="card" style={{ padding: '2px 16px' }}>
          {cat.items.map((it) => (
            <div key={it.key} className="eval-row">
              <div>
                <div className="eval-label">{it.label}</div>
                <div className="eval-guide">{it.guide}</div>
              </div>
              <div className="eval-seg">
                {EVAL_STATES.map((s) => (
                  <button
                    key={s.value}
                    className={checks[it.key] === s.value ? 'on ' + s.value : ''}
                    onClick={() => !readOnly && setCheck(it.key, s.value)}
                    disabled={readOnly}
                    style={readOnly ? { cursor: 'default', opacity: checks[it.key] === s.value ? 1 : 0.5 } : undefined}
                    type="button"
                  >
                    {s.label}
                  </button>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  }
  function renderMemo() {
    return (
      <div>
        {!readOnly && (
          <div className="sect-cap" style={{ marginBottom: 10, marginLeft: 2 }}>
            이 단지의 인상을 한 줄로 남겨보세요
          </div>
        )}
        <textarea
          value={oneliner}
          onChange={(e) => setOneliner(e.target.value)}
          readOnly={readOnly}
          placeholder={readOnly ? '작성한 한줄평이 없어요' : '예) 숲길 바로 앞, 채광 좋고 주차는 빡빡함'}
          style={{
            width: '100%',
            minHeight: 120,
            resize: 'none',
            border: 'none',
            background: 'var(--surface)',
            borderRadius: 16,
            padding: 16,
            fontFamily: 'inherit',
            fontSize: 13.5,
            fontWeight: 500,
            color: 'var(--ink)',
            boxShadow: 'var(--sh-card)',
            lineHeight: 1.6,
          }}
        />
      </div>
    );
  }
  function renderPrice() {
    const ra = repArea(c!);
    const askVal = askMan.trim() === '' ? null : Number(askMan);
    const hasAsk = askVal != null && !isNaN(askVal) && askVal > 0;
    const diff = hasAsk ? askVal - ra.price : 0;
    return (
      <div>
        <div className="price-now-card">
          <div className="row between" style={{ alignItems: 'flex-end' }}>
            <div>
              <div className="sect-cap">
                {hasAsk ? '이 매물 금액' : `대표 ${pyeong(ra.m2)}평 실거래가`}
              </div>
              <div
                className="num"
                style={{
                  fontWeight: 900,
                  fontSize: 26,
                  letterSpacing: '-.04em',
                  marginTop: 3,
                  color: hasAsk ? 'var(--accent)' : 'var(--ink)',
                }}
              >
                {wonText(hasAsk ? (askVal as number) : ra.price)}
              </div>
            </div>
            <span className="note-badge">{hasAsk ? '입력 금액' : '실거래 기준'}</span>
          </div>
          {hasAsk && diff !== 0 && (
            <div
              className="price-diff"
              style={{ color: diff > 0 ? 'var(--bad)' : 'var(--accent)' }}
            >
              <Icon name="trend" size={13} stroke={2.4} />
              {`실거래가 대비 ${diff > 0 ? '+' : '-'}${wonText(Math.abs(diff))}`}
            </div>
          )}
        </div>
        {!readOnly && (
          <>
            <div className="sect-cap" style={{ margin: '18px 2px 8px' }}>
              이 매물 금액 직접 입력
            </div>
            <div className="price-input-wrap">
              <input
                className="price-input num"
                type="text"
                inputMode="numeric"
                placeholder={ra.price.toLocaleString()}
                value={askMan ? Number(askMan).toLocaleString() : ''}
                onChange={(e) => setAskMan(e.target.value.replace(/[^0-9]/g, ''))}
              />
              <span className="price-unit-lab">만원</span>
            </div>
            {hasAsk && (
              <button type="button" className="price-clear" onClick={() => setAskMan('')}>
                실거래가로 되돌리기
              </button>
            )}
            <div
              className="muted"
              style={{
                fontSize: 11.5,
                fontWeight: 600,
                marginTop: 14,
                marginLeft: 2,
                lineHeight: 1.5,
              }}
            >
              {`입력하지 않으면 국토부 실거래가(${wonText(ra.price)})로 표시돼요. 호가·제시 금액을 입력하면 그 금액으로 바뀝니다.`}
            </div>
          </>
        )}
      </div>
    );
  }
  function renderSchedule() {
    // 임장 일정의 단일 출처는 '임장 계획'(plans) — 이 단지가 포함된 계획의 날짜를 반영
    const date = plans
      .filter((p) => p.complexId === id && p.plannedDate)
      .map((p) => p.plannedDate as string)
      .sort()[0];
    if (!date) {
      return (
        <div className="sched-empty">
          <div className="sched-empty-ic">
            <Icon name="calendar" size={24} />
          </div>
          <div style={{ fontWeight: 700, fontSize: 14, color: 'var(--ink-2)' }}>
            예정된 임장 일정이 없어요
          </div>
          <div
            className="muted"
            style={{ fontSize: 12.5, fontWeight: 600, marginTop: 4, lineHeight: 1.5 }}
          >
            임장 탭에서 계획에 추가하면 일정이 표시돼요
          </div>
        </div>
      );
    }
    const today = new Date().toISOString().slice(0, 10);
    const visited = date < today;
    return (
      <div className="sched-row" style={{ cursor: 'default' }}>
        <div className={'sched-row-ic' + (visited ? ' visited' : '')}>
          <Icon name={visited ? 'check' : 'calendar'} size={18} stroke={2.2} />
        </div>
        <div style={{ flex: 1, textAlign: 'left', minWidth: 0 }}>
          <div className="sched-row-lab">{visited ? '다녀온 날' : '임장일'}</div>
          <div className="sched-row-date num">{dt(date)}</div>
        </div>
      </div>
    );
  }
  function renderPanel() {
    const key = noteTabs[activeTab].key;
    if (key === 'price') return renderPrice();
    if (key === 'photo') return renderPhotos();
    if (key === 'memo') return renderMemo();
    const ci = CHECKLIST.findIndex((cat) => cat.id === key);
    return renderChecklist(ci);
  }

  return (
    <div>
      <div className="sheet-scrim" onClick={popOverlay} />
      <div className="sheet" style={{ height: '92%' }}>
        <div className="sheet-grip" />
        <div className="row between pad" style={{ padding: '4px 20px 8px' }}>
          <div>
            <div style={{ fontWeight: 800, fontSize: 17, letterSpacing: '-.02em' }}>
              {readOnly && viewNote ? `${viewNote.authorName}님의 임장노트` : '임장노트'}
            </div>
            <div className="muted" style={{ fontSize: 12, fontWeight: 600, marginTop: 1 }}>
              {c.name}
            </div>
          </div>
          <button onClick={popOverlay} style={{ color: 'var(--ink-3)', padding: 4 }} type="button">
            <Icon name="x" size={20} />
          </button>
        </div>
        <div className="scroll" style={{ paddingBottom: 'calc(env(safe-area-inset-bottom) + 148px)' }}>
          <div className="pad" style={{ paddingTop: 6 }}>
            <div className="card" style={{ padding: 16, textAlign: 'center' }}>
              <div className="sect-cap" style={{ marginBottom: 8 }}>
                이 단지, 총평 별점
              </div>
              <div style={{ display: 'flex', justifyContent: 'center' }}>
                <Stars rating={rating} size="lg" interactive={!readOnly} onRate={setRating} />
              </div>
              {rating > 0 && (
                <div
                  style={{ marginTop: 6, fontWeight: 700, color: 'var(--accent)', fontSize: 13 }}
                >
                  {RATING_LABELS[rating]}
                </div>
              )}
            </div>
            <div style={{ height: 12 }} />
            {renderSchedule()}
            {inPlan && !readOnly && (
              <button
                type="button"
                className="card"
                onClick={() => setShared((v) => !v)}
                style={{
                  width: '100%',
                  marginTop: 12,
                  padding: '13px 16px',
                  display: 'flex',
                  alignItems: 'center',
                  gap: 12,
                  border: 'none',
                  cursor: 'pointer',
                  textAlign: 'left',
                }}
              >
                <div
                  style={{
                    width: 34,
                    height: 34,
                    borderRadius: 10,
                    background: shared ? 'var(--accent-tint)' : 'var(--surface-2)',
                    color: shared ? 'var(--accent)' : 'var(--ink-3)',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    flexShrink: 0,
                  }}
                >
                  <Icon name={shared ? 'people' : 'user'} size={18} stroke={2.2} />
                </div>
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ fontWeight: 700, fontSize: 14 }}>계획 멤버에게 공유</div>
                  <div className="muted" style={{ fontSize: 11.5, fontWeight: 600, marginTop: 1 }}>
                    {shared ? '같은 계획 멤버가 이 노트를 볼 수 있어요' : '계획 멤버에게는 비공개예요'}
                  </div>
                </div>
                <span className={'voice-toggle' + (shared ? ' on' : '')} style={{ pointerEvents: 'none' }}>
                  <span className="sw" />
                </span>
              </button>
            )}
            {!readOnly && (
              <button
                type="button"
                className="card"
                onClick={() => setFriendPickOpen(true)}
                style={{
                  width: '100%',
                  marginTop: 12,
                  padding: '13px 16px',
                  display: 'flex',
                  alignItems: 'center',
                  gap: 12,
                  border: 'none',
                  cursor: 'pointer',
                  textAlign: 'left',
                }}
              >
                <div
                  style={{
                    width: 34,
                    height: 34,
                    borderRadius: 10,
                    background: shareFriends.length > 0 ? 'var(--accent-tint)' : 'var(--surface-2)',
                    color: shareFriends.length > 0 ? 'var(--accent)' : 'var(--ink-3)',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    flexShrink: 0,
                  }}
                >
                  <Icon name="people" size={18} stroke={2.2} />
                </div>
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ fontWeight: 700, fontSize: 14 }}>친구에게 공유</div>
                  <div className="muted" style={{ fontSize: 11.5, fontWeight: 600, marginTop: 1 }}>
                    {shareFriends.length > 0
                      ? `친구 ${shareFriends.length}명이 이 노트를 볼 수 있어요`
                      : '계획 멤버가 아니어도 친구를 지정해 공유해요'}
                  </div>
                </div>
                <Icon name="chevR" size={17} color="var(--ink-4)" />
              </button>
            )}
          </div>
          <div className="cat-tabs" style={{ marginTop: 18 }}>
            {noteTabs.map((tb, i) => (
              <button
                key={tb.key}
                className={'cat-tab' + (i === activeTab ? ' on' : '')}
                onClick={() => goTab(i)}
                type="button"
              >
                <Icon name={tb.icon} size={14} />
                {tb.name}
              </button>
            ))}
          </div>
          <div className="tab-viewport pad" style={{ marginTop: 14 }}>
            <div key={activeTab} className={dir > 0 ? 'tab-slide-r' : 'tab-slide-l'}>
              {renderPanel()}
            </div>
          </div>
          <div style={{ height: 104 }} />
        </div>
        <div
          style={{
            position: 'absolute',
            left: 0,
            right: 0,
            bottom: 0,
            padding: '12px 20px calc(env(safe-area-inset-bottom) + 20px)',
            background: 'linear-gradient(180deg,rgba(255,255,255,0),#fff 28%)',
          }}
        >
          {readOnly ? (
            <div
              className="card"
              style={{ padding: '13px 16px', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 6 }}
            >
              <Icon name="user" size={15} color="var(--ink-3)" stroke={2} />
              <span className="muted" style={{ fontSize: 12.5, fontWeight: 700 }}>
                {`${viewNote?.authorName ?? '멤버'}님의 노트 · 읽기 전용`}
              </span>
            </div>
          ) : (
            <>
              <div className="row between" style={{ marginBottom: 8, padding: '0 2px' }}>
                <span className="sect-cap">{`평가 ${evalDone}/${CHECKLIST_TOTAL} · 사진 ${photos.length}장`}</span>
                <span className="sect-cap">오늘 세션에 저장</span>
              </div>
              <button className="btn btn-primary" onClick={save} type="button" disabled={busy}>
                <Icon name="check" size={20} />
                {busy ? '저장 중…' : '저장하고 세션에 추가'}
              </button>
            </>
          )}
        </div>
      </div>
      {friendPickOpen && (
        <FriendPickSheet
          friends={friends}
          selected={shareFriends}
          onToggle={(fid) =>
            setShareFriends((prev) => (prev.includes(fid) ? prev.filter((x) => x !== fid) : [...prev, fid]))
          }
          onClose={() => setFriendPickOpen(false)}
        />
      )}
    </div>
  );
}

function FriendPickSheet({
  friends,
  selected,
  onToggle,
  onClose,
}: {
  friends: Friend[];
  selected: string[];
  onToggle: (friendId: string) => void;
  onClose: () => void;
}) {
  return (
    <div className="sheet-scrim" onClick={onClose} style={{ zIndex: 140 }}>
      <div className="filter-sheet" onClick={(e) => e.stopPropagation()} style={{ maxHeight: '80%', overflowY: 'auto' }}>
        <div className="sheet-grip" />
        <div className="row between" style={{ marginBottom: 4, padding: '0 2px' }}>
          <div style={{ fontWeight: 800, fontSize: 18, letterSpacing: '-.02em' }}>친구에게 공유</div>
          <button type="button" onClick={onClose} style={{ color: 'var(--ink-3)', padding: 4, background: 'none', border: 'none', cursor: 'pointer' }}>
            <Icon name="x" size={20} />
          </button>
        </div>
        <div className="muted" style={{ fontSize: 12.5, fontWeight: 600, margin: '8px 2px 16px', lineHeight: 1.5 }}>
          선택한 친구가 이 단지의 내 임장노트를 볼 수 있어요. 계획 멤버가 아니어도 공유돼요.
        </div>
        {friends.length === 0 ? (
          <div className="card" style={{ padding: '24px 0', textAlign: 'center', marginBottom: 14 }}>
            <div className="muted" style={{ fontSize: 12.5, fontWeight: 600 }}>친구가 없어요</div>
            <div className="muted" style={{ fontSize: 12, fontWeight: 600, marginTop: 4 }}>친구 탭에서 친구를 추가해보세요</div>
          </div>
        ) : (
          <div className="card" style={{ padding: '4px 14px', marginBottom: 14 }}>
            {friends.map((f, i) => {
              const on = selected.includes(f.id);
              return (
                <div key={f.id} className={'member-row' + (i ? ' br' : '')} onClick={() => onToggle(f.id)} style={{ cursor: 'pointer' }}>
                  <Avatar m={f} size={34} />
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ fontWeight: 700, fontSize: 14, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{f.name}</div>
                    <div className="num muted" style={{ fontSize: 11, fontWeight: 600, marginTop: 1 }}>{f.id.slice(0, 8)}</div>
                  </div>
                  <div
                    style={{
                      width: 24,
                      height: 24,
                      borderRadius: '50%',
                      flexShrink: 0,
                      background: on ? 'var(--accent)' : 'var(--surface-2)',
                      color: '#fff',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                    }}
                  >
                    {on && <Icon name="check" size={15} stroke={2.6} />}
                  </div>
                </div>
              );
            })}
          </div>
        )}
        <button type="button" className="btn btn-primary" style={{ marginBottom: 12 }} onClick={onClose}>
          {selected.length > 0 ? `${selected.length}명 선택 완료` : '완료'}
        </button>
      </div>
    </div>
  );
}
