import type { ComplexNote, ImjangSession, TrailPoint } from '@/types/domain';
import { getSupabase } from '@/lib/supabase';
// 시드는 더 이상 폴백으로 쓰지 않는다 — 익명/오프라인은 빈 데이터, 실데이터는 Supabase에서.
import { Preferences } from '@capacitor/preferences';
import { totalTrailM, TRAIL_MIN_DELTA_M, distanceM } from '@/lib/geo';
import { formatDateLabel, relativeDay } from '@/lib/format';

const LOCAL_SESSIONS_KEY = 'imjang_sessions_v1';
const LOCAL_NOTES_KEY = 'imjang_notes_v1';

type StoredNote = Omit<ComplexNote, 'complexId' | 'sessionId'>;

// =================== 로드 ===================

export async function loadSessionsForUser(userId: string | null): Promise<ImjangSession[]> {
  const sb = getSupabase();
  if (sb && userId) {
    try {
      const { data, error } = await sb
        .from('imjang_sessions')
        .select('id, date, area_name, live, distance_m, duration_min, complex_ids, trail_points')
        .eq('user_id', userId)
        .order('date', { ascending: false });
      if (error) throw error;
      return (data ?? []).map((r: any) => ({
        id: r.id,
        date: r.date,
        dateLabel: formatDateLabel(r.date),
        day: r.live ? '오늘' : relativeDay(r.date),
        areaName: r.area_name,
        live: !!r.live,
        distanceM: r.distance_m ?? 0,
        durationMin: r.duration_min ?? 0,
        complexIds: r.complex_ids ?? [],
        trailPoints: r.trail_points ?? [],
      }));
    } catch (e) {
      console.warn('세션 로드 실패, 로컬 사용', e);
    }
  }
  // 로컬 폴백 (익명/오프라인) — 시드 없음.
  try {
    const { value } = await Preferences.get({ key: LOCAL_SESSIONS_KEY });
    if (value) return JSON.parse(value) as ImjangSession[];
  } catch {
    /* ignore */
  }
  return [];
}

export async function loadNotesForUser(userId: string | null): Promise<Record<string, StoredNote> | null> {
  const sb = getSupabase();
  if (sb && userId) {
    try {
      const { data, error } = await sb
        .from('complex_notes')
        .select('complex_id, rating, checks, photos, oneliner, shared, created_at')
        .eq('user_id', userId);
      if (error) throw error;
      const map: Record<string, StoredNote> = {};
      for (const r of (data ?? []) as any[]) {
        map[r.complex_id] = {
          rating: r.rating ?? 0,
          checks: r.checks ?? {},
          photos: r.photos ?? [],
          oneliner: r.oneliner ?? '',
          shared: r.shared ?? false,
          createdAt: r.created_at ? new Date(r.created_at).getTime() : Date.now(),
        };
      }
      return map;
    } catch (e) {
      console.warn('노트 로드 실패, 로컬 사용', e);
    }
  }
  try {
    const { value } = await Preferences.get({ key: LOCAL_NOTES_KEY });
    if (value) return JSON.parse(value) as Record<string, StoredNote>;
  } catch {
    /* ignore */
  }
  return {};
}

// =================== 라이브 세션 ===================

export async function ensureLiveSession(userId: string | null, areaName: string): Promise<ImjangSession> {
  const today = new Date().toISOString().slice(0, 10);
  const sb = getSupabase();
  if (sb && userId) {
    try {
      const { data: existing } = await sb
        .from('imjang_sessions')
        .select('id, date, area_name, live, distance_m, duration_min, complex_ids, trail_points')
        .eq('user_id', userId)
        .eq('date', today)
        .maybeSingle();
      if (existing) {
        return rowToSession(existing);
      }
      const { data: ins, error } = await sb
        .from('imjang_sessions')
        .insert({
          user_id: userId,
          date: today,
          area_name: areaName,
          live: true,
          distance_m: 0,
          duration_min: 0,
          complex_ids: [],
          trail_points: [],
        })
        .select()
        .single();
      if (error) throw error;
      return rowToSession(ins);
    } catch (e) {
      console.warn('라이브 세션 동기화 실패, 로컬 임시 사용', e);
    }
  }
  // 로컬/익명 폴백
  const local: ImjangSession = {
    id: 'local-' + today,
    date: today,
    dateLabel: formatDateLabel(today),
    day: '오늘',
    areaName,
    live: true,
    distanceM: 0,
    durationMin: 0,
    complexIds: [],
    trailPoints: [],
  };
  return local;
}

function rowToSession(r: any): ImjangSession {
  return {
    id: r.id,
    date: r.date,
    dateLabel: formatDateLabel(r.date),
    day: r.live ? '오늘' : relativeDay(r.date),
    areaName: r.area_name,
    live: !!r.live,
    distanceM: r.distance_m ?? 0,
    durationMin: r.duration_min ?? 0,
    complexIds: r.complex_ids ?? [],
    trailPoints: r.trail_points ?? [],
  };
}

// =================== 트레일 ===================

const pendingTrail: Record<string, TrailPoint[]> = {};
const flushTimers: Record<string, number> = {};
const sessionStart: Record<string, number> = {};

export async function appendTrailPoint(sessionId: string, p: TrailPoint): Promise<void> {
  const arr = (pendingTrail[sessionId] ??= []);
  const last = arr[arr.length - 1];
  if (last && distanceM(last, p) < TRAIL_MIN_DELTA_M) return; // 작은 떨림 무시
  arr.push(p);
  if (!sessionStart[sessionId]) sessionStart[sessionId] = p.t;
  if (flushTimers[sessionId]) return;
  flushTimers[sessionId] = window.setTimeout(() => flushTrail(sessionId), 2500);
}

async function flushTrail(sessionId: string): Promise<void> {
  delete flushTimers[sessionId];
  const points = pendingTrail[sessionId];
  if (!points || !points.length) return;
  const sb = getSupabase();
  if (sb && !sessionId.startsWith('local-')) {
    try {
      // 기존 trail_points와 머지
      const { data } = await sb
        .from('imjang_sessions')
        .select('trail_points, distance_m, duration_min, date')
        .eq('id', sessionId)
        .maybeSingle();
      const existing: TrailPoint[] = (data?.trail_points as any) ?? [];
      const merged = [...existing, ...points];
      const dist = Math.round(totalTrailM(merged));
      const start = sessionStart[sessionId] ?? merged[0]?.t ?? Date.now();
      const durMin = Math.max(1, Math.round((Date.now() - start) / 60000));
      await sb
        .from('imjang_sessions')
        .update({ trail_points: merged, distance_m: dist, duration_min: durMin })
        .eq('id', sessionId);
    } catch (e) {
      console.warn('trail flush 실패', e);
    }
  }
  pendingTrail[sessionId] = [];
}

// =================== 노트 저장 ===================

export async function saveNote(
  userId: string | null,
  sessionId: string,
  complexId: string,
  note: StoredNote,
): Promise<void> {
  const sb = getSupabase();
  if (sb && userId) {
    try {
      await sb.from('complex_notes').upsert(
        {
          user_id: userId,
          session_id: sessionId.startsWith('local-') ? null : sessionId,
          complex_id: complexId,
          rating: note.rating,
          checks: note.checks,
          photos: note.photos,
          oneliner: note.oneliner,
          shared: note.shared ?? false,
          created_at: new Date(note.createdAt).toISOString(),
        },
        { onConflict: 'user_id,complex_id' },
      );
      // 세션 complexIds 갱신
      if (!sessionId.startsWith('local-')) {
        const { data } = await sb
          .from('imjang_sessions')
          .select('complex_ids')
          .eq('id', sessionId)
          .maybeSingle();
        const ids: string[] = (data?.complex_ids as string[]) ?? [];
        if (!ids.includes(complexId)) {
          ids.push(complexId);
          await sb.from('imjang_sessions').update({ complex_ids: ids }).eq('id', sessionId);
        }
      }
      return;
    } catch (e) {
      console.warn('노트 저장 실패, 로컬에 저장', e);
    }
  }
  // 로컬 폴백
  try {
    const { value } = await Preferences.get({ key: LOCAL_NOTES_KEY });
    const map: Record<string, StoredNote> = value ? JSON.parse(value) : {};
    map[complexId] = note;
    await Preferences.set({ key: LOCAL_NOTES_KEY, value: JSON.stringify(map) });
  } catch (e) {
    console.warn('로컬 저장도 실패', e);
  }
}

export async function deleteNote(userId: string | null, complexId: string): Promise<void> {
  const sb = getSupabase();
  if (sb && userId) {
    try {
      await sb.from('complex_notes').delete().eq('user_id', userId).eq('complex_id', complexId);
    } catch (e) {
      console.warn('노트 삭제 실패', e);
    }
  }
  // 로컬 폴백도 정리
  try {
    const { value } = await Preferences.get({ key: LOCAL_NOTES_KEY });
    if (value) {
      const map: Record<string, StoredNote> = JSON.parse(value);
      delete map[complexId];
      await Preferences.set({ key: LOCAL_NOTES_KEY, value: JSON.stringify(map) });
    }
  } catch (e) {
    console.warn('로컬 노트 삭제 실패', e);
  }
}

export async function deleteSession(userId: string | null, sessionId: string): Promise<void> {
  const sb = getSupabase();
  if (sb && userId && !sessionId.startsWith('local-')) {
    try {
      await sb.from('imjang_sessions').delete().eq('id', sessionId);
      return;
    } catch (e) {
      console.warn('세션 삭제 실패', e);
    }
  }
  try {
    const { value } = await Preferences.get({ key: LOCAL_SESSIONS_KEY });
    const list: ImjangSession[] = value ? JSON.parse(value) : [];
    await Preferences.set({
      key: LOCAL_SESSIONS_KEY,
      value: JSON.stringify(list.filter((s) => s.id !== sessionId)),
    });
  } catch {
    /* ignore */
  }
}
