import { useEffect } from 'react';

export interface ConfirmOptions {
  title?: string;
  message: string;
  confirmLabel?: string;
  cancelLabel?: string;
  danger?: boolean;
}

export interface ConfirmState extends ConfirmOptions {
  resolve: (v: boolean) => void;
}

export function ConfirmDialog({ state, onClose }: { state: ConfirmState | null; onClose: () => void }) {
  useEffect(() => {
    if (!state) return;
    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        state.resolve(false);
        onClose();
      } else if (e.key === 'Enter') {
        state.resolve(true);
        onClose();
      }
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [state, onClose]);

  if (!state) return null;

  const cancel = () => { state.resolve(false); onClose(); };
  const ok = () => { state.resolve(true); onClose(); };

  return (
    <div
      style={{
        position: 'fixed',
        inset: 0,
        background: 'rgba(17,24,39,.55)',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        padding: 24,
        zIndex: 9999,
        animation: 'imjangFadeIn .12s ease-out',
      }}
      onClick={cancel}
    >
      <style>{`
        @keyframes imjangFadeIn { from { opacity: 0 } to { opacity: 1 } }
        @keyframes imjangPopIn { from { opacity: 0; transform: scale(.96) } to { opacity: 1; transform: scale(1) } }
      `}</style>
      <div
        onClick={(e) => e.stopPropagation()}
        style={{
          background: 'var(--surface)',
          borderRadius: 18,
          width: '100%',
          maxWidth: 320,
          boxShadow: '0 24px 60px rgba(17,24,39,.28)',
          overflow: 'hidden',
          animation: 'imjangPopIn .14s ease-out',
        }}
      >
        <div style={{ padding: '22px 22px 18px', textAlign: 'center' }}>
          {state.title && (
            <div style={{ fontWeight: 800, fontSize: 16, marginBottom: 8, color: 'var(--ink)' }}>
              {state.title}
            </div>
          )}
          <div
            style={{
              fontSize: 14,
              fontWeight: 600,
              color: 'var(--ink-2)',
              lineHeight: 1.55,
              whiteSpace: 'pre-line',
            }}
          >
            {state.message}
          </div>
        </div>
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: '1fr 1fr',
            borderTop: '1px solid var(--line)',
          }}
        >
          <button
            type="button"
            onClick={cancel}
            style={{
              padding: '14px 0',
              background: 'transparent',
              border: 'none',
              borderRight: '1px solid var(--line)',
              fontSize: 14,
              fontWeight: 700,
              color: 'var(--ink-2)',
              cursor: 'pointer',
            }}
          >
            {state.cancelLabel ?? '취소'}
          </button>
          <button
            type="button"
            onClick={ok}
            style={{
              padding: '14px 0',
              background: 'transparent',
              border: 'none',
              fontSize: 14,
              fontWeight: 800,
              color: state.danger ? 'var(--bad)' : 'var(--accent)',
              cursor: 'pointer',
            }}
          >
            {state.confirmLabel ?? '확인'}
          </button>
        </div>
      </div>
    </div>
  );
}
