type SubTab = 'plan' | 'record';
type PlansMode = 'upcoming' | 'past';

function recordDate(ts: number): string {
  const d = new Date(ts);
  const now = new Date();
  const y = d.getFullYear() === now.getFullYear() ? '' : `${d.getFullYear()}. `;
  return `${y}${d.getMonth() + 1}월 ${d.getDate()}일`;
}

function dateLabel(v: string): string {
  if (!v) return '날짜 미정';
  const d = new Date(v + 'T00:00:00');
  const DOW = ['일', '월', '화', '수', '목', '금', '토'];
  return `${d.getMonth() + 1}월 ${d.getDate()}일 (${DOW[d.getDay()]})`;
}

function PlanCard({
  p,
  more,
  dong,
  members,
  hasNew,
  onOpen,
  onRemove,
  onMembers,
}: {
  p: ImjangPlan;
  more: number;
  dong?: string;
  members?: Member[];
  hasNew?: boolean;
  onOpen: () => void;
  onRemove: () => void;
  onMembers?: () => void;
}) {
  const title = (() => {
    if (p.memo.startsWith('[')) {
      const end = p.memo.indexOf(']');
      if (end > 0) return p.memo.slice(1, end);
    }
    return p.complexName + (more > 0 ? ` 외 ${more}곳` : '');
  })();
  return (
    <div className={'plan-card' + (p.done ? ' done' : '')} onClick={onOpen}>
      <div style={{ flex: 1, minWidth: 0 }}>
        <div className="row between" style={{ gap: 10, marginBottom: 6 }}>
          <div
            style={{
              fontWeight: 700,
              fontSize: 15,
              textDecoration: p.done ? 'line-through' : 'none',
              color: p.done ? 'var(--ink-3)' : 'var(--ink)',
              whiteSpace: 'nowrap',
              overflow: 'hidden',
              textOverflow: 'ellipsis',
              minWidth: 0,
            }}
          >
            {title}
          </div>
          <div className="row gap6" style={{ flexShrink: 0 }}>
            {hasNew && <span className="new-badge">N</span>}
            {onMembers && (
              <button
                type="button"
                className="plan-member-btn"
                onClick={(e) => {
                  e.stopPropagation();
                  onMembers();
                }}
              >
                <Icon name="people" size={14} stroke={2} />
                {(members?.length ?? 0) > 0 ? `멤버 ${members?.length}` : '멤버 관리'}
              </button>
            )}
            <button
              type="button"
              className="plan-x"
              onClick={(e) => {
                e.stopPropagation();
                onRemove();
              }}
              title="계획 삭제"
            >
              <Icon name="x" size={16} />
            </button>
          </div>
        </div>
        <div className="row gap6" style={{ alignItems: 'center', flexWrap: 'wrap' }}>
          <TypeChip type={p.complexType} />
          {dong && (
            <span
              className="muted"
              style={{
                fontSize: 11.5,
                fontWeight: 600,
                overflow: 'hidden',
                textOverflow: 'ellipsis',
                whiteSpace: 'nowrap',
                minWidth: 0,
              }}
            >
              {dong}
            </span>
          )}
          <span
            className="count-badge"
            style={{ flexShrink: 0 }}
          >
            <Icon name="build" size={11} stroke={2.2} />
            {`${more + 1}곳`}
          </span>
        </div>
        <div
          style={{
            borderTop: '1px solid var(--line)',
            marginTop: 11,
            paddingTop: 9,
          }}
        >
          <div
            className="muted"
            style={{
              fontSize: 12.5,
              fontWeight: 600,
              overflow: 'hidden',
              textOverflow: 'ellipsis',
              whiteSpace: 'nowrap',
              color: p.memo ? 'var(--ink-3)' : 'var(--ink-4)',
            }}
          >
            {(() => {
              if (p.memo.startsWith('[')) {
                const end = p.memo.indexOf(']');
                if (end > 0) {
                  const rest = p.memo.slice(end + 1).trim();
                  return rest || '메모 없음';
                }
              }
              return p.memo || '메모 없음';
            })()}
          </div>
        </div>
      </div>
    </div>
  );
}

function AddPlanButton({ onClick }: { onClick: () => void }) {
  return (
    <button type="button" className="add-plan-btn" onClick={onClick}>
      <div className="add-plan-ic">
        <Icon name="plus" size={18} stroke={2.4} />
      </div>
      <div style={{ flex: 1, textAlign: 'left' }}>
        <div style={{ fontWeight: 700, fontSize: 14 }}>임장 계획 추가</div>
        <div className="muted" style={{ fontSize: 11.5, fontWeight: 600, marginTop: 1 }}>
          단지·날짜·메모를 직접 담아요
        </div>
      </div>
      <Icon name="chevR" size={18} color="var(--ink-4)" />
    </button>
  );
}

function PlansList({ mode, onAdd }: { mode: PlansMode; onAdd?: () => void }) {
  const { plans, complexes, openTrip, deletePlanBatch, leavePlan, confirmAlert, unreadBatchIds } = useApp();
  const [shareTarget, setShareTarget] = useState<{ label: string; members: Member[]; batchId: string; canManage: boolean } | null>(null);

  const grouped = useMemo(() => {
    const today = new Date().toISOString().slice(0, 10);
    // 같은 batch끼리 묶기: key = `${plannedDate}|${batchId}`. batchId 없으면 complexId로 단일.
    const byKey = new Map<string, { date: string; arr: ImjangPlan[]; minCreated: number }>();
    plans.forEach((p) => {
      const date = p.plannedDate ?? '';
      const isPast = date !== '' && date < today;
      if (mode === 'past' ? !isPast : isPast) return;
      const k = `${date}|${p.batchId ?? p.complexId}`;
      const cur = byKey.get(k);
      if (cur) {
        cur.arr.push(p);
        if (p.createdAt < cur.minCreated) cur.minCreated = p.createdAt;
      } else {
        byKey.set(k, { date, arr: [p], minCreated: p.createdAt });
      }
    });
    // 같은 batch 내부는 createdAt asc로 정렬 (선택 순서 보존)
    byKey.forEach((g) => g.arr.sort((a, b) => a.createdAt - b.createdAt));
    // 그룹 정렬: 날짜 우선, 같은 날짜에서는 batch 생성 시각순
    const groups = Array.from(byKey.values()).sort((a, b) => {
      // 날짜 미정은 항상 맨 아래
      if (a.date === '' && b.date !== '') return 1;
      if (b.date === '' && a.date !== '') return -1;
      if (a.date !== b.date) {
        return mode === 'past' ? b.date.localeCompare(a.date) : a.date.localeCompare(b.date);
      }
      return mode === 'past' ? b.minCreated - a.minCreated : a.minCreated - b.minCreated;
    });
    return { groups, today };
  }, [plans, mode]);

  if (grouped.groups.length === 0) {
    if (mode === 'past') {
      return (
        <div className="empty-state">
          <div className="empty-ico">
            <Icon name="bookmark" size={26} />
          </div>
          <div style={{ fontWeight: 700, fontSize: 14.5, color: 'var(--ink-2)' }}>
            지나간 임장 기록이 없어요
          </div>
          <div
            className="muted"
            style={{ fontSize: 12.5, fontWeight: 600, marginTop: 6, lineHeight: 1.5 }}
          >
            계획한 날짜가 지나면
            <br />
            이곳에 히스토리로 남아요
          </div>
        </div>
      );
    }
    return (
      <>
        {onAdd && <AddPlanButton onClick={onAdd} />}
        <div className="empty-state">
          <div className="empty-ico">
            <Icon name="bookmark" size={26} />
          </div>
          <div style={{ fontWeight: 700, fontSize: 14.5, color: 'var(--ink-2)' }}>
            담아둔 단지가 없어요
          </div>
          <div
            className="muted"
            style={{ fontSize: 12.5, fontWeight: 600, marginTop: 6, lineHeight: 1.5 }}
          >
            위 버튼으로 직접 추가하거나
            <br />
            시세 목록·지도에서 담아보세요
          </div>
        </div>
      </>
    );
  }

  // 같은 날짜의 batch들을 하나의 date-group 아래로 묶기 (날짜 헤더는 1회만 표시)
  const byDate: { date: string; batches: typeof grouped.groups }[] = [];
  for (const g of grouped.groups) {
    const last = byDate[byDate.length - 1];
    if (last && last.date === g.date) last.batches.push(g);
    else byDate.push({ date: g.date, batches: [g] });
  }

  return (
    <>
      {mode === 'upcoming' && onAdd && <AddPlanButton onClick={onAdd} />}
      {mode === 'upcoming' && <div style={{ height: 8 }} />}
      {byDate.map(({ date, batches }) => {
        const overdue = mode === 'past';
        const totalCount = batches.reduce((s, b) => s + b.arr.length, 0);
        return (
          <div key={date || 'none'} className="date-group">
            <div className="date-head">
              <div className="row gap6" style={{ minWidth: 0 }}>
                <span className={'date-title' + (overdue ? ' over' : '')}>
                  {dateLabel(date)}
                </span>
                {totalCount > 1 && <span className="date-count">{totalCount}곳</span>}
              </div>
            </div>
            {batches.map((g, bi) => {
              const arr = g.arr;
              const batchKey = `${date}|${arr[0].batchId ?? arr[0].complexId}|${bi}`;
              if (arr.length > 1) {
                return (
                  <PlanCard
                    key={batchKey}
                    p={arr[0]}
                    more={arr.length - 1}
                    dong={(complexes.find((c) => c.id === arr[0].complexId) as { dong?: string } | undefined)?.dong}
                    members={[]}
                    hasNew={unreadBatchIds.has(planBatchId(arr[0]))}
                    onOpen={() =>
                      openTrip(
                        arr.map((x) => x.complexId),
                        dateLabel(date),
                        planBatchId(arr[0]),
                      )
                    }
                    onRemove={async () => {
                      const head = arr[0];
                      const headTitle = (() => {
                        if (head.memo.startsWith('[')) {
                          const end = head.memo.indexOf(']');
                          if (end > 0) return head.memo.slice(1, end);
                        }
                        return `${head.complexName} 외 ${arr.length - 1}곳`;
                      })();
                      // 공유받은 계획(내가 호스트가 아님)은 '나가기'
                      if (head.shared) {
                        const ok = await confirmAlert({
                          title: '계획에서 나가기',
                          message: `"${headTitle}"\n해당 계획에서 나가시겠습니까?`,
                          confirmLabel: '나가기',
                          danger: true,
                        });
                        if (!ok) return;
                        void leavePlan(planBatchId(head));
                        return;
                      }
                      const ok = await confirmAlert({
                        title: '임장 계획 삭제',
                        message: `"${headTitle}"\n계획을 삭제할까요?`,
                        confirmLabel: '삭제',
                        danger: true,
                      });
                      if (!ok) return;
                      void deletePlanBatch(planBatchId(head));
                    }}
                    onMembers={() => setShareTarget({ label: dateLabel(date), members: [], batchId: planBatchId(arr[0]), canManage: !arr[0].shared })}
                  />
                );
              }
              const p = arr[0];
              const inComplex = complexes.find((c) => c.id === p.complexId);
              const dong = (inComplex as { dong?: string } | undefined)?.dong;
              return (
                <PlanCard
                  key={batchKey}
                  p={p}
                  more={0}
                  dong={dong}
                  members={[]}
                  hasNew={unreadBatchIds.has(planBatchId(p))}
                  onOpen={() => openTrip([p.complexId], dateLabel(date), planBatchId(p))}
                  onRemove={async () => {
                    if (p.shared) {
                      const ok = await confirmAlert({
                        title: '계획에서 나가기',
                        message: `"${p.complexName}"\n해당 계획에서 나가시겠습니까?`,
                        confirmLabel: '나가기',
                        danger: true,
                      });
                      if (!ok) return;
                      void leavePlan(planBatchId(p));
                      return;
                    }
                    const ok = await confirmAlert({
                      title: '임장 계획 삭제',
                      message: `"${p.complexName}"\n계획을 삭제할까요?`,
                      confirmLabel: '삭제',
                      danger: true,
                    });
                    if (!ok) return;
                    void deletePlanBatch(planBatchId(p));
                  }}
                  onMembers={() => setShareTarget({ label: p.complexName, members: [], batchId: planBatchId(p), canManage: !p.shared })}
                />
              );
            })}
          </div>
        );
      })}
      {shareTarget && (
        <ShareSheet
          sessionLabel={shareTarget.label}
          members={shareTarget.members}
          batchId={shareTarget.batchId}
          onCreateInviteLink={shareTarget.canManage ? () => createInvite('plan', shareTarget.batchId) : undefined}
          onInviteFriend={shareTarget.canManage ? (fid) => inviteFriendToPlan(shareTarget.batchId, fid) : undefined}
          onClose={() => setShareTarget(null)}
        />
      )}
    </>
  );
}

type RecChecks = Record<string, string>;

function RecordCardBody({
  rec,
  rating,
  checks,
  photos,
  oneliner,
}: {
  rec: { name: string; type?: ImjangPlan['complexType']; addr: string };
  rating: number;
  checks: RecChecks;
  photos: unknown[];
  oneliner: string;
}) {
  const evalTotal = Object.keys(checks ?? {}).length;
  return (
    <>
      {rec.addr && (
        <div
          className="muted"
          style={{ fontSize: 11.5, fontWeight: 600, marginBottom: 7, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}
        >
          {rec.addr}
        </div>
      )}
      <div className="row gap6" style={{ alignItems: 'center', flexWrap: 'wrap' }}>
        {rec.type && <TypeChip type={rec.type} />}
        {rating > 0 && (
          <span className="row gap4" style={{ alignItems: 'center' }}>
            <Stars rating={rating} />
            <span className="num" style={{ fontSize: 12, fontWeight: 800, color: 'var(--ink-2)' }}>{rating.toFixed(1)}</span>
          </span>
        )}
        {evalTotal > 0 && (
          <span className="count-badge" style={{ flexShrink: 0 }}>
            <Icon name="check" size={11} stroke={2.4} />
            {`평가 ${evalTotal}/${CHECKLIST_TOTAL}`}
          </span>
        )}
        {photos.length > 0 && (
          <span className="muted" style={{ fontSize: 11.5, fontWeight: 600 }}>{`사진 ${photos.length}`}</span>
        )}
      </div>
      {oneliner && (
        <div
          style={{
            borderTop: '1px solid var(--line)',
            marginTop: 11,
            paddingTop: 9,
            fontSize: 12.5,
            fontWeight: 600,
            color: 'var(--ink-3)',
            overflow: 'hidden',
            textOverflow: 'ellipsis',
            whiteSpace: 'nowrap',
          }}
        >
          {oneliner}
        </div>
      )}
    </>
  );
}

function RecordsList() {
  const { notes, sharedNotes, complexes, plans, openNote, openMemberNote, deleteNote, removeReceivedNote, confirmAlert } = useApp();
  const [info, setInfo] = useState<Map<string, { name: string; type: string; addr: string }>>(new Map());

  type RecItem =
    | { kind: 'mine'; cid: string; createdAt: number; note: (typeof notes)[string] }
    | { kind: 'shared'; cid: string; createdAt: number; recv: (typeof sharedNotes)[number] };

  // 내가 쓴 노트 + 나에게 공유된 노트 — 최신순
  const items = useMemo<RecItem[]>(() => {
    const mine: RecItem[] = Object.entries(notes).map(([cid, n]) => ({ kind: 'mine', cid, createdAt: n.createdAt ?? 0, note: n }));
    const shared: RecItem[] = sharedNotes.map((r) => ({ kind: 'shared', cid: r.complexId, createdAt: r.createdAt ?? 0, recv: r }));
    return [...mine, ...shared].sort((a, b) => b.createdAt - a.createdAt);
  }, [notes, sharedNotes]);

  // 단지명: 주변목록 → 계획 → RPC조회 순. 주소는 RPC조회로만 확보.
  const resolve = (cid: string): { name: string; type?: ImjangPlan['complexType']; addr: string } => {
    const fetched = info.get(cid);
    const c = complexById(complexes, cid);
    const p = plans.find((x) => x.complexId === cid);
    return {
      name: c?.name || p?.complexName || fetched?.name || '단지',
      type: (c?.type as ImjangPlan['complexType']) || p?.complexType || (fetched?.type as ImjangPlan['complexType']),
      addr: fetched?.addr || '',
    };
  };

  useEffect(() => {
    const missing = items.map((it) => it.cid).filter((cid) => !info.has(cid));
    if (missing.length === 0) return;
    let alive = true;
    void loadComplexNames(missing).then((m) => {
      if (alive && m.size) setInfo((prev) => new Map([...prev, ...m]));
    });
    return () => { alive = false; };
    // info 의존성 제외 — 조회 결과 반영 후 재조회 루프 방지
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [items]);

  if (items.length === 0) {
    return (
      <div className="empty-state">
        <div className="empty-ico">
          <Icon name="clipboard" size={26} />
        </div>
        <div style={{ fontWeight: 700, fontSize: 14.5, color: 'var(--ink-2)' }}>
          작성한 임장노트가 없어요
        </div>
        <div className="muted" style={{ fontSize: 12.5, fontWeight: 600, marginTop: 6, lineHeight: 1.5 }}>
          단지 상세에서 임장노트를 작성하면
          <br />
          이곳에 기록으로 모여요
        </div>
      </div>
    );
  }

  return (
    <>
      {items.map((it) => {
        const rec = resolve(it.cid);
        if (it.kind === 'shared') {
          const r = it.recv;
          return (
            <div
              key={`s-${it.cid}-${r.ownerId}`}
              className="plan-card"
              onClick={() =>
                openMemberNote(it.cid, {
                  userId: r.ownerId,
                  authorName: r.authorName,
                  rating: r.rating,
                  checks: r.checks,
                  photos: r.photos,
                  oneliner: r.oneliner,
                  shared: true,
                  createdAt: r.createdAt,
                  isMine: false,
                })
              }
              style={{ cursor: 'pointer' }}
            >
              <div style={{ flex: 1, minWidth: 0 }}>
                <div className="row between" style={{ gap: 10, marginBottom: 4, alignItems: 'center' }}>
                  <div style={{ fontWeight: 700, fontSize: 15, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', minWidth: 0 }}>
                    {rec.name}
                  </div>
                  <div className="row gap6" style={{ flexShrink: 0, alignItems: 'center' }}>
                    <span
                      style={{ fontSize: 10.5, fontWeight: 800, padding: '2px 7px', borderRadius: 999, background: 'var(--accent-tint)', color: 'var(--accent)', whiteSpace: 'nowrap' }}
                    >
                      {`${r.authorName}님에게 공유받음`}
                    </span>
                    <span className="muted" style={{ fontSize: 11.5, fontWeight: 600 }}>{recordDate(r.createdAt)}</span>
                    <button
                      type="button"
                      className="plan-x"
                      title="공유받은 노트 삭제"
                      onClick={async (e) => {
                        e.stopPropagation();
                        const ok = await confirmAlert({
                          title: '공유받은 노트 삭제',
                          message: `"${rec.name}"\n${r.authorName}님이 공유한 노트를 목록에서 삭제할까요?`,
                          confirmLabel: '삭제',
                          danger: true,
                        });
                        if (ok) void removeReceivedNote(r.ownerId, it.cid);
                      }}
                    >
                      <Icon name="x" size={16} />
                    </button>
                  </div>
                </div>
                <RecordCardBody rec={rec} rating={r.rating} checks={r.checks} photos={r.photos} oneliner={r.oneliner} />
              </div>
            </div>
          );
        }
        const n = it.note;
        return (
          <div key={it.cid} className="plan-card" onClick={() => openNote(it.cid)} style={{ cursor: 'pointer' }}>
            <div style={{ flex: 1, minWidth: 0 }}>
              <div className="row between" style={{ gap: 10, marginBottom: 4, alignItems: 'center' }}>
                <div style={{ fontWeight: 700, fontSize: 15, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', minWidth: 0 }}>
                  {rec.name}
                </div>
                <div className="row gap6" style={{ flexShrink: 0, alignItems: 'center' }}>
                  <span
                    style={{
                      fontSize: 10.5,
                      fontWeight: 800,
                      padding: '2px 7px',
                      borderRadius: 999,
                      background: n.shared ? 'var(--accent-tint)' : 'var(--surface-2)',
                      color: n.shared ? 'var(--accent)' : 'var(--ink-3)',
                    }}
                  >
                    {n.shared ? '공유' : '나만'}
                  </span>
                  <span className="muted" style={{ fontSize: 11.5, fontWeight: 600 }}>{recordDate(n.createdAt)}</span>
                  <button
                    type="button"
                    className="plan-x"
                    title="임장노트 삭제"
                    onClick={async (e) => {
                      e.stopPropagation();
                      const ok = await confirmAlert({
                        title: '임장노트 삭제',
                        message: `"${rec.name}"\n임장노트를 삭제할까요?`,
                        confirmLabel: '삭제',
                        danger: true,
                      });
                      if (ok) void deleteNote(it.cid);
                    }}
                  >
                    <Icon name="x" size={16} />
                  </button>
                </div>
              </div>
              <RecordCardBody rec={rec} rating={n.rating} checks={n.checks} photos={n.photos} oneliner={n.oneliner} />
            </div>
          </div>
        );
      })}
    </>
  );
}

