import type { ReactNode } from 'react';
import { Icon } from './Icon';

export function Toast({ children }: { children: ReactNode }) {
  return (
    <div className="toast">
      <Icon name="check" size={18} color="var(--good)" />
      {children}
    </div>
  );
}

export function TypeChip({ type }: { type: string }) {
  return <span className="type-chip">{type}</span>;
}

export function EvalDot({ v }: { v: string | undefined }) {
  const c =
    v === 'good'
      ? 'var(--good)'
      : v === 'soso'
      ? 'var(--soso)'
      : v === 'bad'
      ? 'var(--bad)'
      : 'var(--line-strong)';
  return <span className="cmp-dot" style={{ background: c }} />;
}
