// Kakao Maps JS SDK 로더 — 1회 로드 후 캐시된 promise 재사용
// 사용: const kakao = await loadKakaoMaps(); kakao && new kakao.maps.Map(...)

import { ENV } from './env';

declare global {
  interface Window {
    kakao?: typeof kakaoNs;
  }
}

// 최소 타입 정의 — 필요한 메서드만
export interface KakaoMaps {
  Map: new (container: HTMLElement, options: { center: KakaoLatLng; level?: number; draggable?: boolean }) => KakaoMap;
  LatLng: new (lat: number, lng: number) => KakaoLatLng;
  LatLngBounds: new () => KakaoLatLngBounds;
  CustomOverlay: new (options: {
    position: KakaoLatLng;
    content: HTMLElement | string;
    xAnchor?: number;
    yAnchor?: number;
    zIndex?: number;
    clickable?: boolean;
  }) => KakaoCustomOverlay;
  Marker: new (options: { position: KakaoLatLng; map?: KakaoMap }) => KakaoMarker;
  event: {
    addListener: (target: object, type: string, handler: (...args: unknown[]) => void) => void;
    removeListener: (target: object, type: string, handler: (...args: unknown[]) => void) => void;
  };
  services?: {
    Geocoder: new () => KakaoGeocoder;
    Places: new () => KakaoPlaces;
    Status: { OK: string; ZERO_RESULT: string; ERROR: string };
  };
  load: (cb: () => void) => void;
}

export interface KakaoLatLng {
  getLat(): number;
  getLng(): number;
}

export interface KakaoLatLngBounds {
  extend(latlng: KakaoLatLng): void;
  isEmpty(): boolean;
  getSouthWest(): KakaoLatLng;
  getNorthEast(): KakaoLatLng;
}

export interface KakaoMap {
  setCenter(latlng: KakaoLatLng): void;
  getCenter(): KakaoLatLng;
  setLevel(level: number, options?: { animate?: boolean }): void;
  getLevel(): number;
  setBounds(bounds: KakaoLatLngBounds, paddingTop?: number, paddingRight?: number, paddingBottom?: number, paddingLeft?: number): void;
  getBounds(): KakaoLatLngBounds;
  panTo(latlng: KakaoLatLng | KakaoLatLngBounds): void;
  relayout(): void;
  getProjection(): {
    pointFromCoords(latlng: KakaoLatLng): { x: number; y: number };
    coordsFromPoint(point: { x: number; y: number }): KakaoLatLng;
  };
  getNode(): HTMLElement;
}

export interface KakaoCustomOverlay {
  setMap(map: KakaoMap | null): void;
  setPosition(latlng: KakaoLatLng): void;
  getContent(): HTMLElement | string;
}

export interface KakaoMarker {
  setMap(map: KakaoMap | null): void;
  setPosition(latlng: KakaoLatLng): void;
}

export interface KakaoPlaces {
  keywordSearch(
    query: string,
    cb: (
      result: Array<{
        place_name: string;
        address_name: string;
        road_address_name?: string;
        x: string; // lng
        y: string; // lat
      }>,
      status: string,
    ) => void,
  ): void;
}

export interface KakaoGeocoder {
  coord2RegionCode(
    lng: number,
    lat: number,
    cb: (result: Array<{ region_type: string; address_name: string }>, status: string) => void,
  ): void;
  addressSearch(
    query: string,
    cb: (
      result: Array<{
        address_name: string;
        x: string; // lng
        y: string; // lat
        address_type: string;
        road_address?: { address_name: string };
      }>,
      status: string,
    ) => void,
  ): void;
}

const kakaoNs = {} as { maps: KakaoMaps };

let loadPromise: Promise<KakaoMaps | null> | null = null;

export function loadKakaoMaps(): Promise<KakaoMaps | null> {
  if (loadPromise) return loadPromise;
  if (!ENV.kakaoJsKey) {
    console.warn('[Kakao Maps] VITE_KAKAO_JAVASCRIPT_KEY 미설정 — 지도 비활성');
    return Promise.resolve(null);
  }
  loadPromise = new Promise<KakaoMaps | null>((resolve) => {
    // 이미 로드되어 있으면 즉시 반환
    if (window.kakao?.maps) {
      window.kakao.maps.load(() => resolve(window.kakao!.maps));
      return;
    }
    const script = document.createElement('script');
    script.src = `https://dapi.kakao.com/v2/maps/sdk.js?appkey=${ENV.kakaoJsKey}&autoload=false&libraries=services`;
    script.async = true;
    script.onload = () => {
      const k = window.kakao;
      if (!k?.maps?.load) {
        console.error('[Kakao Maps] SDK 로드 실패');
        resolve(null);
        return;
      }
      k.maps.load(() => resolve(k.maps));
    };
    script.onerror = () => {
      console.error('[Kakao Maps] script onerror — 도메인 등록·키 확인 필요');
      resolve(null);
    };
    document.head.appendChild(script);
  });
  return loadPromise;
}
